-- Poems batch 374
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('594374c0-ab3d-4f56-ac3a-a2be7ba78a2c','書淳師房六言三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','罌粟湯翻白雪，梅花句嚼春冰。',28,'全唐诗/poet.song.87000.json','["罌粟湯翻白雪，梅花句嚼春冰。", "助我看山老眼，借君倚壁枯藤。"]'),
('2b4581df-1ef2-4b7c-bfc4-c719acd2d06e','次韻任道卿見寄','周紫芝','宋','宋诗','song-poetry','','[]','連璧終慚玉一雙，何曾有句似澄江。',64,'全唐诗/poet.song.87000.json','["連璧終慚玉一雙，何曾有句似澄江。", "九霄鴻鵠終掀舉，三峽波濤看擊撞。", "長袖婆娑終解舞，短歌哀怨不成腔。", "詩壇老將元無敵，合爲奔軍作受降。"]'),
('22c42e9a-c530-4570-8fda-8945d75624d4','次韻道卿登樓有作','周紫芝','宋','宋诗','song-poetry','','[]','謝朓樓頭烟樹低，雨餘簾幕捲雌霓。',64,'全唐诗/poet.song.87000.json','["謝朓樓頭烟樹低，雨餘簾幕捲雌霓。", "山從雲外分千疊，水自天來落兩溪。", "南圃飛紅香滿砌，畫橋春漲綠平隄。", "登臨日日傷愁眼，欄下夕陽還復西。"]'),
('24ac22e9-9312-4328-b57b-ea7ff0ca509b','次韻魯庵道人','周紫芝','宋','宋诗','song-poetry','','[]','一事無成雪滿顛，漫憑老眼寄韋編。',64,'全唐诗/poet.song.87000.json','["一事無成雪滿顛，漫憑老眼寄韋編。", "誰將愛酒周光祿，錯比能詩孟浩然。", "心與功名無宿約，天分泉石了殘年。", "相過更待秋風老，來釣琴公斫鱠鯿。"]'),
('6bfd524f-9e20-4c52-ac74-461667463ca9','夜雨達旦枕上作','周紫芝','宋','宋诗','song-poetry','','[]','夜雨不復止，寒聲曉仍酣。',204,'全唐诗/poet.song.87000.json','["夜雨不復止，寒聲曉仍酣。", "懸知變平陸，天水相溶涵。", "今年春雨多，既失麥與蠶。", "五種殊未入，此雨寧可堪。", "日者諸大將，幕府開潭潭。", "連營跨淮楚，仰食江以南。", "郡縣脫兵火，百城無二三。", "何以供厞屨，坐貽有司慚。", "是事姑且置，我窮誰共談。", "有茅兩三椽，往往如漏籃。", "中夜屢起臥，吾寢安得甘。", "晝止方稍稍，暮作還毿毿。", "了無山鞠窮，何由禦烟嵐。", "有躬不暇閱，憂心顧如惔。", "何當煩雨師，驅車反龍驂。", "一飽庶可期，寒餓少已諳。", "小人無遠慮，口腹空饞貪。"]'),
('6ccc03e4-37cc-47c1-b6bf-e375752a321b','重午日晚眺','周紫芝','宋','宋诗','song-poetry','','[]','野艾傷心碧，叢榴滿意紅。',48,'全唐诗/poet.song.87000.json','["野艾傷心碧，叢榴滿意紅。", "兵戈人事别，風物歲時同。", "山倚斜陽外，江横醉眼中。", "楚冤終未洗，誰爲餉絲筒。"]'),
('1e0218d8-e8f2-4404-bb8a-732fcc3cdbd5','六月八日始開北窗得數峰于林樾間命力斬惡木而山態始盡出','周紫芝','宋','宋诗','song-poetry','','[]','老去捨輕舠，小室坐懸磬。',168,'全唐诗/poet.song.87000.json','["老去捨輕舠，小室坐懸磬。", "六月不出門，端居閱晨暝。", "安知咫尺中，有此大殊勝。", "今晨穿北垣，萬象忽輝映。", "太虛本無窮，眼力恐自竟。", "遙岑蔽清樾，了不赴將迎。", "翠幕空繁柯，烟鬟入幽凭。", "雙峰始幡然，起應高士聘。", "長瘦有餘光，名與天地亘。", "馬鬛亦已頹，蓬顆没微徑。", "茲山與周旋，安得往脩敬。", "斗酒時自澆，先生醉初醒。", "落月掛長松，悲風繞危磴。", "徘回想音容，彷彿聽嘲咏。"]'),
('81d45cd0-8e94-4f8a-b184-bc8c4c228a70','七月十六日晚雨已而月出','周紫芝','宋','宋诗','song-poetry','','[]','將雨日已晏，既晴天亦曛。',96,'全唐诗/poet.song.87000.json','["將雨日已晏，既晴天亦曛。", "風從莽蒼來，雲向西南奔。", "忽于蒼玉玦，擁此黄金盆。", "我居在山頂，升沉閲冰輪。", "三年東岡頭，入我圭竇門。", "平生金蘭友，老去無一存。", "願言結神交，相與論素心。", "素心不可說，月亦終無言。"]'),
('58a6a788-6808-49c1-8531-4d8980d0774e','暑夕','周紫芝','宋','宋诗','song-poetry','','[]','卷箔日巳落，移床月未來。',48,'全唐诗/poet.song.87000.json','["卷箔日巳落，移床月未來。", "蛙號還作吹，蚊聚竟成雷。", "我自羲皇臥，誰分河朔杯。", "更憑風露夕，小爲洗胡埃。"]'),
('2b0e50b4-68c1-4ce6-9795-f973e17fa517','夜枕','周紫芝','宋','宋诗','song-poetry','','[]','夜枕欹殘夢，寒燈照白頭。',48,'全唐诗/poet.song.87000.json','["夜枕欹殘夢，寒燈照白頭。", "樓空千嶂曉，簟冷一窗秋。", "時事兵方急，天星火已流。", "欲尋三徑老，何日兩京收。"]'),
('4f532b75-8c8a-461b-b46a-621718eb6138','中秋月下懷西山亭示周都曹','周紫芝','宋','宋诗','song-poetry','','[]','頑雲撥盡玉團欒，飛出青天白玉盤。',64,'全唐诗/poet.song.87000.json','["頑雲撥盡玉團欒，飛出青天白玉盤。", "月似不關常夜白，風應先作九秋寒。", "興來有意攜雙屐，夢去還思把釣竿。", "遙想風流三語掾，不知誰共倚欄干。"]'),
('75ac1656-33c1-4bb4-91e3-f4285d8303c1','次韻道卿咏雪約遵歐陽文忠公令不得用鶴玉潔白等字','周紫芝','宋','宋诗','song-poetry','','[]','魯史書平尺，王春喜可占。',144,'全唐诗/poet.song.87000.json','["魯史書平尺，王春喜可占。", "弄寒初照砌，逐吹旋縈簾。", "水遠還迷望，山高遂失尖。", "欺梅時滿樹，妬舞或陵襜。", "鵲凍痴如夢，兒嬌喜欲拈。", "人應横短櫂，誰且臥窮閻。", "壯士知何畏，衰翁亦懶覘。", "打窗時蔌蔌，拂帽更纖纖。", "獸炭寒仍在，駝裘晚自添。", "鷓鴣茶椀釅，鸚鵡酒杯甜。", "歲事新愁破，詩章舊令嚴。", "遙思庾樓夜，萬里一寒蟾。"]'),
('e1363178-eecf-4364-ba16-2883398a05c0','用晦訪别爲作長句','周紫芝','宋','宋诗','song-poetry','','[]','東風吹雪滿征鞍，奪我瀕湖一笑歡。',64,'全唐诗/poet.song.87000.json','["東風吹雪滿征鞍，奪我瀕湖一笑歡。", "老病不堪頻送客，亂離容易莫求官。", "故人知有山公在，遊子應憐范叔寒。", "留得餘年可相見，不須回眼淚闌干。"]'),
('d343e796-f9b5-4162-99f8-dbca18ad6b7c','十二月二十六日北牆捫虱','周紫芝','宋','宋诗','song-poetry','','[]','今晨頗無事，步遊古牆根。',120,'全唐诗/poet.song.87000.json','["今晨頗無事，步遊古牆根。", "眷茲萬家邑，稍苦三户村。", "于時積雪散，復值朝陽温。", "解衣聊自得，班荆與誰言。", "款欠良已久，吾虱庶可捫。", "平生謝澡刷，懶惰從朝昏。", "坐令邊縫間，朝生暮仍孫。", "回臭比跖香，位卑道仍尊。", "與世倘無求，中有至樂存。", "勿語兒女曹，此意難具論。"]'),
('5f6ca8bf-8341-4490-b9f0-7e72f101468b','次韻道卿觀諸葛生製筆有感而作','周紫芝','宋','宋诗','song-poetry','','[]','任侯富三冬，志在食五鼎。',168,'全唐诗/poet.song.87000.json','["任侯富三冬，志在食五鼎。", "平生名教地，不對紛華境。", "細書抄蠅頭，何當避炎冷。", "毛錐捐脫兔，高與堆阜等。", "遂呼東郭㕙，一一拔項領。", "妙製窺良工，危坐銷日永。", "錙銖辨柔勁，束縳較欹整。", "那因將軍恬，始拜管城頴。", "乃知鬻伎窮，不異束麻檾。", "苞苴入朱門，蠧蚛不窺省。", "吾曹坐書痴，微言姑自警。", "他年草玄窗，長物俱可屏。", "潛夫倘或著，封禪慎勿請。", "相過有餘日，會待風雲靜。"]'),
('d406d516-901e-45e5-8b42-61da67af6496','次韻静翁雪晴有作','周紫芝','宋','宋诗','song-poetry','','[]','曉天晴日麗朱樓，殘雪晶瑩客舍幽。',64,'全唐诗/poet.song.87000.json','["曉天晴日麗朱樓，殘雪晶瑩客舍幽。", "寒柳江梅渾欲動，官軍胡騎幾時休。", "頗無佳客堪同醉，當爲衰翁作少留。", "便典春衣買春酒，同將一酌散千憂。"]'),
('9ac3f9ee-322c-46d4-8070-e3e67a95a92b','次韻道卿效離合體見贈','周紫芝','宋','宋诗','song-poetry','','[]','穠李有佳色，不如蘭芷香。',120,'全唐诗/poet.song.87000.json','["穠李有佳色，不如蘭芷香。", "鳴禽矜爪觜，肯入鸞鳯行。", "若士自有偶，俗子自有腸。", "驗志貴同術，異趨徒參商。", "望羊久自歎，相思不相忘。", "偉哉德祖賢，長年與徜徉。", "逢君青雲衢，弱羽難翺翔。", "槁項與黄馘，珠玉儼在旁。", "唧唧秋蟲吟，敢賡韶濩章。", "夜光入我室，什襲徒珍藏。"]'),
('a465d341-55c5-48a6-813c-923dafd323f0','早歸','周紫芝','宋','宋诗','song-poetry','','[]','野日破朝霧，宿陰回暖風。',48,'全唐诗/poet.song.87000.json','["野日破朝霧，宿陰回暖風。", "人家村崦外，春夢竹輿中。", "天碧鷺斜起，水深桃臥紅。", "山陰幾巖壑，應接自無窮。"]'),
('26de8743-56b2-4039-b9fb-ded6c4982688','題徐伯遠渚堂','周紫芝','宋','宋诗','song-poetry','','[]','徐侯當登瀛，結屋在幽渚。',156,'全唐诗/poet.song.87000.json','["徐侯當登瀛，結屋在幽渚。", "于焉窮心迹，無乃異出處。", "西風肅高秋，黄鵠時一舉。", "自謂可過之，丘壑出肺腑。", "俗眼殊未高，此意吾竊取。", "長卿少倦遊，征衫涴塵土。", "羞陪漉酒翁，共作斜川語。", "魚鳥雜冠巾，蒲蓮暗樽俎。", "江湖滿天地，置身豈無所。", "黄帽與青鞋，造化久見許。", "平生釣餌興，臨老尚齟齬。", "茲懷固泯默，感激聊自吐。", "安得載笭箵，孤蓬聽秋雨。"]'),
('b60bc7c7-26f5-458b-b015-284882d070e8','次韻道卿嘗新梅','周紫芝','宋','宋诗','song-poetry','','[]','梅梢着子葉青青，紅萼猶存味已清。',64,'全唐诗/poet.song.87000.json','["梅梢着子葉青青，紅萼猶存味已清。", "竹外一枝和雨摘，釵頭雙蔕爲誰情。", "雪霜自是元同操，楟奈何由與並名。", "商鼎欲調應有待，不隨鹽豉下蓴羮。"]'),
('92106b88-453b-4ec2-a783-6ce4b5e7bf6c','送元楷官莪橋','周紫芝','宋','宋诗','song-poetry','','[]','相見還須復語離，更看花雨濕征衣。',64,'全唐诗/poet.song.87000.json','["相見還須復語離，更看花雨濕征衣。", "樂丞有酒聊自隱，季子無田安得歸。", "長釣不妨垂白雨，亂帆時看落斜暉。", "何時去作津亭客，更待秋風一葉飛。"]'),
('ac1adda3-97c0-48c1-bbd8-39aad500263d','次韻道卿喜賊平','周紫芝','宋','宋诗','song-poetry','','[]','無人試請一長纓，賢似防胡萬里城。',64,'全唐诗/poet.song.87000.json','["無人試請一長纓，賢似防胡萬里城。", "共說廟堂初奏凱，似聞淮海已無兵。", "黄頭父老農桑晚，白面將軍劍佩榮。", "息馬投戈知有日，黑山青犢已先平。"]'),
('f4254cf1-560a-4d62-9cca-a0a91531c23b','小兒生日','周紫芝','宋','宋诗','song-poetry','','[]','錦里先生聊醉飲，玉川居士以詩鳴。',64,'全唐诗/poet.song.87000.json','["錦里先生聊醉飲，玉川居士以詩鳴。", "人言驥子能扶步，天遣添丁欲助耕。", "窮苦助吾緣底事，饑寒憐汝若爲情。", "相看只有身長健，共瀝餘樽作小頳。"]'),
('a6e437e8-0080-4635-b6f0-7ecb1de08d07','林老借可正平詩編以詩還之','周紫芝','宋','宋诗','song-poetry','','[]','蘇家人物自有種，法護且放僧彌賢。',64,'全唐诗/poet.song.87000.json','["蘇家人物自有種，法護且放僧彌賢。", "誰知癩可東溪句，參得涪翁雙井禪。", "落葉飛雲空自好，流風回雪不成妍。", "更須點檢新編看，恐有隔林機杼篇。"]'),
('e148516b-d1b6-4bf4-8c5c-afa594f94245','送羅仲共罷酒官歸山中','周紫芝','宋','宋诗','song-poetry','','[]','虎額一山同避賊，草堂三月更通家。',64,'全唐诗/poet.song.87000.json','["虎額一山同避賊，草堂三月更通家。", "音容久隔頭俱雪，雲霧相看眼各花。", "晚厭微官猶麯糵，早知豪氣已聱牙。", "北扉青瑣真如夢，且復西谿踏釣沙。"]'),
('e62da393-34f0-404b-8770-4595089eb8d2','次韻常元明見寄三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','月明驚鵲未安巢，生事如僧止一包。',64,'全唐诗/poet.song.87000.json','["月明驚鵲未安巢，生事如僧止一包。", "但得有門容看竹，不知何地可分茅。", "愁來漫載盈鴟酒，老去難穿中鵠髇。", "獨有詩緣難洗盡，强隨春鳥作啁嘲。"]'),
('6750a7fe-efdd-43d9-8802-5da3e69116c1','次韻常元明見寄三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','已分功名噲等高，平生誰問六花包。',64,'全唐诗/poet.song.87000.json','["已分功名噲等高，平生誰問六花包。", "千頭願種封侯橘，三脊仍慚縮酒茅。", "亂後詩囊成長物，夢中驚胆落飛髇。", "我非執戟明光客，知有何人肯見嘲。"]'),
('fa8008df-326e-41c1-a5cc-ead570a2da6d','次韻常元明見寄三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','我如病橘綴寒梢，璀璨何由入貢包。',64,'全唐诗/poet.song.87000.json','["我如病橘綴寒梢，璀璨何由入貢包。", "交舊半應歸宿草，亂離真已壓前茅。", "毛錐早信難當敵，銅弩何由學射髇。", "願借瀾翻千偈手，爲余一洗向來嘲。"]'),
('e11ed779-71dc-48ca-a521-3f861429a855','次韻道卿瑞香','周紫芝','宋','宋诗','song-poetry','','[]','春意催花不自禁，紫團猶復畏輕陰。',64,'全唐诗/poet.song.87000.json','["春意催花不自禁，紫團猶復畏輕陰。", "蘭蓀有意窺芳馥，桃李含羞漫淺深。", "鬭鴨並欄風冉冉，紅油垂幕月沉沉。", "任郎便是花東道，不學香山夢後尋。"]'),
('f36e5635-54fd-47d8-8cc5-20b0ab1a3a04','次韻道卿竹間桃花盛開','周紫芝','宋','宋诗','song-poetry','','[]','玉立疏疏不滿欄，小桃宜向竹閑看。',64,'全唐诗/poet.song.87000.json','["玉立疏疏不滿欄，小桃宜向竹閑看。", "看花何必三千歲，带雨寧須十萬竿。", "却怪靚粧情脈脈，不嫌青玉瘦欒欒。", "何郎粉面堪憐許，擬學風枝耐歲寒。"]'),
('e214be61-bb7b-4f0a-9c82-6dd2ba9fc074','送徐彦思三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','好事何人說醉翁，賢良名在著書中。',64,'全唐诗/poet.song.87000.json','["好事何人說醉翁，賢良名在著書中。", "只今文采猶如此，當日淵源豈易窮。", "遺恨可堪驚别雨，新詩不復咏流風。", "慚公千里相求意，楓落吳江恐未工。"]'),
('ab33f191-bab9-41ed-8d72-6a0077d9731b','送徐彦思三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','凜凜忠言公自持，僞書初赦兩淮時。',64,'全唐诗/poet.song.87000.json','["凜凜忠言公自持，僞書初赦兩淮時。", "膝當不爲奸雄屈，心亦唯應草木知。", "獨任安危百年事，寧辜父老一生思。", "抗章終有論功日，便到鑾坡已恨遲。"]'),
('a77bd88d-0692-4ebf-ad54-6b1892c1946b','送徐彦思三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','枘方乖鑿固應殊，草木相求世久無。',64,'全唐诗/poet.song.87000.json','["枘方乖鑿固應殊，草木相求世久無。", "可怪風流如孺子，不嫌人物似曹蜍。", "兩溪風月空勞夢，千里歌謠尚載塗。", "他日鵷行一回首，冷鳧乘雁只江湖。"]'),
('ee9caf45-a6c1-43dc-b62e-ee8fb1deffa7','二月二十六日伯遠邀遊小園明日有詩次韻','周紫芝','宋','宋诗','song-poetry','','[]','園荒不見二疏歸，風引長藤欲上籬。',64,'全唐诗/poet.song.87000.json','["園荒不見二疏歸，風引長藤欲上籬。", "燕子作巢春寂寂，竹枝搖月影離離。", "誰爲五柳當年傳，又誦三堂此日詩。", "我欲一邱藏曲折，此心唯有子相知。"]'),
('d49e94a1-d9d6-4f58-bee5-e42e5e8aafbb','二月二十八日靜寄軒作','周紫芝','宋','宋诗','song-poetry','','[]','看得階前碧草濃，小桃猶作亞枝紅。',64,'全唐诗/poet.song.87000.json','["看得階前碧草濃，小桃猶作亞枝紅。", "五更夢斷鷄鳴雨，三月寒生燕子風。", "歸意擬尋黄篾舫，春愁最惱白頭翁。", "鶴長鳧短知多少，盡付軒渠一笑中。"]'),
('29f1d26a-dffe-4d5a-a0e0-93cbbb8090a1','駝山寒食二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','時節近禁火，東風猶小寒。',48,'全唐诗/poet.song.87000.json','["時節近禁火，東風猶小寒。", "絮飛爭渡水，鞦稳欲平竿。", "酒忍愁前把，春仍亂後看。", "吾歸須少日，花在莫吹殘。"]'),
('f25d7391-87f8-47ed-8c4a-1db2e32c3bdf','駝山寒食二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','過眼夕陽雨，滿襟寒食風。',48,'全唐诗/poet.song.87000.json','["過眼夕陽雨，滿襟寒食風。", "鳴禽說春事，暖樹落嫣紅。", "杯莫頻停手，花令解笑儂。", "人生不相見，可忍更匆匆。"]'),
('27e0e50d-07bd-4a0d-b2de-df648400b859','張元明爲道卿畫竹間梅','周紫芝','宋','宋诗','song-poetry','','[]','我作東窗竹外開，斷魂香自雪邊來。',64,'全唐诗/poet.song.87000.json','["我作東窗竹外開，斷魂香自雪邊來。", "細尋水墨圖中意，似對檀欒塢裏梅。", "筆下懸知有冰玉，胸中元自少風埃。", "可憐能事王摩詰，解令春從一笑回。"]'),
('c3d761cb-d015-481e-9a14-a7441a774535','題周掾西山亭','周紫芝','宋','宋诗','song-poetry','','[]','江靜雲恬眼界空，危亭高枕麗譙東。',64,'全唐诗/poet.song.87000.json','["江靜雲恬眼界空，危亭高枕麗譙東。", "風來雨後憑闌處，山在人間拄笏中。", "春去平蕪隨處有，鳥啼斜日滿林紅。", "伯仁空洞渾無物，容我清樽一笑同。"]'),
('aa4f3033-2ff4-499a-9d36-e3d8fdcfc87e','次韻道卿聞新鶯','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','草長江南春欲闌，曉鶯聲在綠陰間。',64,'全唐诗/poet.song.87000.json','["草長江南春欲闌，曉鶯聲在綠陰間。", "定應春恨知公子，故作清歌學小蠻。", "催盡落花風自暖，喚醒愁眼日長閑。", "隔枝時見黄金羽，始信庭柯會解顔。"]'),
('e6c7cab1-bf56-406a-8b50-8a6e3064cee0','次韻道卿縣樓觀雨之集','周紫芝','宋','宋诗','song-poetry','','[]','樓下江聲雜雨聲，斷雲初掩斷霞明。',64,'全唐诗/poet.song.87000.json','["樓下江聲雜雨聲，斷雲初掩斷霞明。", "吹殘惡熱凉生面，瀉作奔流綠繞城。", "擾擾驚禽棲不定，娟娟缺月坐來生。", "遙知舉白酬豐歲，醉裏憑欄句又成。"]'),
('6e72ab4d-f426-4119-bfe7-be90937c8892','道卿論吳中夏果詞頗夸且借蘇內相春菜詩韻作詩僕亦同賦聊爲江南解嘲','周紫芝','宋','宋诗','song-poetry','','[]','江南五月菱垂葉，葉底紫菱如紫蕨。',128,'全唐诗/poet.song.87000.json','["江南五月菱垂葉，葉底紫菱如紫蕨。", "棃香濺齒蔗漿寒，瓜熟堆盤水精滑。", "紅薑抺縷雜吳鹽，纖手淹梅带微辣。", "芳林露下摘金桃，入眼臙脂紅臉抺。", "木瓜甘酸天下無，百果論功誰可甲。", "朱櫻萬顆滴階紅，滿架蒲桃更肥茁。", "橙香栗大芋如鴟，此品秋來不勝說。", "老翁空作解嘲詩，但恐年衰左車脫。"]'),
('4bf4545c-69df-41b9-8ba1-81a23af0a474','次韻羅仲共靈泉夏夜二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','靈泉無暑竹連山，絕似秋霜五月寒。',32,'全唐诗/poet.song.87000.json','["靈泉無暑竹連山，絕似秋霜五月寒。", "我欲訪君安得往，江湖滿地一漁竿。"]'),
('8ba55c6c-e187-4a08-99f1-7f3d423b981a','次韻羅仲共靈泉夏夜二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','泉聲落枕喚詩成，傑句中含萬壑聲。',32,'全唐诗/poet.song.87000.json','["泉聲落枕喚詩成，傑句中含萬壑聲。", "起看四更山吐月，又扶藜杖到天明。"]'),
('bdbe8030-fd07-492a-963e-afe181d62e00','夜訪伯遠偶題長句','周紫芝','宋','宋诗','song-poetry','','[]','夜攜桃竹上山枝，來叩徐侯種菊籬。',64,'全唐诗/poet.song.87000.json','["夜攜桃竹上山枝，來叩徐侯種菊籬。", "憐我風霜猶短褐，喜君人物是長離。", "酣歌强對老來酒，忍淚重聽亂後詩。", "一笑相逢真我輩，此情慎勿遣兒知。"]'),
('976a124f-7bbf-4895-b93f-ec416f706041','駝山秋晚二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','詩翁老去無人數，晚歲移家在河滸。',64,'全唐诗/poet.song.87000.json','["詩翁老去無人數，晚歲移家在河滸。", "敗絮蒙頭那復霜，破屋穿天只愁雨。", "大兒窗下抄奇書，小兒燈前誦論語。", "明日羞囊餘幾何，客至無錢具鷄黍。"]'),
('44e22672-bbe4-414f-90fb-187c351dd910','駝山秋晚二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','溪邊茅屋知誰家，門前水落溪露沙。',64,'全唐诗/poet.song.87000.json','["溪邊茅屋知誰家，門前水落溪露沙。", "枯藤繞屋掛秋實，黑如點漆紅丹砂。", "蜀葵花空已收子，鷄冠樹高猶有花。", "客來倚杖主人出，屋頭日暖聽蜂衙。"]'),
('ff805f58-509b-42cd-aec5-92b2b3aa9cd1','聞張伯真割奉粟二十斛見遺而書未至戲題小篇','周紫芝','宋','宋诗','song-poetry','','[]','老去空嗤守錢虜，我亦無錢買田畝。',144,'全唐诗/poet.song.87000.json','["老去空嗤守錢虜，我亦無錢買田畝。", "未容殘月喘吳牛，空對杏花耕宿雨。", "昨宵夜誦偶連明，今日晨炊忽停午。", "長腰聞有尺素書，腹飽先懸待椎鼓。", "浣花老人殊可憐，忍饑更索饑膓語。", "故人祿米肯長供，司業酒錢時亦與。", "平生無句可驚人，未審何由坐斯苦。", "幾時去作多田君，滿田䆉稏多黄雲。", "長年飽飯作穀伯，且免勞人勤指囷。"]'),
('58e342f7-7287-438f-8598-4f80428a9946','九月十六日生日示內','周紫芝','宋','宋诗','song-poetry','','[]','從我憐君二十年，備嘗險阻與艱難。',64,'全唐诗/poet.song.87000.json','["從我憐君二十年，備嘗險阻與艱難。", "試看剪髮師陶母，肯爲親舂愧阿鸞。", "香火結緣聊爲老，杯盤爲壽小同歡。", "鹿門願遂平生志，更享全家百歲安。"]'),
('05519830-fd1f-420c-b857-c1df3b04ce5d','次韻道卿見貽','周紫芝','宋','宋诗','song-poetry','','[]','樓下秋空月似波，與君高目在庭柯。',64,'全唐诗/poet.song.87000.json','["樓下秋空月似波，與君高目在庭柯。", "新愁别後知無數，白髮年來畏轉多。", "歲月催人駒過隙，世緣相縛雉罹羅。", "多才似子仍多學，他日金鑾穩上坡。"]'),
('1f10d9c2-9d60-4a2a-9b3c-1aa06f484f1b','次韻道卿催梅','周紫芝','宋','宋诗','song-poetry','','[]','江上連朝暗飛雪，花信風遲寒凛冽。',128,'全唐诗/poet.song.87000.json','["江上連朝暗飛雪，花信風遲寒凛冽。", "東閣觀梅殊未妍，揚州何遜心應折。", "何郎思苦花欲開，羯鼓不倩天公催。", "詩翁自是催花手，能挽春從天際來。", "帳下玉人羞起晚，弄粉含姿半驕蹇。", "應憐冶葉與倡條，有意凌寒入芳苑。", "君詩好更誰與論，會令寒谷生春温。", "冰姿一笑忽滿眼，誰道鶴林花有神。"]'),
('952d59dc-b81b-4af5-b35a-6364d7e3743d','次韻道卿梅花長句','周紫芝','宋','宋诗','song-poetry','','[]','月娥窺水晚纖纖，風味能回鐵石嚴。',64,'全唐诗/poet.song.87000.json','["月娥窺水晚纖纖，風味能回鐵石嚴。", "滿地不禁飛處急，一枝猶得醉時拈。", "國香無意欺蘭蕙，天質應羞擬絮鹽。", "冷蘂依然在空谷，何人重傍少陵簷。"]'),
('e3cb8370-5b5b-481b-abdc-db28fa175703','次韻邵文伯懷桐渚與陳子高唱酬之樂','周紫芝','宋','宋诗','song-poetry','','[]','謫仙騎鯨上天去，萬古風流一丘土。',152,'全唐诗/poet.song.87000.json','["謫仙騎鯨上天去，萬古風流一丘土。", "去天尺五城南杜，晚上瞿塘望江渚。", "兩翁憔悴人不與，造物嗔渠作奇語。", "陳侯筆勢誰可禦，九鼎自可獨力舉。", "夢中尺錦君盡取，時向胸中作吞吐。", "邵郎詩高孰賓主，一笑相看兩相許。", "清歌那忍聽金縷，渠坐詩窮君勿怒。", "衰翁老氣不可鼓，篆鼎瓦棺心好古。", "此别相逢定何所，他時剝啄叩君户，藜杖經行尚堪拄。"]'),
('0ff59777-6f23-43b3-87cc-980c870c9d42','次韻靜翁雪中見過三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','年年飛雪閉寒齋，老怯風威不下階。',64,'全唐诗/poet.song.87000.json','["年年飛雪閉寒齋，老怯風威不下階。", "客至未妨頻叩户，人生何必要籠街。", "莫嫌縱飲方投轄，聞道中興已勒崖。", "自笑下愚移不得，從渠撫掌笑高柴。"]'),
('4bc43b34-812f-4d12-9d19-38289cbcde96','次韻靜翁雪中見過三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','故國飄零萬事乖，十年不見雪中階。',64,'全唐诗/poet.song.87000.json','["故國飄零萬事乖，十年不見雪中階。", "要令幽子安圭竇，少待兇酋脫藁街。", "援筆何由賦梁苑，閉門只合老蒼崖。", "君來看我煨黄獨，自採春山带葉柴。"]'),
('21e269c2-284e-4b99-a368-e75cf5e21fae','次韻靜翁雪中見過三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','端門萬馬想初回，跪賀群臣拜玉階。',64,'全唐诗/poet.song.87000.json','["端門萬馬想初回，跪賀群臣拜玉階。", "我約江鷗分雪浦，誰將烏帽踏天街。", "從遊久欲真浮海，送客懸知亦自崖。", "猶有升平臨老眼，尚堪方嶽看燔柴。"]'),
('224939cf-8bcc-4f0b-9109-ad1620e6a487','二十八日雪霽讀晁無咎集呈别乘徐彦志且以奉懷','周紫芝','宋','宋诗','song-poetry','','[]','蘇公論士昔未聞，四客輩出俱同門。',224,'全唐诗/poet.song.87000.json','["蘇公論士昔未聞，四客輩出俱同門。", "龍媒忽下洗凢馬，野鶴一舉空鷄群。", "虞皇七友廊廟具，元和十子非渠倫。", "張公屈宋排衙官，清詞麗句冰雪寒。", "秦公筆下有過秦，平生目短曹劉垣。", "金華仙伯學杜甫，句法自許窺公藩。", "晁公磊落天下士，帝遣長庚下人世。", "舊聞一醉百梨花，醉後狂歌滿天地。", "詩成只在倚馬間，高談頗似懸河翻。", "當時七發真少作，秦漢以來無此文。", "今日晴窗有佳色，積雪爲洗烟埃昏。", "千山排巒削寒玉，萬木擁户明朝暾。", "試攜塵編醒病眼，隱几一笑空爐芬。", "是中有味知者少，此意便欲從公論。"]'),
('b1a54413-5af9-4b83-8cd6-55a35270517f','題南金慎獨齋','周紫芝','宋','宋诗','song-poetry','','[]','聖道不可窮，探取隨已欲。',156,'全唐诗/poet.song.87000.json','["聖道不可窮，探取隨已欲。", "平生所受用，政可一言足。", "子思著中庸，暗室戒慎獨。", "危微恐懼心，此念旋已熟。", "學從西洛來，標榜相品目。", "袖手看屋梁，表表如鶴鵠。", "誰知胸中塵，往往盈斗斛。", "伋也而有知，寧不貽彼忸。", "吳侯蚤作吏，未肯事邊幅。", "得妙自聖處，了不關世俗。", "頗知幽隱中，日月所照燭。", "不敢欺秋毫，高情潔冰玉。", "願言從君遊，着鞭蹈前躅。"]'),
('163c2dcf-c8e4-4a6a-a799-6511f139e6d6','題彦恢家草堂','周紫芝','宋','宋诗','song-poetry','','[]','昭陵厚德如乾坤，廊廟補袞多公言。',208,'全唐诗/poet.song.87000.json','["昭陵厚德如乾坤，廊廟補袞多公言。", "徂徠官在百寮底，有時論事驚天閽。", "皂囊欲上謗已滿，霜臺不到名空尊。", "李侯自是千載士，人說贊皇今有孫。", "長安御史一驄馬，人物眼高爭薦論。", "南牀小忍便可得，直氣肯受高官吞。", "青雲垂上却回首，得州如斗車朱轓。", "兩公相望空落落，當年風采今仍存。", "古來名節與富貴，輕重略等常平分。", "天公相愛似有意，黄鵠欲舉方騰鶱。", "未開青瑣霄漢上，故著草堂烟雨閑。", "人生窮達固難料，時來鶴亦能高軒。", "願公努力善自愛，更進藥石禆華勛。"]'),
('98e89fbb-3299-44b3-8e96-bd5acc76a700','次韻道卿殘臘步遊林藪草木漸有生意三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','抱病歲忽杪，杜門誰復來。',72,'全唐诗/poet.song.87000.json','["抱病歲忽杪，杜門誰復來。", "感子陽春句，爲嘘寒谷荄。", "君才那易得，辭華陋鄒枚。", "草木不足羡，雲衢路當開。", "春意私節物，榮枯竟何哉。", "封侯與裂土，且當付輿臺。"]'),
('d30cf49a-51f8-4bb1-898c-dfbb43a56746','次韻道卿殘臘步遊林藪草木漸有生意三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','老意慘不樂，青春爲誰來。',72,'全唐诗/poet.song.87000.json','["老意慘不樂，青春爲誰來。", "藝蘭在九畹，誰能起殘荄。", "桃李忽滿眼，其寔亦枚枚。", "耕田種芝草，玲瓏殊未開。", "榮華競春事，于我何有哉。", "當浮白玉闕，下睨黄金臺。"]'),
('7cbc5169-b5a4-4819-8294-c67822b85805','次韻道卿殘臘步遊林藪草木漸有生意三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','人生有榮瘁，否極泰必來。',72,'全唐诗/poet.song.87000.json','["人生有榮瘁，否極泰必來。", "君看九地春，寸草無餘荄。", "白首始一遇，蒲輪迎老枚。", "祁隱不可招，詡徑行當開。", "我欲尋盧敖，盧敖安在哉。", "但當急洗眼，看子登雲臺。"]'),
('d497cffb-9f0f-4b36-9d22-c79dadcff02a','讀元微之詩有感','周紫芝','宋','宋诗','song-poetry','','[]','從古才高少識真，此公句法老尤新。',64,'全唐诗/poet.song.87000.json','["從古才高少識真，此公句法老尤新。", "世間言語渾無用，天上吹嘘却要人。", "但遣前旒知娬媚，莫嫌後榻有嚬呻。", "夢中富貴能多少，空使清流作怒嗔。"]'),
('78026f0e-97d8-4286-ba2f-02cec5f7aec1','舟次句茨','周紫芝','宋','宋诗','song-poetry','','[]','移居來近玉湖中，漁户新添白脚翁。',64,'全唐诗/poet.song.87000.json','["移居來近玉湖中，漁户新添白脚翁。", "覓句深慚何水部，浮家全似陸龜蒙。", "山寒政恐無黄獨，地濕應須要鞠藭。", "晚日飄零天不管，雙鳧乘雁聽西東。"]'),
('4a1dabd9-8978-48d1-9c81-7c5de8e1f453','雨寒連日大風病中作此詩','周紫芝','宋','宋诗','song-poetry','','[]','門外湖光瀲灧中，春寒那聽雨濛濛。',64,'全唐诗/poet.song.87000.json','["門外湖光瀲灧中，春寒那聽雨濛濛。", "吹殘梅雪如山雪，顛得江風似颶風。", "雙燕擬來尋舊約，小桃渾未試新紅。", "黄紬獨擁眠方熟，剝啄何須來惱翁。"]'),
('92cb5f7a-94cd-4d36-b744-dc582df5d5a7','暝立','周紫芝','宋','宋诗','song-poetry','','[]','山隔湖邊路，人棲柳下扉。',48,'全唐诗/poet.song.87000.json','["山隔湖邊路，人棲柳下扉。", "船從几席過，燕掠水波飛。", "鳥亦昏纔定，牛知晚自歸。", "幽人常暝立，日日到斜暉。"]'),
('49dfac73-4b0a-4f5d-b3d7-2b458b180382','次韻黄文若寄燈夕不出之作','周紫芝','宋','宋诗','song-poetry','','[]','少小從舞雩，鼓瑟常屢希。',252,'全唐诗/poet.song.87000.json','["少小從舞雩，鼓瑟常屢希。", "結髪事墳典，願言探玄微。", "鐘鳴漏忽盡，殘星獨暉暉。", "征鞍老塗路，白露霑裳衣。", "齒髪倏已暮，富貴終難祈。", "佳辰念京洛，流車看騑騑。", "結客少年場，兒女如瓠肥。", "紅燈白晝暖，醉盌黄金揮。", "回頭二十載，狗盗相因依。", "時光了如夢，菽粟不救饑。", "飄零少行樂，老大空歔欷。", "今年四海靜，扊扅張外扉。", "芙渠焰明缸，金波麗春幃。", "穠李樽前歌，遊子月下稀。", "錚錚銀漏中，撲撲春蛾飛。", "此老最可憐，已杜禦寇機。", "但知草中和，浩蕩歌皇威。", "晶熒一短檠，搔首悟昨非。", "風流如黄香，不作傳柑歸。", "更攜袖中珠，來尋北山薇。", "詩盟倘可同，願復無余遺。"]'),
('f43a00b9-b7fb-4c97-9028-932d1e0025a1','題趙安定像','周紫芝','宋','宋诗','song-poetry','','[]','烏巾白角雲錦裘，長脛骯髒高結喉。',128,'全唐诗/poet.song.87000.json','["烏巾白角雲錦裘，長脛骯髒高結喉。", "王孫自是真龍種，世上懸知無此儔。", "醉裏哦詩詩欲就，風月平欺兩肩瘦。", "秋風爲神玉爲骨，畫手何從寫奇秀。", "仇池客多誰在亡，高準虬髯唯汝陽。", "紫皇苦欲奏璈語，此曲至今空斷腸。", "腸斷公歌侍兒拍，甕裏黄柑自春色。", "老坡不見空凄然，此詩此意無人傳。"]'),
('0eb0f0df-701d-466a-8946-17f844ea6365','題包鼎大虎圖','周紫芝','宋','宋诗','song-poetry','','[]','人間妙伎古亦有，畫虎從來易成狗。',160,'全唐诗/poet.song.87000.json','["人間妙伎古亦有，畫虎從來易成狗。", "何人爲作老於菟，鼎死百年無此手。", "想當運筆亦有神，睥睨知誰看回肘。", "便恐陰崖風雨來，何止草中狐兔走。", "易生驚猿羞掛枝，周昉稺犬空復肥。", "畫中生意似可喜，此虎一出無餘姿。", "邇來喪亂書阨苦，唯有君家此畫古。", "妖狐一丘渠自安，狡兔三窟無人取。", "建章宮殿空咸陽，猛士知誰守疆土。", "藜藿不採虎在山，安得有臣如此虎。"]'),
('e5d6f909-e81d-4be8-98d5-102404c8299c','忻師介軒','周紫芝','宋','宋诗','song-poetry','','[]','念我昔年少，剛介頗成癖。',144,'全唐诗/poet.song.87000.json','["念我昔年少，剛介頗成癖。", "多錢嗤守虜，飽飯嘲穀伯。", "有口能雌黄，反眼輒青白。", "阿奴恃火攻，未必出下策。", "一笑當尊拳，僅得貸雞肋。", "只今真老大，鬚髯已如戟。", "折肱成良醫，忤物知何益。", "要令空洞中，下視滄溟窄。", "嶢嶢固難全，容容聊自適。", "知雌在守雄，外曲當內直。", "此理吾已明，師獨未之得。", "願言戒覆車，聊用銘子壁。"]'),
('4d9b8f47-a409-4ecf-865d-6de40a7861c1','三月五日晚霽大風','周紫芝','宋','宋诗','song-poetry','','[]','雨後風扉擁青嶂，家在斜陽晚潮上。',64,'全唐诗/poet.song.87000.json','["雨後風扉擁青嶂，家在斜陽晚潮上。", "沙頭飛盡雪色鷗，柳下初横短蓬舫。", "皇天惡料風忽顛，賈客倉黄回五兩。", "老人倚杖不肯歸，看打南湖白頭浪。"]'),
('a8a0d635-6234-46b2-a137-60cee8bfeb1e','九江王興道早歲休官作易安奚疑二室要余作詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','心如止水不妨清，身似無官不爲名。',64,'全唐诗/poet.song.87000.json','["心如止水不妨清，身似無官不爲名。", "但把一椽供偃蹇，從他百鬼瞰高明。", "路迷鷄犬家何在，身與漁樵席屢爭。", "眼看青雲有矰繳，鷦鷯巢小未宜輕。"]'),
('e727f132-b37e-4d1f-a798-bf30afa875a3','九江王興道早歲休官作易安奚疑二室要余作詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','朽骨枯莖未必靈，行藏何苦訪君平。',64,'全唐诗/poet.song.87000.json','["朽骨枯莖未必靈，行藏何苦訪君平。", "問津世路心先懶，買地江干計已成。", "解向急流求勇退，便知幽事合關情。", "裕陵將種今誰在，但恐君王問姓名。"]'),
('e4c45285-a50f-4a52-b046-83bb55968312','倚杖','周紫芝','宋','宋诗','song-poetry','','[]','雨脚收寒久，東風倚杖頻。',48,'全唐诗/poet.song.87000.json','["雨脚收寒久，東風倚杖頻。", "浪翻雙鷺起，船過小鵝嗔。", "客飯長腰米，林居折角巾。", "澆山一掬淚，回首故鄉春。"]'),
('6fb1147d-89c6-4ea4-a01d-45cec3a045b3','寒食日歸郡舟中作二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','歸櫂浮江水，寒衾擁醉眠。',48,'全唐诗/poet.song.87000.json','["歸櫂浮江水，寒衾擁醉眠。", "亂花飛送客，細浪穩隨船。", "淚落澆山酒，愁生禁火天。", "一從胡騎入，飄泊到今年。"]'),
('3ab4e090-03d9-4505-99ec-2c26a61552dd','寒食日歸郡舟中作二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','世事聊相挽，吾歸亦有期。',48,'全唐诗/poet.song.87000.json','["世事聊相挽，吾歸亦有期。", "白湖爲客久，寒食到家遲。", "接屋花仍在，遮門柳自垂。", "向來歌社裏，應著老人嬉。"]'),
('ff70dd91-a094-4925-b1d8-b507e38cebc5','春事','周紫芝','宋','宋诗','song-poetry','','[]','春事無多日，江村有數家。',48,'全唐诗/poet.song.87000.json','["春事無多日，江村有數家。", "等閑飛燕子，容易落梨花。", "草色過薄雨，柳陰暝淡霞。", "詩成不歸去，暝立看棲鴉。"]'),
('dfb82311-5e2f-4ba0-b1e7-4f991c8a6e18','湖居春晚雜賦八絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','雪屋臨湖憶繫船，柳汀吹絮又經年。',32,'全唐诗/poet.song.87000.json','["雪屋臨湖憶繫船，柳汀吹絮又經年。", "白鷗大似知人意，分與滄波十里天。"]'),
('748e2327-9d0b-4b5f-8638-d376c2cf1a71','湖居春晚雜賦八絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','雨後春湖拍拍流，近門誰繫兩三舟。',32,'全唐诗/poet.song.87000.json','["雨後春湖拍拍流，近門誰繫兩三舟。", "水邊寒食飛雙燕，柳外斜陽臥一牛。"]'),
('9508d249-5e36-421e-8f13-e094f2765d4a','湖居春晚雜賦八絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','數日東風緊閉門，小桃知有一枝新。',32,'全唐诗/poet.song.87000.json','["數日東風緊閉門，小桃知有一枝新。", "花飛不復到老眼，可是春寒欺得人。"]'),
('4b2a7ddb-0688-4389-b347-0424ef512592','湖居春晚雜賦八絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','倚牀相伴一枝藤，强作春遊老不能。',32,'全唐诗/poet.song.87000.json','["倚牀相伴一枝藤，强作春遊老不能。", "花底嬋娟詩嫵媚，枕中日月睡瞢騰。"]'),
('89e9b7b0-34ec-42df-9323-abfa76613bb0','湖居春晚雜賦八絕  其五','周紫芝','宋','宋诗','song-poetry','','[]','黄蜂歸後燕成家，楊柳初飛一兩花。',32,'全唐诗/poet.song.87000.json','["黄蜂歸後燕成家，楊柳初飛一兩花。", "已是無春可拚得，亂紅何苦惱霜華。"]'),
('7ffbfbca-36d2-474f-914e-eb4baa446e8d','湖居春晚雜賦八絕  其六','周紫芝','宋','宋诗','song-poetry','','[]','曉鏡烟凝水繞湖，晚汀飛鷺又成圖。',32,'全唐诗/poet.song.87000.json','["曉鏡烟凝水繞湖，晚汀飛鷺又成圖。", "早知魚鳥堪同樂，愁得華顛政不須。"]'),
('5a50bc9f-df9c-417e-980c-11b507fed4e5','湖居春晚雜賦八絕  其七','周紫芝','宋','宋诗','song-poetry','','[]','兩日東風着意顛，南湖風浪不行船。',32,'全唐诗/poet.song.87000.json','["兩日東風着意顛，南湖風浪不行船。", "飛沙走石成何事，吹得楊花也上天。"]'),
('509d2527-95ea-4c59-9b16-d9a56b7805a1','湖居春晚雜賦八絕  其八','周紫芝','宋','宋诗','song-poetry','','[]','湖水波連野水邊，欲晴鳩喚未晴天。',32,'全唐诗/poet.song.87000.json','["湖水波連野水邊，欲晴鳩喚未晴天。", "懶吹雲去風無力，打得花殘雨可憐。"]'),
('032e5161-6420-488a-99a8-25e969b2f218','雨中立杏花下','周紫芝','宋','宋诗','song-poetry','','[]','淺紅疏蘂出牆頭，事往人空鎖北樓。',64,'全唐诗/poet.song.87000.json','["淺紅疏蘂出牆頭，事往人空鎖北樓。", "鳥爲春愁渾不語，花知人意亦含羞。", "東風脈脈情何限，細雨濛濛淚不休。", "却憶去年花下醉，依稀記得小蠻謳。"]'),
('60dc3b25-6d81-46de-a7ab-e13e6d8ddcf0','恭聞已迎原廟聖容入行在所','周紫芝','宋','宋诗','song-poetry','','[]','戎氣腥京洛，橋山萬木悲。',48,'全唐诗/poet.song.87000.json','["戎氣腥京洛，橋山萬木悲。", "園陵回望遠，袞繡自天垂。", "日月瞻遺像，衣冠拜赤墀。", "櫻桃薦原廟，重見漢官儀。"]'),
('8857ff50-61c4-4591-b9b5-227344df2fd1','雨後二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','造物有佳思，放晴娛薄遊。',48,'全唐诗/poet.song.87000.json','["造物有佳思，放晴娛薄遊。", "湖光散鳧雁，野日下羊牛。", "水欲滿舊壑，草還青遠疇。", "雲來猶倚杖，雨過忽横舟。"]'),
('033bc3d9-7451-4b41-8f74-03ba872b47cb','雨後二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚日纖纖出，痴雲陣陣回。',48,'全唐诗/poet.song.87000.json','["晚日纖纖出，痴雲陣陣回。", "風林無定翼，晴漢有殘雷。", "白水自天去，青山隨眼來。", "峰高月未吐，更擬着詩催。"]'),
('2d6ccab1-fb42-4721-8ab7-dcf8946b248b','夜半熱甚湖上短歌','周紫芝','宋','宋诗','song-poetry','','[]','江頭老父誰共語，白髮垂肩汗如雨。',64,'全唐诗/poet.song.87000.json','["江頭老父誰共語，白髮垂肩汗如雨。", "兒方高枕作自畀，雷翁開門傍河滸。", "水邊雲黑雨欲成，山外天高月將吐。", "江湖滿地身未歸，星斗橫空夜如許。"]'),
('a272d385-d98c-4d4c-a9d4-ae04a350c06a','舟中睡起','周紫芝','宋','宋诗','song-poetry','','[]','幅巾聽雨臥風檣，呼得青奴伴晚涼。',64,'全唐诗/poet.song.87000.json','["幅巾聽雨臥風檣，呼得青奴伴晚涼。", "白髮蠹書緣已熟，黑甜欹枕味偏長。", "月侵冰簟何妨白，舟入荷花不奈香。", "更倩長年打雙槳，雲山青處是吾鄉。"]'),
('60ce804d-0746-4f6f-9ea2-e274f00f87b5','五月十九日雨中困臥起讀西清錄見其載歐陽文忠公與許昌齡事甚異作此','周紫芝','宋','宋诗','song-poetry','','[]','四字丹書亦偶然，石唐未必是真仙。',32,'全唐诗/poet.song.87000.json','["四字丹書亦偶然，石唐未必是真仙。", "無人解得潮州意，也復留衣與大顛。"]'),
('ccda9e68-4f2c-490b-aba0-70c6af034778','即席二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','凋盡朱顔年少春，不堪柳下對離樽。',32,'全唐诗/poet.song.87000.json','["凋盡朱顔年少春，不堪柳下對離樽。", "劉郎已是無腸斷，更唱陽關惱客魂。"]'),
('5f3232bd-55f8-4b00-9956-25d92688e430','即席二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','舊家明月醉歸時，夜靜朱樓歌折枝。',32,'全唐诗/poet.song.87000.json','["舊家明月醉歸時，夜靜朱樓歌折枝。", "只有杜娘真好事，樽前猶唱後山詞。"]'),
('d445ee80-d2c5-451d-9ac5-9767caae8f40','將歸白湖而雨','周紫芝','宋','宋诗','song-poetry','','[]','世間那得此間身，恐是前生賀季真。',64,'全唐诗/poet.song.87000.json','["世間那得此間身，恐是前生賀季真。", "白水窗閑頻入夢，黄梅雨細却留人。", "重聽欸乃烟中曲，淨掃離騷几上塵。", "但得南風送歸棹，未應幽獨解傷神。"]'),
('60c2c83f-d22e-4ed9-854e-268d107f8f05','中元日雨中錄所見','周紫芝','宋','宋诗','song-poetry','','[]','顛風急來萬木萎，迅雷不聼人掩耳。',64,'全唐诗/poet.song.87000.json','["顛風急來萬木萎，迅雷不聼人掩耳。", "南山栖鳥失故巢，北山翔龍卷湖水。", "翔龍掉尾不肯收，眼看滄波接雲起。", "想當舟楫避驚濤，無數魚蝦趁龍尾。"]'),
('8c43b373-bc9f-4cf5-a6c7-10a4b37cfbf4','讀張載揚所示近詩頗懷其人','周紫芝','宋','宋诗','song-poetry','','[]','眼中人物欠曹劉，老矣逢君接勝遊。',64,'全唐诗/poet.song.87000.json','["眼中人物欠曹劉，老矣逢君接勝遊。", "詩與漫郎推行輩，字從坡老得源流。", "羸驂又踏千山去，黄菊空催九日愁。", "横槊想多秋後句，詩成須着錦囊收。"]'),
('5f0196fe-4f9e-42b9-acfc-0de87c98ecea','次韻仲照秋懷四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','日斜樓閣暮雲中，黄菊紅蕖滿院風。',32,'全唐诗/poet.song.87000.json','["日斜樓閣暮雲中，黄菊紅蕖滿院風。", "酒熟未酬花爛熳，詩來時聽玉丁東。"]'),
('2428f228-7ac2-44c3-8e9c-a0966c650a23','次韻仲照秋懷四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','老去篇章誰與酬，秋來又喜與君遊。',32,'全唐诗/poet.song.87000.json','["老去篇章誰與酬，秋來又喜與君遊。", "遺音固自成三歎，妙語不應慚四愁。"]'),
('869af049-3c81-4f48-851c-de1831522e74','次韻仲照秋懷四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','白髮新愁滿眼中，騷人零落怨秋風。',32,'全唐诗/poet.song.87000.json','["白髮新愁滿眼中，騷人零落怨秋風。", "年來詩思成何事，聊伴寒螿泣露叢。"]'),
('b52b47cd-fd6b-4474-b554-d29feb81a273','次韻仲照秋懷四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','秋在幽人行樂中，好山欲盡更須窮。',32,'全唐诗/poet.song.87000.json','["秋在幽人行樂中，好山欲盡更須窮。", "花姑水繞幾時到，罨畫溪遙路欲通。"]'),
('4920e055-8b2e-4ed4-b79a-88a6de2ed904','秋雨連日','周紫芝','宋','宋诗','song-poetry','','[]','老鬢風吹急，愁雲带雨飛。',48,'全唐诗/poet.song.87000.json','["老鬢風吹急，愁雲带雨飛。", "白添平岸水，紅掩傍幽扉。", "力盡方謀食，天寒未授衣。", "此身慚社燕，秋晚亦能歸。"]'),
('f3c048ea-e739-4048-94e2-422471ff15ce','次韻羅仲共教授閑居三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','爲米要令陶令出，無氈今坐廣文窮。',64,'全唐诗/poet.song.87000.json','["爲米要令陶令出，無氈今坐廣文窮。", "懸知嚼蠟世味薄，未抵撲衣山色濃。", "大蓋且從渠自擁，小槽當與客頻中。", "家談安得從三老，華萼同編是古風。"]'),
('0c23757d-9185-422b-b787-58de9cc003a5','次韻羅仲共教授閑居三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','了事痴兒不到詩，間中鼓吹自應奇。',64,'全唐诗/poet.song.87000.json','["了事痴兒不到詩，間中鼓吹自應奇。", "莫教句法驚人甚，便恐功名入手遲。", "性癖雅宜嵇叔懶，官閑只有漫郎知。", "庭梧想得西風急，秋意微生楚些悲。"]'),
('529a91d4-a9a4-4ad1-9d35-10758273f34b','次韻羅仲共教授閑居三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','擬築揚雄宅一區，碧鷄坊外且成居。',64,'全唐诗/poet.song.87000.json','["擬築揚雄宅一區，碧鷄坊外且成居。", "湖江君尚作浮宅，風雨我當無敝廬。", "平日夢遊嗟路遠，新凉見面恰秋餘。", "便須載酒相從去，要識平生未見書。"]'),
('b59e8759-9ccc-428f-9f44-ed11feda18cf','白湖聞雁三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','斗落參横天雨霜，夢殘燈盡客思鄉。',32,'全唐诗/poet.song.87000.json','["斗落參横天雨霜，夢殘燈盡客思鄉。", "丁寧莫作叫雲去，老眼不禁秋夜長。"]'),
('df5102fd-ba60-47cc-aa3f-387611fa8948','白湖聞雁三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚向瀕湖寄一椽，只憑沙雁與周旋。',32,'全唐诗/poet.song.87000.json','["晚向瀕湖寄一椽，只憑沙雁與周旋。", "北來南去莫惆悵，我亦飄零那記年。"]'),
('d53ca5b6-b2ae-43ad-b9e8-f87138169301','白湖聞雁三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','華人流落幾秋風，南望中原信不通。',32,'全唐诗/poet.song.87000.json','["華人流落幾秋風，南望中原信不通。", "好寄書來蘇屬國，君王方射上林中。"]'),
('b042676a-8c38-42ee-8bda-bc6c7f1cbce1','九日風雨終日用懷載揚韻','周紫芝','宋','宋诗','song-poetry','','[]','九日清尊强挽秋，滿庭風雨復誰遊。',64,'全唐诗/poet.song.87000.json','["九日清尊强挽秋，滿庭風雨復誰遊。", "俗人言下無三語，此老胸中有九流。", "白髮不妨欺短帽，黄花應解笑痴愁。", "客情老去何曾好，雙鯉書來幾日收。"]'),
('1d10a5a1-716b-4d16-908c-e7844f6e1d3c','九日不出','周紫芝','宋','宋诗','song-poetry','','[]','白髮誰憐我，黄花最憶渠。',48,'全唐诗/poet.song.87000.json','["白髮誰憐我，黄花最憶渠。", "酒盃今日把，筋力去年殊。", "身遠秋如夢，謀疏老更愚。", "客愁澆不下，强欲醉茱萸。"]'),
('d24c2472-f1bf-43cd-b769-5df4b17ea67b','橋成','周紫芝','宋','宋诗','song-poetry','','[]','尚憶防秋日，疏渠轉曲城。',48,'全唐诗/poet.song.87000.json','["尚憶防秋日，疏渠轉曲城。", "萬方知盗息，此地看橋成。", "拄杖知頻過，遊魚莫漫驚。", "明朝趁虚去，畫柱曉霜明。"]'),
('4fbbd01b-2bd0-4ba9-b2a7-fed85f987d9d','雪夜','周紫芝','宋','宋诗','song-poetry','','[]','病眼怕遙夜，宿爐依小温。',48,'全唐诗/poet.song.87000.json','["病眼怕遙夜，宿爐依小温。", "酒醨嫌雪厚，書細苦燈昏。", "殘臘歸時夢，他鄉盡處村。", "可憐雙白鬢，深閉一蓬門。"]'),
('bff44a1f-96aa-4052-b77e-174a2492298c','讀蔡中郎傳','周紫芝','宋','宋诗','song-poetry','','[]','人生無先知，頗欲邀後福。',156,'全唐诗/poet.song.87000.json','["人生無先知，頗欲邀後福。", "自言苟依違，安得有顛覆。", "伯喈英偉資，高義甚敦篤。", "不爲左回天，輒作流水曲。", "立朝有公言，誰能保家族。", "朝奏皂囊封，暮就洛陽獄。", "晚節不自守，一跌變前躅。", "起依千里草，九徙如轉軸。", "卓死固已久，安得復嚬蹙。", "琴中知殺氣，此理反未燭。", "陋哉王司徒，避謗私欲戮。", "公忠信安在，志操等流俗。", "何能起頹綱，此輩真碌碌。"]'),
('c33836dd-7329-48c1-9e81-576a109bfcfa','責鷄','周紫芝','宋','宋诗','song-poetry','','[]','豢犬欲司夜，畜鷄要鳴晨。',132,'全唐诗/poet.song.87000.json','["豢犬欲司夜，畜鷄要鳴晨。", "二物一失職，遂辜畜養恩。", "嗟我籠中鷄，芥羽光照人。", "峨冠事飲啄，緘口隨晨昏。", "我怒欲爾烹，鷄笑復自陳。", "君看多言者，以忠獲怒嗔。", "臺評與幕辨，呶呶常殺身。", "幸此北窗臥，頗似羲皇民。", "五起笑朝士，三號驚夢魂。", "使子臥紅日，謝客扃柴門。", "此意殊不惡，誚我無諄諄。"]'),
('d9e8d626-e56b-49db-92b9-0d862fe1673f','客舍二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','日日湖邊路，頻來我不嗔。',48,'全唐诗/poet.song.87000.json','["日日湖邊路，頻來我不嗔。", "故山無百里，客舍遂三春。", "紅落含桃過，青垂小杏新。", "光陰花委地，飄泊燕依人。"]'),
('8defa591-6ee9-490d-afe9-eead54dd9c35','客舍二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','疇昔江湖意，兒曹總不知。',48,'全唐诗/poet.song.87000.json','["疇昔江湖意，兒曹總不知。", "幅巾霑雨過，拄杖看雲移。", "鳯子飛應遠，鶯兒語最遲。", "閑從梅雪後，直到麥秋時。"]'),
('febb2fb7-52c8-4cf7-9c73-dba114bb6875','送張顛東歸','周紫芝','宋','宋诗','song-poetry','','[]','張顛佳處是清高，不但詩狂酒亦豪。',64,'全唐诗/poet.song.87000.json','["張顛佳處是清高，不但詩狂酒亦豪。", "自說平生耽翰墨，未嘗名諱落官曹。", "書工恥作雲間榜，畫好能添頰上毛。", "早信人間苦荆棘，不嫌門外長蓬蒿。"]'),
('f5be20f5-bc9d-478f-b662-66c8c471c5dd','薄暮二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','物外無餘子，愁邊有是翁。',48,'全唐诗/poet.song.87000.json','["物外無餘子，愁邊有是翁。", "夢回驚日脚，雨罷看雲峰。", "天與長閑處，湖供不斷風。", "猶嫌太多事，身落亂書叢。"]'),
('efe459ca-57c4-41e4-8b43-265133425d27','薄暮二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','睡熟不知雨，夢殘無限凉。',48,'全唐诗/poet.song.87000.json','["睡熟不知雨，夢殘無限凉。", "鶯飛時到眼，鷺起不成行。", "瓜熟分蒼玉，蓮香擘翠房。", "掃門還待月，近水更移床。"]'),
('92df704c-4ff5-4fc6-a36f-44f6f28303a7','靜夜二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','家與重湖近，門當永夜開。',48,'全唐诗/poet.song.87000.json','["家與重湖近，門當永夜開。", "鷺隨波浩蕩，人共月徘徊。", "曉色催星落，飛雲带雨來。", "長鬚汲水去，小艇淂魚回。"]'),
('7a794a44-64ee-40a6-b40d-2b4ee6b408fb','靜夜二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','湖影入散髪，晚沙横斷汀。',48,'全唐诗/poet.song.87000.json','["湖影入散髪，晚沙横斷汀。", "冠欹從自落，門設未嘗扃。", "鬼着林邊火，螢翻水上星。", "時聞有船過，月黑夜冥冥。"]'),
('1efd73eb-9e36-4475-b262-0fbbb5cbb646','雨晴望青山','周紫芝','宋','宋诗','song-poetry','','[]','世間尤物如異人，青山不入諸山群。',160,'全唐诗/poet.song.87000.json','["世間尤物如異人，青山不入諸山群。", "晚來濃翠欲成滴，雨後數鬟高切雲。", "人言兹山下埋玉，太白祠扉落巖谷。", "至今樵牧無斧斤，餘潤油然歸草木。", "往歲小生來酹公，秋山未霜葉尚綠。", "是時落日在屋梁，彷彿如照公眉目。", "今我不樂湖水濱，青山到眼無朝昏。", "更欲再拜望拱木，公已乘鸞上天門。", "帝鄉渺渺不知處，誰能爲我招清魂。", "死生夜旦何足道，不敢復作湘纍文。"]'),
('1cf6953d-c542-4128-ac02-9a29e04bdc9d','僕去歲作湖居十二詩向開叔有詩次韻迺爲謝','周紫芝','宋','宋诗','song-poetry','','[]','三年湖雨一茅茨，坐遣幽人識面遲。',64,'全唐诗/poet.song.87000.json','["三年湖雨一茅茨，坐遣幽人識面遲。", "遺恨忽從愁裏盡，交情先向句中知。", "重尋故里空勞夢，亟買歸舟會有期。", "何日劇談聽亹亹，滿傾春酒細論詩。"]'),
('63e2441c-333f-4270-8617-b174d9e99e49','得木犀','周紫芝','宋','宋诗','song-poetry','','[]','三年身在菰蒲裏，手把巖花意惘然。',32,'全唐诗/poet.song.87000.json','["三年身在菰蒲裏，手把巖花意惘然。", "折得秋芳香滿袖，夢魂常繞故山前。"]'),
('29f791cf-1298-417c-9049-719f53615348','夜苦秋蚊達旦不寐','周紫芝','宋','宋诗','song-poetry','','[]','昔年記淮邦，茅廬蔚秋草。',120,'全唐诗/poet.song.87000.json','["昔年記淮邦，茅廬蔚秋草。", "兩耳無晨昏，秋蚊困飛繞。", "利吻極慘傷，群飛固輕矯。", "懸知孀女祠，未可較多少。", "至今夢中雷，客枕疑已曉。", "那知三家村，復此終夕撓。", "青烟鬱蒿艾，横空益奔擾。", "手倦勞撲緣，眼病惡薰燎。", "誰言天宇大，微物吝除剿。", "何必養嘉羞，便可付丹鳥。"]'),
('9a3118f0-e952-467f-81a2-08c27f2de8ee','歸自白湖舟中作','周紫芝','宋','宋诗','song-poetry','','[]','客舍三寒暑，扁舟八往還。',48,'全唐诗/poet.song.87000.json','["客舍三寒暑，扁舟八往還。", "殘年不如意，老色日凋顔。", "暗谷鳴珊珮，晴巒結翠鬟。", "江禽渾識面，似欲喚人閑。"]'),
('b8e44e23-d3d1-4574-8e34-e392734286fc','寄家龍谿寺小閣初成','周紫芝','宋','宋诗','song-poetry','','[]','三年波浸白湖門，佛屋新分水北村。',64,'全唐诗/poet.song.87000.json','["三年波浸白湖門，佛屋新分水北村。", "窗可近書真窈窕，室纔容榻頗深温。", "妻孥共社同香火，魚鼓催人作曉昏。", "雪頷已疏憐我老，雲蹤無定與誰論。"]'),
('e40fd83a-d9b2-4936-96db-390f5064fe54','次韻雷飛卿送其女兄南歸','周紫芝','宋','宋诗','song-poetry','','[]','蘭皋飛佩一凄然，别酒深傾玉滿船。',64,'全唐诗/poet.song.87000.json','["蘭皋飛佩一凄然，别酒深傾玉滿船。", "誰喚孤帆落天際，盡驅秋色到愁邊。", "燎鬚心在人能說，擬絮才高墨未乾。", "莫向南湖頻着眼，斷鴻疏影在雲烟。"]'),
('2cb58f70-898e-46e2-b2df-53329bdd5d3d','次韻陳季陵閲猥藁見寄','周紫芝','宋','宋诗','song-poetry','','[]','相思一日九迴腸，多謝來書細作行。',64,'全唐诗/poet.song.87000.json','["相思一日九迴腸，多謝來書細作行。", "鏡裏有霜憐我老，鼎中無臠付君嘗。", "衰顔本自羞連璧，佳句仍驚得夜光。", "五鳯樓高無此手，曹劉真是及肩牆。"]'),
('fa4361ca-a8e8-40d8-9f8a-cdf24b98d66e','次韻文殊老人題寶頂寺','周紫芝','宋','宋诗','song-poetry','','[]','門連弱水不可渡，山似妙高知幾尋。',64,'全唐诗/poet.song.87000.json','["門連弱水不可渡，山似妙高知幾尋。", "得雨僧分香積飯，行檀人施褭蹄金。", "重新佛屋龍天喜，已退魔軍歲月深。", "老去願隨君共隱，誰能擁膝更長吟。"]'),
('42be647c-6a83-4bae-83d3-56d77dc07802','楊次公侍講得古印于洪井其文云東海開國次翁之子德潤以贈徐伯遠伯遠有詩次韻','周紫芝','宋','宋诗','song-poetry','','[]','王謝風流本自長，天教洪井發珍藏。',64,'全唐诗/poet.song.87000.json','["王謝風流本自長，天教洪井發珍藏。", "定知東海新金斗，可繼文安舊印章。", "龜去豈無江上戀，鵲來今得石中黄。", "傳家已作他年兆，莫把功名付錦囊。"]'),
('09c35f08-880d-4be2-936b-02270be14ae1','次韻雷飛卿遊山時余以病不往','周紫芝','宋','宋诗','song-poetry','','[]','一病能令百念闌，霜蓬零亂照衰顔。',64,'全唐诗/poet.song.87000.json','["一病能令百念闌，霜蓬零亂照衰顔。", "心知只可開三徑，炙手何勞叩八關。", "老喜社中多臭味，夢思方外有躋攀。", "勸君莫放尋山屐，嬴取浮生半日閑。"]'),
('bf9857e0-854e-4c51-9229-0b5f0986f95a','渡陂南用斜川韻','周紫芝','宋','宋诗','song-poetry','','[]','萬物自有得，吾生感行休。',120,'全唐诗/poet.song.87000.json','["萬物自有得，吾生感行休。", "及茲天氣佳，步尋水南遊。", "青板得野航，竟渡一葦流。", "乘流本無心，豈有不下鷗。", "開口月有幾，百年終一邱。", "與世似異趨，此行誰我儔。", "村醪亦足醉，對影自獻酬。", "未知垂老日，能遂此樂不。", "事定會當諧，不復懷預憂。", "但願營自安，孰是都無求。"]'),
('bfd7e539-b850-47e6-9837-2a886523e234','歸陂北用斜川韻','周紫芝','宋','宋诗','song-poetry','','[]','薄遊不盡興，歸臥當少休。',120,'全唐诗/poet.song.87000.json','["薄遊不盡興，歸臥當少休。", "曲水雖陳迹，斜川有新遊。", "浩歌獨長往，豈亦慚此流。", "僑寓三家村，飄如浮水鷗。", "屢爭漁樵席，共守狐鼠邱。", "削跡屏冠服，索居謝朋儔。", "樽中有餘滴，子獻復父酬。", "殷勤問穉子，汝復樂此不。", "稚子掉頭笑，老夫豁深憂。", "但令常復爾，過是吾何求。"]'),
('eefbf2a2-d3db-492e-9021-5016e88564b4','舟中次韻飛卿贈别長句','周紫芝','宋','宋诗','song-poetry','','[]','早歲從田歎不逢，老隨乘雁聽西東。',64,'全唐诗/poet.song.87000.json','["早歲從田歎不逢，老隨乘雁聽西東。", "青山約在何時了，白髮歡成一笑空。", "昨夜清歌催别酒，只今寒月上孤蓬。", "相逢莫怪長相憶，舉世交遊無此風。"]'),
('6ab12542-c4e3-49c4-b189-095b308dcd5c','雪後望文脊諸峰哦韋蘇州門對寒流雪滿山之句得兩詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','雪壓寒林春未回，晚山猶带玉崔嵬。',32,'全唐诗/poet.song.87000.json','["雪壓寒林春未回，晚山猶带玉崔嵬。", "誰將舊日韋郎句，貌取郭煕平遠來。"]'),
('fba5b8c5-038b-4c2e-bd55-f246b1f4f154','雪後望文脊諸峰哦韋蘇州門對寒流雪滿山之句得兩詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','新來嫋嫋娉娉雪，猶在重重疊疊山。',32,'全唐诗/poet.song.87000.json','["新來嫋嫋娉娉雪，猶在重重疊疊山。", "莫作故時峰嶺看，玉京今不是人間。"]'),
('c2549b90-cc77-4414-b53c-0138ad62c86c','送方元相宰錢塘','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲路飛騰合到君，不應猶現宰官身。',64,'全唐诗/poet.song.87000.json','["雲路飛騰合到君，不應猶現宰官身。", "未分東觀消長日，聊爲西湖作主人。", "天近得聲知亦易，民饑當念可須嗔。", "簿書叢裏江山在，了事何妨得句頻。"]'),
('18d2417f-8a8e-4976-b761-791e01b9c6b6','向開叔借陳公詩卷以詩奉寄且易乙藁  其一','周紫芝','宋','宋诗','song-poetry','','[]','誰言靜寄是窮兒，盡得陳公晚歲詩。',32,'全唐诗/poet.song.87000.json','["誰言靜寄是窮兒，盡得陳公晚歲詩。", "一讀便醒雙淚眼，頭風更擬倩誰醫。"]'),
('a66e2a6e-76df-4166-a7e8-3cf81398ce95','向開叔借陳公詩卷以詩奉寄且易乙藁  其二','周紫芝','宋','宋诗','song-poetry','','[]','平生不識陳驚坐，傳得新詩喜失牀。',32,'全唐诗/poet.song.87000.json','["平生不識陳驚坐，傳得新詩喜失牀。", "聞道明珠猶滿眼，煩君爲我一傾囊。"]'),
('635c3daa-45e7-437d-b7d0-2de6b18e75da','舟過道場山下將往遊舟師告以雪塗不可行而止','周紫芝','宋','宋诗','song-poetry','','[]','風蒲飽朝航，霽色急新漲。',132,'全唐诗/poet.song.87000.json','["風蒲飽朝航，霽色急新漲。", "雲山繞平湖，水墨澹屏障。", "夷猶柂初回，突兀山入望。", "何妨傾寸眸，便足了千嶂。", "想像鐘磬音，隱約霄漢上。", "我欲一往遊，遐瞻茲可暢。", "暮雪猶在塗，遺事不得訪。", "人生蠟屐緣，一世能幾兩。", "登山追勝遊，脚力須少壯。", "重來定何時，吾策今可杖。", "老願復爾違，撫事一惆悵。"]'),
('53023f9a-9c85-492d-9838-e6634604c863','老日','周紫芝','宋','宋诗','song-poetry','','[]','老日那容惜，晴光到眼休。',48,'全唐诗/poet.song.87000.json','["老日那容惜，晴光到眼休。", "蠶知今日浴，麥復幾時收。", "黄犢分青草，花鳧趁綠溝。", "誰能更歸得，已是一春留。"]'),
('da5db36a-02ab-43a3-8608-8e0b5d7d7ab7','西湖山下梅花塢行可里許至陳御史園亭','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倦客厭卑栖，白日坐飄忽。',132,'全唐诗/poet.song.87000.json','["倦客厭卑栖，白日坐飄忽。", "呼我同舍郎，緩策扶勃窣。", "緣山得人家，附影蔽深樾。", "湖水一鏡明，梅花千樹發。", "扶疏弄清影，仿彿見羅襪。", "凄迷香霧中，身已在月窟。", "窮探意未已，取徑無詰屈。", "誰家歌舞園，花亂竹復密。", "御史投紱餘，課豎種梨栗。", "吾曹不解事，尚此學操瑟。", "當從漢陰人，抱甕日搰搰。"]'),
('cb107ffd-72c7-4a7f-a2c5-125efc8ef829','寒食前五日作二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','杜鵑新聽曉來聲，暖氣催花一夜成。',32,'全唐诗/poet.song.87000.json','["杜鵑新聽曉來聲，暖氣催花一夜成。", "寒食只今無幾日，故鄉何處不關情。"]'),
('8510138e-2933-45ca-964b-fa8b72007bf3','寒食前五日作二絕  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒食風埃滿客巾，西湖烟雨送愁頻。',32,'全唐诗/poet.song.87000.json','["寒食風埃滿客巾，西湖烟雨送愁頻。", "日高未起鳥呼夢，春晚不歸花笑人。"]'),
('5ad3e5c8-7e89-4907-b558-8478040b82ec','三月二十二日春雨終日','周紫芝','宋','宋诗','song-poetry','','[]','此情誰與問天公，幽事全歸白髮翁。',64,'全唐诗/poet.song.87000.json','["此情誰與問天公，幽事全歸白髮翁。", "袖手尋詩紅燭裏，卷簾聽雨綠陰中。", "杯盤眼見櫻桃熟，時節心驚柳絮空。", "誰爲羈栖到三月，還家猶及舞雩風。"]'),
('36a96ac2-d5ad-42f4-b18a-2f621e75c678','奉酬德莊見和','周紫芝','宋','宋诗','song-poetry','','[]','横飛袞袞見諸公，着眼何由到此翁。',64,'全唐诗/poet.song.87000.json','["横飛袞袞見諸公，着眼何由到此翁。", "胡粤相忘千里外，金蘭投分一言中。", "詩緣漸熟情難洗，老色來煎念已空。", "銷盡客愁知底事，愛君回雪與流風。"]'),
('aaf5089f-1b8a-4f5c-a0e6-4474b4aec650','酌六一泉頗懷昔遊','周紫芝','宋','宋诗','song-poetry','','[]','孤山屹中流，長隄轉湖尾。',120,'全唐诗/poet.song.87000.json','["孤山屹中流，長隄轉湖尾。", "泯然懷昔遊，踴躍尚壯齒。", "道人引清甘，一掬託分似。", "重來固依然，歲月今有幾。", "華堂失雄觀，缺甃久未理。", "誰令走鼃黽，投筆便如鬼。", "龍宮空一炬，狗盜忽四起。", "佳處不負人，環山自湖水。", "並遊適相契，况我二三子。", "少留當何之，再來吾老矣。"]'),
('cf247041-4e77-4c35-aa24-6b219a5fd653','黄文若攜秦别駕侍兒像見過戲題二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','能事空傳王右丞，句如徐庾轉難名。',32,'全唐诗/poet.song.87000.json','["能事空傳王右丞，句如徐庾轉難名。", "明眸正似溪光様，自古無人畫得成。"]'),
('97ff6be7-718f-4528-b6d3-8389c31960bd','黄文若攜秦别駕侍兒像見過戲題二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','謝家林下小梅花，不着紅藍染絳紗。',32,'全唐诗/poet.song.87000.json','["謝家林下小梅花，不着紅藍染絳紗。", "莫笑畫師無國手，玉肌元不受鈆華。"]'),
('e417e1ff-12e8-4710-90ce-201713b5bb1b','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','好箇神仙張志和，平生只是一漁蓑。',32,'全唐诗/poet.song.87000.json','["好箇神仙張志和，平生只是一漁蓑。", "和月醉，棹船歌，樂在江湖可奈何。"]'),
('ce7dcb90-db41-451a-8741-37d1f44296db','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','禁中圖畫訪玄真，晚得歌詞獻紫宸。',32,'全唐诗/poet.song.87000.json','["禁中圖畫訪玄真，晚得歌詞獻紫宸。", "天一笑，物皆春，依舊扁舟釣白蘋。"]'),
('5df845e0-ee19-4b51-ace5-7231832313b3','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其三','周紫芝','宋','宋诗','song-poetry','','[]','解印歸來暫結廬，有時同釣水西魚。',32,'全唐诗/poet.song.87000.json','["解印歸來暫結廬，有時同釣水西魚。", "閑着屐，醉騎驢，分明人在輞川圖。"]'),
('f21eb2cc-6211-4532-b0c7-4c9e3bbda6a1','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','趁梅尋得水邊枝，獨棹漁舟却過谿。',32,'全唐诗/poet.song.87000.json','["趁梅尋得水邊枝，獨棹漁舟却過谿。", "人似玉，醉如泥，閑歌五色線中詩。"]'),
('563aa055-5662-4350-a89a-416ce775bf61','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','人間何物是窮通，終向烟波作釣翁。',32,'全唐诗/poet.song.87000.json','["人間何物是窮通，終向烟波作釣翁。", "江不動，月横空，漫郎船過小回中。"]'),
('e05db643-5280-461d-9b57-87ee4150ad33','羅叔共五色線中得玄真子漁父詞擬其體僕亦擬作六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','花姑溪上鷺鷀灘，辜負漁竿二十年。',32,'全唐诗/poet.song.87000.json','["花姑溪上鷺鷀灘，辜負漁竿二十年。", "無可載，不抛官，攜取全家去不難。"]'),
('5bb3f2fc-ddd0-4819-9c16-869d7b113943','次韻黄文若春日山行過秦德久六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','百金聊作杖頭沽，旋剪春苗薦野蔬。',32,'全唐诗/poet.song.87000.json','["百金聊作杖頭沽，旋剪春苗薦野蔬。", "便可且傾陶令酒，未須真憶季鷹魚。"]'),
('ede17045-56e9-4c8a-9a09-e51bbb8e7815','次韻黄文若春日山行過秦德久六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','眼前風物一番新，江上桃花惱殺人。',32,'全唐诗/poet.song.87000.json','["眼前風物一番新，江上桃花惱殺人。", "可笑草玄窗下客，滿庭吹絮不知春。"]'),
('694a90ef-480a-4af4-a4e5-aeda69b2b3c9','次韻黄文若春日山行過秦德久六首  其三','周紫芝','宋','宋诗','song-poetry','','[]','階前春草喚愁生，屋上鳴鳩報晚晴。',32,'全唐诗/poet.song.87000.json','["階前春草喚愁生，屋上鳴鳩報晚晴。", "忽有好詩來照眼，似逃空谷聽人聲。"]'),
('5e85cbad-7a37-4287-b01d-ce1f22d01c9b','次韻黄文若春日山行過秦德久六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','不作林間曳履行，老來春日總無情。',32,'全唐诗/poet.song.87000.json','["不作林間曳履行，老來春日總無情。", "還驚柳上風催燕，又見花邊雨弄晴。"]'),
('f15fa7e8-1357-4858-86f3-c202eae3a597','次韻黄文若春日山行過秦德久六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','櫻桃花下小窗扉，聞說嬋娟是柳枝。',32,'全唐诗/poet.song.87000.json','["櫻桃花下小窗扉，聞說嬋娟是柳枝。", "茗椀已煩羅袖捧，篆香仍借好風吹。"]'),
('3e44f00d-35c2-479f-9443-8496c97ca864','次韻黄文若春日山行過秦德久六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','鳥啼花發未春闌，日飲無何意自閑。',32,'全唐诗/poet.song.87000.json','["鳥啼花發未春闌，日飲無何意自閑。", "更喚小蠻娛醉客，主人風味似香山。"]'),
('29da7647-1e47-430f-847e-1130843ff949','追和向蘇州罷吳門作','周紫芝','宋','宋诗','song-poetry','','[]','幕北傳烽飛夕埃，廟堂今日要真才。',64,'全唐诗/poet.song.87000.json','["幕北傳烽飛夕埃，廟堂今日要真才。", "肯將身向急流退，要問客從何處來。", "寶墨光翻銀漢落，畫船恩重錦帆開。", "胸中丘壑公元有，便恐鴟夷挽不回。"]'),
('5275e12a-be67-4eca-b8db-238761668b08','追和向蘇州頃在吳門嘗用韋應物作凝香閣舊有白公檜今不復存爲補植之','周紫芝','宋','宋诗','song-poetry','','[]','韋白兩公名欲埃，薌林一出未難才。',64,'全唐诗/poet.song.87000.json','["韋白兩公名欲埃，薌林一出未難才。", "樹從居士池邊種，香入蘇州句裏來。", "陶令北窗應好在，何郎東閣爲誰開。", "二疏歸後今重見，遙想都門張飲迴。"]'),
('aea51bc0-e9fb-4d8b-942a-0850a827ca0d','追和向蘇州舟次京口聞召諸公簡朝中知舊','周紫芝','宋','宋诗','song-poetry','','[]','聖主思清戰騎埃，盡將尺一起群才。',64,'全唐诗/poet.song.87000.json','["聖主思清戰騎埃，盡將尺一起群才。", "匈奴莫向雲中入，尚父今從海上來。", "繡祫不當氈毳用，玉關寧爲犬羊開。", "公冠已掛知何事，猶有忠腸日九迴。"]'),
('f48f750f-1a33-4bad-926f-1df2162dc73c','古風二首别李守  其一','周紫芝','宋','宋诗','song-poetry','','[]','東南富佳郡，此地復名城。',108,'全唐诗/poet.song.87000.json','["東南富佳郡，此地復名城。", "拜策奉温詔，謁帝辭明庭。", "悠悠出金闕，旆旆搖熊旌。", "蘭風藹微和，玉露湑以零。", "征鼙肅郊壘，嘯詠閑齋鈴。", "微生等薜蘿，託根符餘榮。", "誤遭一笑盼，永懷千古情。", "千古不足多，喜遇罕所并。", "白璧勿漫予，按劍徒取憎。"]'),
('90714d21-71cf-4c74-b8aa-c43fcff72cad','古風二首别李守  其二','周紫芝','宋','宋诗','song-poetry','','[]','逸足思長途，勁翮慕遠漢。',96,'全唐诗/poet.song.87000.json','["逸足思長途，勁翮慕遠漢。", "壯志忽蹉跎，功名失華旦。", "孤芳不自惜，靡靡同草蔓。", "饑寒日劬勞，霜雪念衰晏。", "眇焉尚遐征，遄車指芳甸。", "故國念離憂，高軒增老戀。", "會當酬知心，努力加餐飯。", "微勇或可賈，未和南山粲。"]'),
('109c23fc-ba4a-40e3-881d-06b8635e0a62','叔共出近詩百餘篇攜歸燈下讀竟題小詩其後三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','避地兩家三五口，只今那忍記當時。',32,'全唐诗/poet.song.87000.json','["避地兩家三五口，只今那忍記當時。", "誰知臨老相逢日，猶得重看亂後詩。"]'),
('42d8d48e-745c-4c8f-a996-7bc2da164685','叔共出近詩百餘篇攜歸燈下讀竟題小詩其後三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','翠鬟當户山如染，匹練繞簷江自寒。',32,'全唐诗/poet.song.87000.json','["翠鬟當户山如染，匹練繞簷江自寒。", "縱有鵝溪誰寫得，要從無色畫中看。"]'),
('86106d5e-ada2-492d-a195-4b0efd763984','叔共出近詩百餘篇攜歸燈下讀竟題小詩其後三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','東平不復歎塗窮，有姪賢如阮仲容。',32,'全唐诗/poet.song.87000.json','["東平不復歎塗窮，有姪賢如阮仲容。", "淨觀庵中詩作社，水西山下酒分鍾。"]'),
('bc858a11-74ac-4523-9c85-59b8b022ee1d','讀巴東集二首','周紫芝','宋','宋诗','song-poetry','','[]','熟睡能令虜退師，高談聊決廟堂疑。',64,'全唐诗/poet.song.87000.json','["熟睡能令虜退師，高談聊決廟堂疑。", "胡塵洗盡渾無事，却卷波瀾入小詩。", "談笑成盧事亦難，一言能借百年安。", "群姦未死公休恨，但遣枯枝作歲寒。"]'),
('22ad4c88-3ef4-4424-88f4-c26234f7d559','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其一','周紫芝','宋','宋诗','song-poetry','','[]','口角瀾翻二十年，書多却厭腹便便。',32,'全唐诗/poet.song.87000.json','["口角瀾翻二十年，書多却厭腹便便。", "年來抝折枯藤杖，參得跏趺面壁禪。"]'),
('b4a75b35-a362-4b5f-9ae9-320a2883def3','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其二','周紫芝','宋','宋诗','song-poetry','','[]','黑甜有味要須嘗，一枕誰同夜雨床。',32,'全唐诗/poet.song.87000.json','["黑甜有味要須嘗，一枕誰同夜雨床。", "世路風波難著脚，老來當以夢爲鄉。"]'),
('d988bfb8-3dbf-48ad-b663-4f35b497e2e4','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其三','周紫芝','宋','宋诗','song-poetry','','[]','年來孛窣與誰牢記，林下婆娑萬事休。',33,'全唐诗/poet.song.87000.json','["年來孛窣與誰牢記，林下婆娑萬事休。", "草淺沙平谿路穩，漫郎空棹小回舟。"]'),
('26dddc22-b8d4-41e4-8b00-6b501a57b9e7','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其四','周紫芝','宋','宋诗','song-poetry','','[]','夢中棐几得常憑，更有南窗可寄情。',32,'全唐诗/poet.song.87000.json','["夢中棐几得常憑，更有南窗可寄情。", "便是人間好消息，別無勝解可譏評。"]'),
('c6696d4b-dca7-488f-9b47-829ea7247f8a','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其五','周紫芝','宋','宋诗','song-poetry','','[]','平生不識大官餘，小摘時尋雪後蔬。',32,'全唐诗/poet.song.87000.json','["平生不識大官餘，小摘時尋雪後蔬。", "一歲不齋能幾日，北山松韭未宜疏。"]'),
('27d025de-c194-4def-a610-004a9a1c8578','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其六','周紫芝','宋','宋诗','song-poetry','','[]','伎癢撩人不易禁，讀殘書葉喜重臨。',32,'全唐诗/poet.song.87000.json','["伎癢撩人不易禁，讀殘書葉喜重臨。", "牙籤玉軸知多少，浪與兒童較寸陰。"]'),
('b32cc938-4b6f-4989-82e0-6e5113432e24','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其七','周紫芝','宋','宋诗','song-poetry','','[]','妙畫心傳豈學能，是中真樂不容聲。',32,'全唐诗/poet.song.87000.json','["妙畫心傳豈學能，是中真樂不容聲。", "譏評盡入雌黄口，寫得吾心不要名。"]'),
('bebe1274-3e90-42b2-bda2-0715947b034c','次韻韓伯嘉擬陸龜蒙坐眠行倚食學書吟八題  其八','周紫芝','宋','宋诗','song-poetry','','[]','老來無意作悲秋，不奈庾郎知處愁。',32,'全唐诗/poet.song.87000.json','["老來無意作悲秋，不奈庾郎知處愁。", "筆底波瀾何日了，人間風雨幾時休。"]'),
('25fb3759-e3b3-4879-bbd1-269f8d4dfbcd','謁顔魯公祠時新築懷忠堂云','周紫芝','宋','宋诗','song-poetry','','[]','平生高目看兒童，晚喜低頭拜魯公。',64,'全唐诗/poet.song.87000.json','["平生高目看兒童，晚喜低頭拜魯公。", "政恐父師千載後，未輸丞相百年中。", "投諸魑魅知何事，碎得狻猊有底功。", "長遣忠臣泣遺恨，謾營華屋照豐容。"]'),
('d044e522-9f4e-407f-bdc0-1c2c7119a1f0','吳興道中過落石祠廟貌甚嚴榜云唐李英公廟','周紫芝','宋','宋诗','song-poetry','','[]','天厭孤隋失羣醜，鹿走中原死誰手。',176,'全唐诗/poet.song.87000.json','["天厭孤隋失羣醜，鹿走中原死誰手。", "爬搔癢疥不足平，虬髯少年十八九。", "經營四海多腹發，英公扶持真臂肘。", "從來斷國要老成，公獨含糊無可否。", "留得宮中老孽妻，幾覆昭陵一杯酒。", "蚤歲功名塞天破，九廟丘墟只回首。", "狐埋未幾狐掘之，天上浮雲倏蒼狗。", "更憑頑石作靈祠，頗似當年柳州柳。", "不如梁公摩虎鬚，爲言百歲不祔姑。", "提師十萬復誰可，興邦一言還要渠。", "人間萬事本難料，老將未須輕腐儒。"]'),
('8ca8673f-52a2-46e4-a2d2-72d7097f6381','河橋晚思三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','出門猶未夕陽低，倚杖還驚露濕衣。',32,'全唐诗/poet.song.87000.json','["出門猶未夕陽低，倚杖還驚露濕衣。", "等得樹頭鴉定後，會邀林外月同歸。"]'),
('80c6b29e-72ec-4b93-951a-cb9936b7204d','河橋晚思三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雨後津橋飲斷虹，暮林重噪一蟬風。',32,'全唐诗/poet.song.87000.json','["雨後津橋飲斷虹，暮林重噪一蟬風。", "月來烟隴掛玉玦，雲向碧天成峭峰。"]'),
('32c9dae6-919b-4b8f-a124-3e3d584916cc','河橋晚思三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','秋水平堤带雨渾，小橋分港到籬根。',32,'全唐诗/poet.song.87000.json','["秋水平堤带雨渾，小橋分港到籬根。", "晚來幽事亦可喜，忽有漁舟時傍門。"]'),
('f5b58d1e-49ca-4a1f-9755-4359e216ad91','次韻德莊送别  其一','周紫芝','宋','宋诗','song-poetry','','[]','千里辭家復臥疴，賴君一笑肯相過。',64,'全唐诗/poet.song.87000.json','["千里辭家復臥疴，賴君一笑肯相過。", "夢看赤鯉春騰浪，歸見牽牛秋渡河。", "空裏懶能書怪事，酒中自可作無何。", "一竿忍負平生意，重釣花姑溪上波。"]'),
('c33d4465-7fc2-4673-8e34-8118fcb62dcf','次韻德莊送别  其二','周紫芝','宋','宋诗','song-poetry','','[]','烏帽前頭没馬塵，箇中元自不無人。',64,'全唐诗/poet.song.87000.json','["烏帽前頭没馬塵，箇中元自不無人。", "風流公是習主簿，文字我慚陰子春。", "此日定交真有意，一生弔影復誰親。", "相從又失秋來約，已結茅椽着病身。"]'),
('459bc7eb-ace8-45b1-9441-c8aa02d7bd26','題黄縣丞墨牛','周紫芝','宋','宋诗','song-poetry','','[]','一牛飽臥春草綠，一牛下坡引黄犢。',64,'全唐诗/poet.song.87000.json','["一牛飽臥春草綠，一牛下坡引黄犢。", "長安可笑人海中，眼前見此三觳觫。", "詩翁老去饑滿腹，歸把春犁豈非欲。", "人生所願能幾何，百畝良田一牛足。"]'),
('3f959cdf-a532-41df-a21c-5d6d7e93e9d5','鹿苑假寐','周紫芝','宋','宋诗','song-poetry','','[]','掛席月未落，輟棹日將午。',120,'全唐诗/poet.song.87000.json','["掛席月未落，輟棹日將午。", "亟尋墟里烟，盡閱菱芡浦。", "烈日方在舟，騰雲未成雨。", "瀕河得風巖，佛飯過齋鼓。", "龕燈明廣殿，妙炷繞殘縷。", "窈窕幾僧窗，款欠無一語。", "我來兀晝夢，得句瘖不吐。", "欹巾倒烏紗，墮扇横白羽。", "凉襟亦已披，歸杖當復拄。", "爲君趣扁舟，夜雨軋鳴櫓。"]'),
('dd971701-99dd-4118-a363-2edc27b876bf','次韻崔都巡馬上望天目山','周紫芝','宋','宋诗','song-poetry','','[]','雨後青雲萬里開，翠螺新染玉縈迴。',64,'全唐诗/poet.song.87000.json','["雨後青雲萬里開，翠螺新染玉縈迴。", "將軍馬健隨風去，天目山高入眼來。", "稚子能文非好武，君王賦韻不爲才。", "且將横槊新傳句，獨對西風侑酒盃。"]'),
('d87b8611-6d82-4ed8-a3a1-715d34445e88','苕霅舟中戲題','周紫芝','宋','宋诗','song-poetry','','[]','永日扁舟破浪遲，青蘋不動柳垂垂。',32,'全唐诗/poet.song.87000.json','["永日扁舟破浪遲，青蘋不動柳垂垂。", "滿川安得飛來雨，看濕紅裙雪藕絲。"]'),
('63789fd0-1579-4d22-8e01-764d1dff62cc','再賦二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','故國辭家遠，苕溪轉柂深。',48,'全唐诗/poet.song.87000.json','["故國辭家遠，苕溪轉柂深。", "交游千里隔，歲月二毛侵。", "滿意悲煙樹，移時看水禽。", "唯應陸魯望，相見可知心。"]'),
('65ea6e92-c2e1-4115-8463-552e38d70031','再賦二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雲暗千家雨，寒生兩岸秋。',48,'全唐诗/poet.song.87000.json','["雲暗千家雨，寒生兩岸秋。", "水翻波入户，人靚玉明樓。", "山色遮愁眼，荷香滿客舟。", "水晶宮裏夢，還作此生游。"]'),
('8ef4974f-6d3c-4f4a-8195-bcbeadb6391d','船曉','周紫芝','宋','宋诗','song-poetry','','[]','瞑鳥驚飛急，孤舟犯曉行。',48,'全唐诗/poet.song.87000.json','["瞑鳥驚飛急，孤舟犯曉行。", "柂牙侵月白，帆腹受風輕。", "雲破千峰出，秋隨一雨生。", "倚檣誰共語，蓬首看參横。"]'),
('c0475a61-a409-438c-adee-eef0df110104','舟中晚色二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','望處天仍闊，雲邊雨未成。',24,'全唐诗/poet.song.87000.json','["望處天仍闊，雲邊雨未成。", "秋風莫吹散，留作打篷聲。"]'),
('21c94a1a-b3d9-405c-a496-fec45a9965ab','舟中晚色二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','風急雨初過，天高日未曛。',24,'全唐诗/poet.song.87000.json','["風急雨初過，天高日未曛。", "翠鬟堆晚岫，水墨畫秋雲。"]'),
('8a4c9167-3646-4018-beed-1da2271221dc','臨安道中晚晴書所見二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','客路鄉關遠，雲山暮色添。',48,'全唐诗/poet.song.87000.json','["客路鄉關遠，雲山暮色添。", "秋高尚寒薄，雨過却風恬。", "附隴田成陛，傾崖水作簾。", "此行殊不惡，未愧賈胡淹。"]'),
('190294c3-1a6b-42dc-8f98-58d267aec165','臨安道中晚晴書所見二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','何日王摩詰，瀟湘畫短屏。',48,'全唐诗/poet.song.87000.json','["何日王摩詰，瀟湘畫短屏。", "扁舟横遠壑，晚翼在青冥。", "木杪收殘照，雲間得數星。", "吳姫不驚客，拜月下中庭。"]'),
('57cff6e3-5436-4505-a51f-fd57af775d40','西湖寒食','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','落花殘絮憶西園，寒食歸心似紙鳶。',32,'全唐诗/poet.song.87000.json','["落花殘絮憶西園，寒食歸心似紙鳶。", "無復御廊分冷食，又看茅屋禁清烟。"]'),
('f0721dc5-ade6-4833-9c4d-0462a02cebe9','十日不至湖上','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我始跨匹馬，蹭蹬來東吳。',156,'全唐诗/poet.song.87000.json','["我始跨匹馬，蹭蹬來東吳。", "東吳亦何有，政復爲西湖。", "西湖如靜女，婉然真彼姝。", "湘娥結烟鬟，水鏡涵空虚。", "晴光固不惡，雨態亦自殊。", "窈窕一僧窗，煙雲媚朝晡。", "上下數白鳥，飛翻與人娛。", "只今雨鳴葉，便作破跳珠。", "寒窗掛薜蘿，身疑在菰蒲。", "咫尺不得往，况乃千里餘。", "始來梅欲花，旋復春去徂。", "幸茲得少留，駐我西征車。", "尚可具小舟，紅粧醉芙蕖。"]'),
('1d0a62b4-6acd-4f5e-a877-cd653860e9b2','蘇公隄','周紫芝','宋','宋诗','song-poetry','','[]','翰林一去幾經秋，猶有平隄繞碧流。',32,'全唐诗/poet.song.87000.json','["翰林一去幾經秋，猶有平隄繞碧流。", "誰向西州還度曲，此翁零落已山邱。"]'),
('1253f343-7db0-4ecb-9244-366cd26b41b6','次韻關子東筇杖','周紫芝','宋','宋诗','song-poetry','','[]','林下相從政要君，春來花草各欣欣。',64,'全唐诗/poet.song.87000.json','["林下相從政要君，春來花草各欣欣。", "須煩無語木上座，時伴能言鄭廣文。", "徒步飽看山入眼，醉歸應有句凌雲。", "誰知九節仙人杖，解與先生立茂勳。"]'),
('0fb9aa3e-2609-4260-b5a6-2baea79cff63','悶題','周紫芝','宋','宋诗','song-poetry','','[]','命薄官如虱，年多髩似銀。',48,'全唐诗/poet.song.87000.json','["命薄官如虱，年多髩似銀。", "酒醺雖有聖，錢少本無神。", "含笑花欺老，妨眠鳥閙人。", "青山渾可戀，白眼莫相嗔。"]'),
('4f00a31c-c878-4088-86cc-1797a29a5b03','湖隄步游客言此蘇小墓也','周紫芝','宋','宋诗','song-poetry','','[]','野水横分青草陂，誰埋玉樹與瓊枝。',64,'全唐诗/poet.song.87000.json','["野水横分青草陂，誰埋玉樹與瓊枝。", "湖邊山自向人綠，門外柳今何處垂。", "行雨行雲鈞是夢，施朱施粉未相宜。", "一從蕙死蘭枯後，剛道桃花好面皮。"]'),
('fa06cabb-3bcd-40fa-bcf4-41bb2e5d43f5','題淨空泉二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','誰穿巨石貯清泉，不見超公舊講筵。',32,'全唐诗/poet.song.87000.json','["誰穿巨石貯清泉，不見超公舊講筵。", "龍伴白雲歸寶藏，魚隨流水下春田。"]'),
('2407245e-18ca-486f-a936-60e6bd3418b6','題淨空泉二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','欲尋遺事苦無碑，老宿猶傳古律師。',32,'全唐诗/poet.song.87000.json','["欲尋遺事苦無碑，老宿猶傳古律師。", "尚恐蜿蜒在空谷，水清不敢唾方池。"]'),
('6eb1e79b-23c2-4272-a5d1-f4e8caa75a6d','送别王元韻徙居武康','周紫芝','宋','宋诗','song-poetry','','[]','扁舟憶東來，梅冷殊未芳。',96,'全唐诗/poet.song.87000.json','["扁舟憶東來，梅冷殊未芳。", "故人念客寒，滿意傾酒漿。", "坐中東床君，笑語芝蘭香。", "相從忽三月，共飲湖水光。", "花事乃如此，碧草日夜長。", "子歸我當留，語離意難忘。", "似聞小山居，一葦僅可航。", "會尋霅川盟，着屐登上方。"]'),
('ffd5afa3-0195-4778-b2c9-0f6ef26f4cd6','晚雨薄寒枕上作','周紫芝','宋','宋诗','song-poetry','','[]','睡過花時常掩關，老人歡意自應闌。',64,'全唐诗/poet.song.87000.json','["睡過花時常掩關，老人歡意自應闌。", "愁邊可奈雨如許，客裏不禁天尚寒。", "數月鄉音無雁到，一年春事已梅酸。", "夢餘猶憶江頭路，擬喚歸舟下急湍。"]'),
('f42d399f-d017-4e50-8ccb-9d5828a96dbb','奉酬德莊見和一首','周紫芝','宋','宋诗','song-poetry','','[]','老於春事豈相關，只有翻書意未闌。',64,'全唐诗/poet.song.87000.json','["老於春事豈相關，只有翻書意未闌。", "白眼何由常玩世，黑裘元自不遮寒。", "飽聽風雨眠方熟，細說窮愁語更酸。", "日誦離騷三百字，便知新句有驚湍。"]'),
('8112f9f9-2f3c-4465-994a-2bcddb9d9b1c','樓居雜句五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','吳江横絕斷雲間，白鳥歸飛去不還。',32,'全唐诗/poet.song.87000.json','["吳江横絕斷雲間，白鳥歸飛去不還。", "烟樹青連越王國，暮潮聲過海門山。"]'),
('1809078f-6529-43b5-b780-a03d88e66314','樓居雜句五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','湖光山影入樓明，曉色催人夢自驚。',32,'全唐诗/poet.song.87000.json','["湖光山影入樓明，曉色催人夢自驚。", "畫棟去天無一握，青山銜月恰三更。"]'),
('220de9f3-53c5-4cd5-8ba5-6449555a1a00','樓居雜句五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','上方重閣亂山前，噴雪跳珠日夜泉。',32,'全唐诗/poet.song.87000.json','["上方重閣亂山前，噴雪跳珠日夜泉。", "蹔借小樓聽雨睡，更攜官焙與僧煎。"]'),
('44966533-2611-41ef-8171-792ae09ce0c5','樓居雜句五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','五月江南烟雨時，吳儂初喜餉楊梅。',32,'全唐诗/poet.song.87000.json','["五月江南烟雨時，吳儂初喜餉楊梅。", "綠枝紅雨連山暗，應似瀘戎摘荔枝。"]'),
('ae70e3a6-6750-4a1d-90e4-fcbbdb54e782','樓居雜句五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','人間第一東南郡，天上飛來碧峭峰。',32,'全唐诗/poet.song.87000.json','["人間第一東南郡，天上飛來碧峭峰。", "更乞老僧雙不借，爲君穿盡玉玲瓏。"]'),
('1930123d-af02-458a-ad3d-326d50f7bba2','雨中湖上晚歸書所見三絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','菰蒲風裏棹歌遲，屬玉雙飛欲暮時。',32,'全唐诗/poet.song.87000.json','["菰蒲風裏棹歌遲，屬玉雙飛欲暮時。", "荷葉吹香送歸客，片雲催雨濕燕姬。"]'),
('6a452380-4228-4d76-b581-4bf731aed271','雨中湖上晚歸書所見三絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','誰家歌管載凉州，何處跳珠入柂樓。',32,'全唐诗/poet.song.87000.json','["誰家歌管載凉州，何處跳珠入柂樓。", "山雨忽隨雲渡嶺，明眸還與水爭愁。"]'),
('e46da429-b315-4ef2-8baf-deacd0b9c678','雨中湖上晚歸書所見三絕句  其三','周紫芝','宋','宋诗','song-poetry','','[]','風荷憶伴醉顔紅，湖水重來照雪翁。',32,'全唐诗/poet.song.87000.json','["風荷憶伴醉顔紅，湖水重來照雪翁。", "此世相看最長久，只應南北兩高峰。"]'),
('cde74ec9-6121-4f75-87b8-6002f1fba1a1','孤山新作三賢祠','周紫芝','宋','宋诗','song-poetry','','[]','兩公才力盡驊騮，俱得東南第一州。',64,'全唐诗/poet.song.87000.json','["兩公才力盡驊騮，俱得東南第一州。", "易濕青衫江上淚，難禁白髮海邊秋。", "此生名字依然在，晚歲功名亦未酬。", "處士若無當日節，更將何物配風流。"]'),
('dddf284c-a265-44b8-928d-8adfabc84e44','晚至靈峰  其一','周紫芝','宋','宋诗','song-poetry','','[]','綠樹千枝與萬枝，靈峰寺裏看楊梅。',32,'全唐诗/poet.song.87000.json','["綠樹千枝與萬枝，靈峰寺裏看楊梅。", "青山行盡且歸去，紅子熟時應再來。"]'),
('2915b375-d6d3-4863-8eed-db64db5e03c0','晚至靈峰  其二','周紫芝','宋','宋诗','song-poetry','','[]','山前山後僧來浴，兩兩三三松下行。',32,'全唐诗/poet.song.87000.json','["山前山後僧來浴，兩兩三三松下行。", "自是眼邊無俗物，老夫不浴更身輕。"]'),
('6c61b99f-21df-49d7-b91e-24ac3cc1aa0f','五月六日湖上晚歸初見荷二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','藕湖烟水欲沉沙，已着芙渠一兩花。',32,'全唐诗/poet.song.87000.json','["藕湖烟水欲沉沙，已着芙渠一兩花。", "擬借短蓑隨雨去，共誰同把釣魚車。"]'),
('794a8f2f-8085-4056-b52d-f3cff30262bc','五月六日湖上晚歸初見荷二絕  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','毿毿煙柳誰家樹，拍拍西湖盡日風。',32,'全唐诗/poet.song.87000.json','["毿毿煙柳誰家樹，拍拍西湖盡日風。", "和靖宅邊山雨急，蘇公隄下藕花紅。"]'),
('a831cd68-2f38-442c-bd29-0aa3d12c7051','曉起趨郡湖上作','周紫芝','宋','宋诗','song-poetry','','[]','湖色初分宿霧餘，綠蒲深處聽跳魚。',64,'全唐诗/poet.song.87000.json','["湖色初分宿霧餘，綠蒲深處聽跳魚。", "一枝聊作烏棲樹，五曉尚隨人趁虚。", "老矣坐曹真戲事，歸歟懷舊却情疏。", "未開禁鑰聽傳漏，殘夢猶堪付竹輿。"]'),
('d664adb9-2717-430c-8007-d4125f22c771','五月二十二日再葺靜寄','周紫芝','宋','宋诗','song-poetry','','[]','晚將華髮試青衫，靜寄從來是舊銜。',64,'全唐诗/poet.song.87000.json','["晚將華髮試青衫，靜寄從來是舊銜。", "俗子未須憐怨鶴，老夫元不負耕巖。", "晴山有約長相見，惡木妨人要盡芟。", "自笑飄零苦無定，今年來此誦琅函。"]'),
('98cd2047-594e-4683-9dad-83012f3cec2a','初凉','周紫芝','宋','宋诗','song-poetry','','[]','白露初垂葉，輕陰漸着衣。',48,'全唐诗/poet.song.87000.json','["白露初垂葉，輕陰漸着衣。", "幽蟲近床語，黄葉到階飛。", "暮雨村常暗，秋風客未歸。", "短檠還有意，凉滿讀書幃。"]'),
('3713b267-e29c-414e-b591-d856c9a4855c','武林逢邵文伯','周紫芝','宋','宋诗','song-poetry','','[]','念昔與君遊，相過江水傍。',180,'全唐诗/poet.song.87000.json','["念昔與君遊，相過江水傍。", "翩翩俱少年，滿鏡青絲長。", "别來二十載，四海一戰場。", "物色到朋舊，十客八九亡。", "今年好時莭，匹馬不犯疆。", "將軍鏁金甲，萬玉朝明堂。", "長安人海中，袞袞逢此郎。", "驚視久乃識，兩帽俱垂霜。", "撫事念晼晚，含凄各酸傷。", "便當呼醽醁，暖熱澆中腸。", "我笑謂君言，語離且勿忙。", "人生如水鳧，相值不可常。", "况此秋物佳，草木交青黄。", "與君着隻屐，尚可相扶將。", "願言遲明發，歷井升南岡。"]'),
('8d07aec8-2592-4289-b691-56c5b2ad10e4','次韻文伯與余遊孤山','周紫芝','宋','宋诗','song-poetry','','[]','客塵費爬搔，佳士要推挽。',168,'全唐诗/poet.song.87000.json','["客塵費爬搔，佳士要推挽。", "誰與同薄遊，君來慰愁眼。", "並湖得名山，水色淡平遠。", "清泉手可掬，汲綆不畏短。", "何人談醉翁，但取瀹茗椀。", "古幹不受寒，霜露閲歲晚。", "向来後庭花，想像空婉娈。", "堂堂兩使君，摹晝暗丹粉。", "名莭冠今古，風流未渠泯。", "處士一癯儒，萬像共偃蹇。", "珠玉儼在前，未肯作寒窘。", "勝遊那可既，客意殊未滿。", "更當窮兩高，豈復悔重趼。", "果腹尚可期，嘗鼎安一臠。"]'),
('55f8768b-61a3-41a8-88c2-4dc816d7af7d','秋夜聞雨','周紫芝','宋','宋诗','song-poetry','','[]','堂空自生秋，凉簟已無暑。',48,'全唐诗/poet.song.87000.json','["堂空自生秋，凉簟已無暑。", "齒蟲含微酸，唧唧相對語。", "天公知客意，夜寂誰與處。", "慎勿遣西風，吹斷芭蕉雨。"]'),
('ad6afd41-2d6e-4e0c-850a-d3bc7beb9873','酌龍井泉書聰師房二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','十里泉聲咽斷巖，繡衣玄袞閉朱龕。',32,'全唐诗/poet.song.87000.json','["十里泉聲咽斷巖，繡衣玄袞閉朱龕。", "老翁不要千山雨，只乞龍君一酌甘。"]'),
('01640a03-7826-434e-9b64-ea4823c2b348','酌龍井泉書聰師房二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','八十霜髭不出門，老師猶是辯才孫。',32,'全唐诗/poet.song.87000.json','["八十霜髭不出門，老師猶是辯才孫。", "高人已復如雲散，舊事那堪與客論。"]'),
('1badc8f2-a35e-47bc-8ee0-fe38c9275ce8','太學落成二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','偃革逢華旦，三雍識漢儀。',48,'全唐诗/poet.song.87000.json','["偃革逢華旦，三雍識漢儀。", "明倫先太學，首善自京師。", "聖主脩文日，諸生望幸時。", "宸奎在輪奐，萬目仰宏規。"]'),
('16529dc2-6a96-410b-97e3-299a5149a630','太學落成二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','當宁敷文德，賢關喜氣多。',48,'全唐诗/poet.song.87000.json','["當宁敷文德，賢關喜氣多。", "横經將正坐，講藝忽投戈。", "雲擁橋門路，風搖辟水波。", "小臣歌聖化，無地獻菁莪。"]'),
('dc01a7b6-5dc8-43bf-a1b4-8904974fcc96','秋夕臥病效唐人作語  其一','周紫芝','宋','宋诗','song-poetry','','[]','畫閣蘭膏欲盡初，小窗留住玉蟾蜍。',32,'全唐诗/poet.song.87000.json','["畫閣蘭膏欲盡初，小窗留住玉蟾蜍。", "欲知此地愁多少，一夜秋聲入井梧。"]'),
('6aa80bd0-5bbb-4876-9254-b0d403a7c118','秋夕臥病效唐人作語  其二','周紫芝','宋','宋诗','song-poetry','','[]','此夜秋懷誰得知，幽蟲相語替人悲。',32,'全唐诗/poet.song.87000.json','["此夜秋懷誰得知，幽蟲相語替人悲。", "自從啼破黄昏後，直到寒窗無月時。"]'),
('0e064e5f-76a5-47cc-9dad-1298de3fb187','西谿道人全一堂','周紫芝','宋','宋诗','song-poetry','','[]','道人不愛葛藤禪，參得維摩妙法門。',64,'全唐诗/poet.song.87000.json','["道人不愛葛藤禪，參得維摩妙法門。", "頗怪後三猶有說，要從全一便歸根。", "昭文琴在何須鼓，惠子書多亦費言。", "聞道山中少來客，爐香清坐與誰論。"]'),
('8f761a50-6837-4e3b-a73c-74fb031f6f8d','次韻季長感事','周紫芝','宋','宋诗','song-poetry','','[]','久將華髮寄林泉，尺一呼來近日邊。',64,'全唐诗/poet.song.87000.json','["久將華髮寄林泉，尺一呼來近日邊。", "身退已甘無事老，眼明重見太平年。", "鼎湖龍去心雖在，長樂鍾鳴喜欲顛。", "解道貞元朝士少，劉郎定自有新篇。"]'),
('5f3dab68-a225-4e06-ae42-3a1302ed9beb','種罌粟','周紫芝','宋','宋诗','song-poetry','','[]','牆根有地一弓許，人言可種數十竹。',176,'全唐诗/poet.song.87000.json','["牆根有地一弓許，人言可種數十竹。", "翁來只作三年留，僅比浮屠桑下宿。", "竹成須待五六年，我已歸鄉卜新築。", "園夫笑謂主人言，不如鋤苗種罌粟。", "二月春風上翠莖，三月輕紅照深綠。", "嫣花落盡罌不空，碎粒圓時粟初熟。", "乳膏自入崖蜜甜，滿貯醍醐飲僧粥。", "與其種竹供後人，孰若栽花資老腹。", "人間作計真眼前，萬事皆爾真可憐。", "十年種木尚不肯，百年種德知何緣。", "倚鋤自顧頗羞澀，病眼對花空惘然。"]'),
('c5b36882-d59a-4a1c-adba-da4ac2b44700','周秀實陳庭藻攜酒見過徜徉湖山間甚款明日秀實有詩乃次韻','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','少年懷二妙，一日如三秋。',168,'全唐诗/poet.song.87000.json','["少年懷二妙，一日如三秋。", "豈料京洛間，歲暮方從游。", "空疏坐晚繆，清楚知前脩。", "周郎古名士，功以一戰收。", "太丘亦賢者，盛德令人羞。", "周旋奉談笑，領略開羈囚。", "有如我輩人，夫豈公等儔。", "窈窕尋遠壑，共賦臨清流。", "青山儻在眼，白髮從滿頭。", "西湖如西子，好句豈易酬。", "不敢妄作語，恐有不下鷗。", "微君妙篇章，何以寫我憂。", "人生每如此，萬户不足侯。", "斯盟儻未寒，小艇尚可浮。"]'),
('4bdf5aa7-c057-478b-a70c-f481a2c17d71','送喬民瞻赴官閩中','周紫芝','宋','宋诗','song-poetry','','[]','我昔游梁走千里，回望江南隔江水。',176,'全唐诗/poet.song.87000.json','["我昔游梁走千里，回望江南隔江水。", "是時公作桐汭官，不復東來問行李。", "人言左史有重客，玉面青衫氣豪偉。", "酒催紅蠟詩欲成，月墮秋江客方起。", "我從京洛塵中來，哦君新篇眼如洗。", "濺血驚魂二十年，長夢清樽奉簪履。", "相逢吳會不相識，昔年强健今如此。", "如公自是臺閣人，老困一官何乃爾。", "只今尚作入幕賓，無事不令公怒喜。", "丈夫要當列鼎食，何止忍饑分斗米。", "且須拄頰望閩山，飽看麥秋丹荔子。"]'),
('00577912-67d8-4530-9f27-0a208ef6e160','送關康子將還青陽治舊田','周紫芝','宋','宋诗','song-poetry','','[]','關郎人物妙人間，莫作雲長一様看。',64,'全唐诗/poet.song.87000.json','["關郎人物妙人間，莫作雲長一様看。", "不到青雲知有命，頻遭白眼坐無官。", "紉蘭秋浦應須爾，索米長安政恐難。", "我欲買田猶未可，但令歸夢逐征鞍。"]'),
('17a18414-625e-4376-be3b-7e2282a833ea','書杭僧法惠事後見邊郎中觀音感應記','周紫芝','宋','宋诗','song-poetry','','[]','眼中鐵彈不辭枯，眢井重波事亦殊。',32,'全唐诗/poet.song.87000.json','["眼中鐵彈不辭枯，眢井重波事亦殊。", "不用三三前說法，要須六六後還珠。"]'),
('e2b4c126-b1e7-452e-846f-4998772afd89','次韻葉兵部九日不出十日登北高峰','周紫芝','宋','宋诗','song-poetry','','[]','登臨一笑與誰同，此事人間未易逢。',64,'全唐诗/poet.song.87000.json','["登臨一笑與誰同，此事人間未易逢。", "莫恨清樽負重九，且看黄菊笑西風。", "江連碧海潮初上，山近丹霄路欲通。", "向晚歸來得新句，便知雲夢落胸中。"]'),
('206a024f-2deb-43f4-9d21-f4c0fe819ac6','頃歲盗起徽嚴間兵既臨城部使者而下皆棄官以走别乘强幼安攝郡事解衣高臥而賊不至城遂以全僕嘗作送行詩以書其事後二十一年歲癸亥幼安始得州相遇于錢塘幼安猶能誦鄙詩而余漫不復省矣手錄見遺讀之惘然爲題三絕其後  其一','周紫芝','宋','宋诗','song-poetry','','[]','當年玉食軫深憂，兩月東南棄八州。',32,'全唐诗/poet.song.87000.json','["當年玉食軫深憂，兩月東南棄八州。", "只有孤城强别駕，醉中看雪倚江樓。"]'),
('6bc6c30b-2e3f-4e6d-a911-e643d510dc8b','頃歲盗起徽嚴間兵既臨城部使者而下皆棄官以走别乘强幼安攝郡事解衣高臥而賊不至城遂以全僕嘗作送行詩以書其事後二十一年歲癸亥幼安始得州相遇于錢塘幼安猶能誦鄙詩而余漫不復省矣手錄見遺讀之惘然爲題三絕其後  其二','周紫芝','宋','宋诗','song-poetry','','[]','使君功大苦難酬，埋没孤忠二十秋。',32,'全唐诗/poet.song.87000.json','["使君功大苦難酬，埋没孤忠二十秋。", "便擁一麾知未稱，伯郎猶解得凉州。"]'),
('5fce8979-0a2a-4366-9b8b-4ffed43c98c5','頃歲盗起徽嚴間兵既臨城部使者而下皆棄官以走别乘强幼安攝郡事解衣高臥而賊不至城遂以全僕嘗作送行詩以書其事後二十一年歲癸亥幼安始得州相遇于錢塘幼安猶能誦鄙詩而余漫不復省矣手錄見遺讀之惘然爲題三絕其後  其三','周紫芝','宋','宋诗','song-poetry','','[]','江上孤城欲破時，閉門高臥復誰知。',32,'全唐诗/poet.song.87000.json','["江上孤城欲破時，閉門高臥復誰知。", "我無文字銘金石，安用煩君寫惡詩。"]'),
('e88ae8e1-3c01-4228-b412-c5b12ed922ba','張鼇詩','周紫芝','宋','宋诗','song-poetry','','[]','曹瞞舉漢鼎，一目窺九州。',156,'全唐诗/poet.song.87000.json','["曹瞞舉漢鼎，一目窺九州。", "凌轢欺孤兒，大蒙口舌羞。", "左慈有道者，何爲與之遊。", "堂堂清獻公，盛德豈操儔。", "鼇乃元放徒，爲公亦少留。", "了知高世士，至意俱難求。", "先生兩琴鶴，清節貫白頭。", "雅宜鴻寶書，取火遽自投。", "公今騎箕尾，笑談閱千秋。", "椿年亦細事，蟻夢輕封侯。", "强侯公自出，矯矯亦此流。", "作詩紀異事，誓將踵前脩。", "愧乏大手筆，爲公著嘉猷。"]'),
('9680f55f-23f5-41d0-a2f5-00397a0632aa','去年聞載揚在武林及余至而載揚病已久逮其歸則逝矣乃追用往時九日詩韻以悼其亡','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','與君一别幾經秋，忽作脩文地下游。',64,'全唐诗/poet.song.87000.json','["與君一别幾經秋，忽作脩文地下游。", "詩憶向來雲態度，人今何在柳風流。", "西湖烟月生前恨，客路風霜晚歲愁。", "勝日交流半零落，數行老泪倩誰收。"]'),
('3552caa7-60dc-4d59-afbd-716926eb5e7a','次韻德莊惠南城紙衾且示妙句','周紫芝','宋','宋诗','song-poetry','','[]','范公古遺直，富貴不自娛。',168,'全唐诗/poet.song.87000.json','["范公古遺直，富貴不自娛。", "平生一布衾，歲晚眠粗疏。", "至今鑱新銘，尚得司馬書。", "此老抱剛節，豈與公孫俱。", "乃知枯槁士，白单良復須。", "衰年忍風露，蹭蹬來東吳。", "感君借餘温，此意知何如。", "青氈寄幽夢，蕙帳羞吾廬。", "得此林下具，爛錦不願餘。", "况乃粲佳句，薄袖翻明珠。", "恨我無蒼珉，爲君載龜趺。", "願與冰雪姿，臥起同卷舒。", "荆土作翠被，此俑無乃愚。", "問言擁六尺，豈不賢一襦。"]'),
('77f36308-688f-435b-b749-706fface8ddc','十月二十日晨起見枇杷花','周紫芝','宋','宋诗','song-poetry','','[]','枝頭紅日退霜華，矮樹低牆密護遮。',32,'全唐诗/poet.song.87000.json','["枝頭紅日退霜華，矮樹低牆密護遮。", "黄菊已殘秋後朵，枇杷又放隔年花。"]'),
('5c39fe55-ac83-4aed-86e6-4072dda21b68','夜宿淨慈明日當宿齋宮','周紫芝','宋','宋诗','song-poetry','','[]','上方枝策記當年，仿彿天宮五日間。',64,'全唐诗/poet.song.87000.json','["上方枝策記當年，仿彿天宮五日間。", "老去新添唯白髮，重來好在只青山。", "已憐雪意催寒急，更遣泉聲喚夢還。", "明日郊宮禋社稷，此生猶得綴朝班。"]'),
('39481bcf-b98e-4642-990e-00fb07fef6a2','齋宮夜雨明日大雪','周紫芝','宋','宋诗','song-poetry','','[]','郊祭嚴祠事，齋宮肅夜寒。',48,'全唐诗/poet.song.87000.json','["郊祭嚴祠事，齋宮肅夜寒。", "鸞刀催宰急，庭燎及晨難。", "雨濕牛羊俎，烟埋幣帛壇。", "南山忽清曉，萬玉已巑岏。"]'),
('b24f3382-4f87-4684-ae6f-8cdebeb0ed10','聞耘老猶在霅川','周紫芝','宋','宋诗','song-poetry','','[]','湖上雖相見，重來失後期。',48,'全唐诗/poet.song.87000.json','["湖上雖相見，重來失後期。", "風塵爲客久，舟楫送歸遲。", "雁遠無消息，梅殘惱别離。", "何時酌君酒，爛漫說新詩。"]'),
('ea2c19c6-3d6f-4501-9203-10f245031ced','十一月十一日夜步行中庭月色明甚作詩三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','冰輪漸出海西頭，身在三吳近海州。',32,'全唐诗/poet.song.87000.json','["冰輪漸出海西頭，身在三吳近海州。", "賴有梅花管羈客，細分疏影上駞裘。"]'),
('be5a9312-74fc-4b4d-b4ff-73a6585645b2','十一月十一日夜步行中庭月色明甚作詩三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','香風嫋嫋月娟娟，月滿中庭夜悄然。',32,'全唐诗/poet.song.87000.json','["香風嫋嫋月娟娟，月滿中庭夜悄然。", "只恐大羅天上有，人間今夕是何年。"]'),
('3152fc5b-ee2f-40ae-b8c1-28a1a0a42b6a','十一月十一日夜步行中庭月色明甚作詩三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','少年邀月伴清樽，老去空餘滿袖塵。',32,'全唐诗/poet.song.87000.json','["少年邀月伴清樽，老去空餘滿袖塵。", "多謝蟾光深有意，尚來同我作三人。"]'),
('429bbda4-eafa-48b9-a36d-c5c12e0baccd','二十一日雪中歸資國','周紫芝','宋','宋诗','song-poetry','','[]','出門天意已垂垂，湖上回鞭雪滿衣。',64,'全唐诗/poet.song.87000.json','["出門天意已垂垂，湖上回鞭雪滿衣。", "人在水晶宮裏住，馬從銀色界中歸。", "樹頭雲凍依然在，湖面鷗寒斷不飛。", "今夜燈前有殘榼，擁爐深閉一篷扉。"]'),
('a65736e8-44ba-45a1-8d61-879f90e0dfac','蠟梅大有生意','周紫芝','宋','宋诗','song-poetry','','[]','幽芳念初分，厚地凍始裂。',144,'全唐诗/poet.song.87000.json','["幽芳念初分，厚地凍始裂。", "耐寒憐孤根，忍苦度尺雪。", "誰持萬金良，起死醫寸蘖。", "伶俜初回姿，荏苒似看葉。", "灌木猶未成，已與凢草别。", "平生冰玉交，勝韻頗奇絕。", "微風折輕黄，香霧濕寒月。", "棐几著冰壺，餘芬散清樾。", "只今滿眼花，想像疑可折。", "感君分似意，老味倍欣悅。", "添我小窗春，芳意未衰歇。", "盛德不可忘，封殖寧敢闕。"]'),
('c07fe9f7-84d9-4fe6-aa18-ab636a11e084','石佛道中隔水梅花滿山','周紫芝','宋','宋诗','song-poetry','','[]','平明跨羸驂，遙遵石頭路。',120,'全唐诗/poet.song.87000.json','["平明跨羸驂，遙遵石頭路。", "循山一谿横，隔水得幽處。", "樹疑虬龍驤，石作蒼虎踞。", "雲庵有遺屋，突兀在煙樹。", "方壺豈不佳，弱水無船渡。", "空餘惱幽香，梅花滿春嶼。", "心知姑射仙，茲焉飲風露。", "水自平湖分，香從一山度。", "風姿不自持，照影各矜顧。", "安得從之遊，徘徊著雙屨。"]'),
('dfeea351-e419-4941-b365-75533168b162','書東窗二首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','枕上青山翠撲衣，西湖郡更似西施。',32,'全唐诗/poet.song.87000.json','["枕上青山翠撲衣，西湖郡更似西施。", "苦無能事王摩詰，領略煙鬟却要詩。"]'),
('d9e07bf3-a855-4165-95a3-975c15a99e7c','書東窗二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','湖上梅花春意回，水光山影入銜杯。',32,'全唐诗/poet.song.87000.json','["湖上梅花春意回，水光山影入銜杯。", "無人許我分幽事，故遣雙飛屬玉來。"]'),
('ad4c6876-5014-4c6d-9125-7483d8592c96','次韻强幼安歲晚感事','周紫芝','宋','宋诗','song-poetry','','[]','寒日催殘歲，新詩得夜光。',48,'全唐诗/poet.song.87000.json','["寒日催殘歲，新詩得夜光。", "雪猶隨處有，梅亦爲春芳。", "愁鬢何從白，流年有底忙。", "官閑應放臘，燕寢自凝香。"]'),
('8bce06a1-bfde-4bd9-92b0-92a9b07afef7','歲晚雜題四首  其一','周紫芝','宋','宋诗','song-poetry','','[]','安穩三冬計，棲遲一舍寛。',48,'全唐诗/poet.song.87000.json','["安穩三冬計，棲遲一舍寛。", "卷簾唯水近，倚杖得山看。", "老罷人誰數，天寒歲又闌。", "自無稽古力，未可怨儒冠。"]'),
('d7ff499f-d942-482f-a27f-8eb1c8a54485','歲晚雜題四首  其二','周紫芝','宋','宋诗','song-poetry','','[]','草色無人地，梅花近臘天。',48,'全唐诗/poet.song.87000.json','["草色無人地，梅花近臘天。", "擬飛猶未雪，將盡欲新年。", "漫與空成恨，無求合信緣。", "平生爲晚計，老去更茫然。"]'),
('4f8f061b-861f-4628-b645-b714d432ceb6','歲晚雜題四首  其三','周紫芝','宋','宋诗','song-poetry','','[]','倚杖千山裏，窮年一水濱。',48,'全唐诗/poet.song.87000.json','["倚杖千山裏，窮年一水濱。", "有官羞隱吏，無句作詩人。", "雨送燈前夢，儺催臘後春。", "孤山林處士，笑我是比鄰。"]'),
('db0a8ad8-0ab1-4101-abe7-26c09271b538','歲晚雜題四首  其四','周紫芝','宋','宋诗','song-poetry','','[]','老病時攜客，斜陽更上樓。',48,'全唐诗/poet.song.87000.json','["老病時攜客，斜陽更上樓。", "山寒猶有雪，湖晚最宜鷗。", "詩可書幽事，兒能伴薄游。", "人生每如此，吾意復何憂。"]'),
('f8574393-3c38-42d3-9837-71843fe1d941','次韻幼安寺丞感舊見示','周紫芝','宋','宋诗','song-poetry','','[]','當時長嘯敵先摧，不費官軍一炬灰。',64,'全唐诗/poet.song.87000.json','["當時長嘯敵先摧，不費官軍一炬灰。", "黠虜自驚風鳥散，使君方看玉山頽。", "攖城捍賊今亡矣，抗疏論功有是哉。", "相見可堪談舊事，爲公搔首一徘徊。"]'),
('0ae6f589-4a17-4b5e-8f21-38deac98d108','甲子立春口號四首  其一','周紫芝','宋','宋诗','song-poetry','','[]','梅花消息未闌珊，春入千門笑語喧。',32,'全唐诗/poet.song.87000.json','["梅花消息未闌珊，春入千門笑語喧。", "人道上元新甲子，從頭却數太平年。"]'),
('61fe6e1c-6d77-443f-822d-aebea5cf66a9','甲子立春口號四首  其二','周紫芝','宋','宋诗','song-poetry','','[]','春來玉燭又初調，盡喜官儀是漢朝。',32,'全唐诗/poet.song.87000.json','["春來玉燭又初調，盡喜官儀是漢朝。", "御道雪晴方試輦，彤庭日暖漸聞韶。"]'),
('26eb2e62-2b4d-4919-861d-57ec73e3d439','甲子立春口號四首  其三','周紫芝','宋','宋诗','song-poetry','','[]','力爭和議衆初疑，事在君王子母知。',32,'全唐诗/poet.song.87000.json','["力爭和議衆初疑，事在君王子母知。", "舊日塞垣啼鳥處，如今長樂曉鐘時。"]'),
('c2bf404b-cd95-4645-8ab2-e446ba2fca45','甲子立春口號四首  其四','周紫芝','宋','宋诗','song-poetry','','[]','晴日初生禁籞春，苑花宮樹一番新。',32,'全唐诗/poet.song.87000.json','["晴日初生禁籞春，苑花宮樹一番新。", "君王勤儉無行樂，只作銀鈎賜近臣。"]'),
('d7707f3a-c4ca-42c4-afa1-4b8372d50151','元夕前三日書事  其一','周紫芝','宋','宋诗','song-poetry','','[]','舊歲冬餘雪，今年雨復晴。',48,'全唐诗/poet.song.87000.json','["舊歲冬餘雪，今年雨復晴。", "奉常新奏樂，蕃使近朝正。", "燈火鼇山路，風光鳯輦城。", "須煩天一笑，四海盡無兵。"]'),
('4234d005-0c32-494d-8020-9419f0ef88cf','元夕前三日書事  其二','周紫芝','宋','宋诗','song-poetry','','[]','落日滄江上，潮回水自平。',48,'全唐诗/poet.song.87000.json','["落日滄江上，潮回水自平。", "雲連子胥廟，山接闔閭城。", "海岳朝吳會，衣冠奉帝京。", "端門舊燈火，還向此時明。"]'),
('99849669-ee60-4372-aedf-ba22bc59e661','飯餘過總持庵','周紫芝','宋','宋诗','song-poetry','','[]','飽飯度永日，問鄰從小園。',48,'全唐诗/poet.song.87000.json','["飽飯度永日，問鄰從小園。", "閑攜居士杖，来扣總持門。", "花木無人見，文書聽客翻。", "更將方外事，細爲老夫論。"]'),
('a3464b40-c191-4057-aefc-18c81c48aa1e','德莊别後以詩見寄再游錢塘始見之次韻奉答且以叙將别之意','周紫芝','宋','宋诗','song-poetry','','[]','分作經年别，還成一笑同。',48,'全唐诗/poet.song.87000.json','["分作經年别，還成一笑同。", "看君鬚點漆，羞我鬢吹蓬。", "共醉寧非夢，緣詩各坐窮。", "相逢又驚散，往往似征鴻。"]'),
('64a4d9ad-5cb5-4d2e-8e79-27204f514079','二月二十三日薄雪','周紫芝','宋','宋诗','song-poetry','','[]','湖上春風結暮陰，亂雲堆雪晚來深。',64,'全唐诗/poet.song.87000.json','["湖上春風結暮陰，亂雲堆雪晚來深。", "便隨柳絮飛將去，誰管桃花冷不禁。", "自苦多愁成客恨，不關難測是天心。", "乘除妙理誰能會，明日朝暾忽滿林。"]'),
('4924d547-c935-4da6-8c18-ed1cfb892601','次韻子東春雪','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春光早已到千林，尚有餘寒壓曉衾。',64,'全唐诗/poet.song.87000.json','["春光早已到千林，尚有餘寒壓曉衾。", "解作飛花朝蔌蔌，絕勝疏雨曉涔涔。", "無田亦有三登意，是瑞何妨一尺深。", "雪裏故人誰過我，西湖巖壑似山陰。"]'),
('48a3322a-d893-4eb7-97dd-16dafe34b13b','湖上戲題','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一湖春水綠漪漪，臥水桃花紅滿枝。',64,'全唐诗/poet.song.87000.json','["一湖春水綠漪漪，臥水桃花紅滿枝。", "去住雲情渾不定，陰晴天色故相欺。", "風前柳作小垂手，雨後山成雙畫眉。", "何必娉娉仍嫋嫋，西湖應便是西施。"]'),
('1f15fcc5-eb08-4749-9857-b7b77a5cd626','後二日又題一首','周紫芝','宋','宋诗','song-poetry','','[]','家在東灣古渡頭，柴扉草閣枕寒流。',64,'全唐诗/poet.song.87000.json','["家在東灣古渡頭，柴扉草閣枕寒流。", "無人擬彈能言鴨，有眼那驚不下鷗。", "月裏踏歌何處社，樽中載酒幾家遊。", "溪南溪北村村水，春雨春風日日愁。"]'),
('36f87838-6141-4f99-81a7-5e669b427c4c','後五日又題一首','周紫芝','宋','宋诗','song-poetry','','[]','幾日春風大放顛，晚來寒日露晴天。',64,'全唐诗/poet.song.87000.json','["幾日春風大放顛，晚來寒日露晴天。", "浪紋隨棹湖如鏡，日脚翻鴉月似弦。", "便可飽看花入眼，不應直待柳吹綿。", "庾郎分得愁千斛，肯與青絲作少年。"]'),
('651103a0-f1e7-4104-9b7c-a57ff18d91ad','湖居無事日課小詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','春湖潮滿入青天，浪拍東風打釣船。',32,'全唐诗/poet.song.87000.json','["春湖潮滿入青天，浪拍東風打釣船。", "人在空濛飛絮裏，鳥啼紅白亂花前。"]'),
('15583886-3671-45cb-a70c-220a326f938b','湖居無事日課小詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','天上陰晴不可猜，兩番雲黑又雲開。',32,'全唐诗/poet.song.87000.json','["天上陰晴不可猜，兩番雲黑又雲開。", "鷺從落日山邊去，魚趁晚湖潮裏來。"]'),
('f8a12072-d36a-4145-a5ff-ada05d93b700','湖居無事日課小詩  其三','周紫芝','宋','宋诗','song-poetry','','[]','茶了詩窗飯後杯，兒書未熟急須催。',32,'全唐诗/poet.song.87000.json','["茶了詩窗飯後杯，兒書未熟急須催。", "鳥於花外喚客出，山自眼前將句來。"]'),
('30d9a8d8-6aba-4573-977d-774cd238f84d','湖居無事日課小詩  其四','周紫芝','宋','宋诗','song-poetry','','[]','老向華胥占一窗，無心更夢小雲郎。',32,'全唐诗/poet.song.87000.json','["老向華胥占一窗，無心更夢小雲郎。", "城居可似湖居好，詩味頗隨茶味長。"]'),
('62723554-6d63-4254-bb16-4fe61935c0cb','湖居無事日課小詩  其五','周紫芝','宋','宋诗','song-poetry','','[]','花枝滿樹雨添肥，晴色十分春又歸。',32,'全唐诗/poet.song.87000.json','["花枝滿樹雨添肥，晴色十分春又歸。", "一生萬事無不爾，行年六十盡成非。"]'),
('25520908-07a5-43a6-8864-853b338d8075','湖居無事日課小詩  其六','周紫芝','宋','宋诗','song-poetry','','[]','多情白鳥去還來，無事風扉閉復開。',32,'全唐诗/poet.song.87000.json','["多情白鳥去還來，無事風扉閉復開。", "山下一帆衝雨過，水邊雙燕得泥回。"]'),
('6b20c80b-c48e-40a8-bab9-37380ad94416','湖居無事日課小詩  其七','周紫芝','宋','宋诗','song-poetry','','[]','海內名流詩有宗，時傳佳句落閑中。',32,'全唐诗/poet.song.87000.json','["海內名流詩有宗，時傳佳句落閑中。", "不道建安六七子，可是近時三數公。"]'),
('76e8d3d1-dd9d-4e68-b2e8-18668c21759e','次韻同季夜宿松園兼呈清照師','周紫芝','宋','宋诗','song-poetry','','[]','鶴骨松園老，霜髯八十春。',48,'全唐诗/poet.song.87000.json','["鶴骨松園老，霜髯八十春。", "相逢看日夕，留客賦詩新。", "鬼亦來聽法，誰應可作鄰。", "折腰營斗粟，寧不愧斯人。"]'),
('92a5fba6-c0bd-493c-8ed0-9d152ae70e5d','强幼安用余與曾同季唱酬韻作二章見寄謹用韻爲謝  其一','周紫芝','宋','宋诗','song-poetry','','[]','江國從游地，花今幾度春。',48,'全唐诗/poet.song.87000.json','["江國從游地，花今幾度春。", "老唯羈客在，情獨使君新。", "未敢論傾盖，應須托善鄰。", "如公真盛德，舉世更何人。"]'),
('3f7e36c2-5fae-4558-9ec6-e6b797ae7bad','强幼安用余與曾同季唱酬韻作二章見寄謹用韻爲謝  其二','周紫芝','宋','宋诗','song-poetry','','[]','花落青墩寺，誰從作好春。',48,'全唐诗/poet.song.87000.json','["花落青墩寺，誰從作好春。", "錦囊題句近，舊旆得州新。", "老手摧强敵，餘風睦四鄰。", "他年數循吏，神爵有斯人。"]'),
('e3d1b86c-bf7d-46f4-84da-f65d704fe0ac','寄李司農三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','東閣當年夜，華燈照别樽。',48,'全唐诗/poet.song.87000.json','["東閣當年夜，華燈照别樽。", "斷碑思雁塔，佳客愧龍門。", "豈料三吳路，相逢一水村。", "只今懸望眼，猶欲黯離魂。"]'),
('cf28bc01-2f2f-4ebc-88e0-bbcbb210de5e','寄李司農三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','徽水定何處，謫官今幾時。',48,'全唐诗/poet.song.87000.json','["徽水定何處，謫官今幾時。", "長沙應有賦，南磵可無詩。", "柳絮催春遠，梅花寄客遲。", "誰憐憶公久，頭白少相知。"]'),
('545feb77-b56b-4d19-b60f-452c6be1ae56','寄李司農三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','謝朓南齊守，司農古漢官。',48,'全唐诗/poet.song.87000.json','["謝朓南齊守，司農古漢官。", "杯今與誰把，山亦要公看。", "細札頒何日，離騷讀又殘。", "侍郎兄弟在，往往上金鑾。"]'),
('a56a4905-ebf4-4fec-873f-673c6c4303e9','客舍春寒','周紫芝','宋','宋诗','song-poetry','','[]','毎日東風吹暗塵，小池幽樹不成春。',64,'全唐诗/poet.song.87000.json','["毎日東風吹暗塵，小池幽樹不成春。", "妨他燕子關何事，折盡梅花最惱人。", "愁裏了知身是幻，老來惟與睡相親。", "去年湖水渾依舊，欲買扁舟釣白蘋。"]'),
('0d4a3954-b9c4-4618-8b7e-3ecef8466116','洗馬行和關子東韻','周紫芝','宋','宋诗','song-poetry','','[]','憶昔四海多甲兵，令嚴細柳將軍營。',192,'全唐诗/poet.song.87000.json','["憶昔四海多甲兵，令嚴細柳將軍營。", "鐵衣健卒持滿立，黑頭壯士從軍行。", "眼前千馬復萬馬，寸土不耕犁與騂。", "自從虎皮蒙劍戟，此馬不聞鼙鼓驚。", "只今盡浴長安水，七十萬匹俱長鳴。", "風騣霧鬛久不試，日饜官粟無斗升。", "廟堂伊吕自有策，不與韓白齊功名。", "圉人但喜馬肥健，野老安知無戰爭。", "有君如此豈不樂，俟河幾時今得清。", "不須天育驃騎種，雲霧晦冥方降精。", "我欲刻石上浯水，白頭弄筆羞書生。", "不聞鐵騎響鳴鏑，但聽玉簫吹九成。"]'),
('6bd19849-bc0a-4708-a430-e59ebd0292c5','讀楚詞三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','借令無策拒强秦，何至甘心受虎吞。',32,'全唐诗/poet.song.87000.json','["借令無策拒强秦，何至甘心受虎吞。", "楚國已墟三十載，區區猶念爾東門。"]'),
('08dc5af7-b957-4039-9cef-5aa01525d37f','讀楚詞三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','方從黄棘望回驂，可笑襄王又信讒。',32,'全唐诗/poet.song.87000.json','["方從黄棘望回驂，可笑襄王又信讒。", "已分世間無鮑叔，便須水底覓彭咸。"]'),
('6cc63437-d76d-4437-ba07-867567f11fe3','讀楚詞三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','人生長策是同流，却遣何人爲國憂。',32,'全唐诗/poet.song.87000.json','["人生長策是同流，却遣何人爲國憂。", "鼎鑊軒裳俱一死，屈原何得畏陽侯。"]'),
('1fa5056e-9c0e-4e5a-88b7-7537b09fc8b7','夜中聞雨枕上作','周紫芝','宋','宋诗','song-poetry','','[]','老去飄零日，春愁爛漫中。',48,'全唐诗/poet.song.87000.json','["老去飄零日，春愁爛漫中。", "詩窗窺窈窕，睡枕聽朦朧。", "弱柳妨晴態，小桃吹落紅。", "顛風莫相惱，花事不關儂。"]'),
('1772b357-8707-4c47-9805-c314a27b693f','爲人賀沈鎮江生日  其一','周紫芝','宋','宋诗','song-poetry','','[]','一麾新領浙西州，重說當年八詠侯。',64,'全唐诗/poet.song.87000.json','["一麾新領浙西州，重說當年八詠侯。", "要遣虜人知宿將，故乘軺傳作遨頭。", "朅來京口頒明詔，便合甘泉從禁遊。", "紅袖相扶客爲壽，莫嫌和月醉西樓。"]'),
('8060623e-58e2-489e-921a-c40cc1a6190e','爲人賀沈鎮江生日  其二','周紫芝','宋','宋诗','song-poetry','','[]','甲子重新數中興，濟川人爲聖時生。',64,'全唐诗/poet.song.87000.json','["甲子重新數中興，濟川人爲聖時生。", "五花名肅金鑾殿，八陣威寒鐵甕城。", "賀客杯觴方瀲灧，使君忠力轉精明。", "祝年有意留公住，只恐調元要老成。"]'),
('610c2c8b-218d-4ca1-b7d9-e2b155abcb5d','春寒','周紫芝','宋','宋诗','song-poetry','','[]','楊柳毿毿一水間，梅花憔悴雨𩆓𩆑。',32,'全唐诗/poet.song.87000.json','["楊柳毿毿一水間，梅花憔悴雨𩆓𩆑。", "春愁已自難禁酒，病骨何由更耐寒。"]'),
('e7eea566-a517-4f4f-951c-67d25a067bdf','種蘭','周紫芝','宋','宋诗','song-poetry','','[]','桃杏花中偶並欄，依然風味是幽蘭。',32,'全唐诗/poet.song.87000.json','["桃杏花中偶並欄，依然風味是幽蘭。", "莫因移種長安市，不作春山一様看。"]'),
('29a3699b-c94d-432c-8b6e-f9708403281b','種萱','周紫芝','宋','宋诗','song-poetry','','[]','萬事全歸兩鬢霜，新愁盡屬少年場。',32,'全唐诗/poet.song.87000.json','["萬事全歸兩鬢霜，新愁盡屬少年場。", "如今乞得忘憂草，已自無憂可得忘。"]'),
('7bd40378-c25d-43ed-b9ca-e80b57756e85','次韻張元明同邊郎中遊西湖二君講同年之好有此游','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里春波翠染衣，小尋魚鳥共追隨。',64,'全唐诗/poet.song.87000.json','["十里春波翠染衣，小尋魚鳥共追隨。", "船頭風急何妨醉，湖上山多盡入詩。", "藜杖偶來飛絮裏，蘆鞭猶憶看花時。", "兩公人物如連璧，同上金鑾亦未遲。"]'),
('418e146e-5082-4fd0-8096-597763304d10','皇帝親祀高禖十五韻','周紫芝','宋','宋诗','song-poetry','','[]','曆欲綿洪祚，郊宜築巨臺。',180,'全唐诗/poet.song.87000.json','["曆欲綿洪祚，郊宜築巨臺。", "有司脩祝冊，天子祭高禖。", "意與群情合，春隨上瑞來。", "翠輿瞻玉座，桂酒奠金罍。", "喜色回中壼，歡聲入九畡。", "熊羆占已兆，弧矢射將催。", "異禮關宗社，餘波被草萊。", "靈基千歲永，玉葉萬枝開。", "制度新儀著，歌詩舊典該。", "魯侯徒復宇，后稷始封邰。", "帝德應先格，天心亦易回。", "至誠參造化，妙響疾風靁。", "歷數周家久，封疆漢地恢。", "山河今壯矣，瓜瓞信悠哉。", "準擬螽斯詠，微臣愧不才。"]'),
('de709ee7-4253-490c-9231-7a4a0eb137d1','校李從一臺閣集因效其體  其一','周紫芝','宋','宋诗','song-poetry','','[]','細誦台州句，湖邊草舍幽。',48,'全唐诗/poet.song.87000.json','["細誦台州句，湖邊草舍幽。", "好山來競秀，清瀨與爭流。", "吏可供書札，兒能伴校讎。", "小窗誰共此，唯有夕陽留。"]'),
('7a902afa-ba71-40af-afc2-1db944dd0ec2','校李從一臺閣集因效其體  其二','周紫芝','宋','宋诗','song-poetry','','[]','舊旆來分賴，唐朝有百人。',48,'全唐诗/poet.song.87000.json','["舊旆來分賴，唐朝有百人。", "諸公皆泯滅，此句獨清新。", "異世名空在，今年迹已塵。", "何由弔高冢，一望石麒麟。"]'),
('a57f99bb-390d-4b0e-9a67-021626c70ec9','次韻子東奉命祠高禖齋宮望臨平山','周紫芝','宋','宋诗','song-poetry','','[]','遙想祠宮曉色寒，卷簾聊此看孱顔。',64,'全唐诗/poet.song.87000.json','["遙想祠宮曉色寒，卷簾聊此看孱顔。", "官閑頗似蘇司業，詩好全如庾子山。", "覓句不妨煙雨外，浮家猶記往來間。", "舊游有意重回首，恐上金鑾未得還。"]'),
('5e273708-462b-4691-ad32-5d6d6d90e7a5','甲子春日二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','燕來不擬著簾遮，要聽雙飛語日斜。',32,'全唐诗/poet.song.87000.json','["燕來不擬著簾遮，要聽雙飛語日斜。", "芳草滿庭人不掃，東風吹盡石楠花。"]'),
('a630daef-3266-451c-9af1-398c8b472827','甲子春日二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','海棠枝上曉鶯啼，梔子花邊蛺蝶飛。',32,'全唐诗/poet.song.87000.json','["海棠枝上曉鶯啼，梔子花邊蛺蝶飛。", "貪看游蜂偷蘂去，不知雙燕得泥歸。"]'),
('861cc696-6e7c-42af-9ba5-cab5c7f1e96a','與王漕乞張右史集二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','文采推前輩，兒童識姓名。',48,'全唐诗/poet.song.87000.json','["文采推前輩，兒童識姓名。", "日邊張右史，江左謝宣城。", "自恨空飄泊，無由見老成。", "著書如可得，尚足慰生平。"]'),
('787848c4-f1dc-400b-80e4-c83ad0fe4adc','與王漕乞張右史集二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','張緒風流士，文昌古淡詩。',48,'全唐诗/poet.song.87000.json','["張緒風流士，文昌古淡詩。", "發揚知有助，埋没竟多時。", "公已勤讎校，神應作護持。", "何當遺珠玉，璀璨滿書幃。"]'),
('9ed3c941-22e8-428d-9970-ff8bb77f4386','對雨','周紫芝','宋','宋诗','song-poetry','','[]','風細寒猶甚，愁多睡更濃。',48,'全唐诗/poet.song.87000.json','["風細寒猶甚，愁多睡更濃。", "閉門春色裏，盡日雨聲中。", "草各爭先出，花皆稱意紅。", "故人書信少，不記此衰翁。"]'),
('f4a31d9d-5dc3-4a38-87bc-3da7dbd6a7a1','晚行湖堤望南山諸峰','周紫芝','宋','宋诗','song-poetry','','[]','曳履步遠壑，挽衣枝短筇。',120,'全唐诗/poet.song.87000.json','["曳履步遠壑，挽衣枝短筇。", "霽色過急雨，餘霞漏微紅。", "照眼一湖淨，環湖幾山重。", "不知何禪燈，明滅蒼翠叢。", "但聞煙霞間，繞山鳴亂鐘。", "暮年行樂意，不與足力窮。", "明晨倘可遲，尚堪歷諸峰。", "有幽固當探，無客誰與同。", "餘子不足偕，形往影自從。", "言旋且當爾，興在何由終。"]'),
('8a0c4a08-10fa-48ed-9e54-e46e0ec212e8','謝曾同季示近作因以爲贈','周紫芝','宋','宋诗','song-poetry','','[]','老色秋蒲晚，朱顔玉樹春。',48,'全唐诗/poet.song.87000.json','["老色秋蒲晚，朱顔玉樹春。", "年方賈生妙，詩似庾郎新。", "黄墓初傾蓋，青墩欲買鄰。", "知君真似舅，笑我作陳人。"]'),
('83e9449e-7df9-4b48-a5f6-ecafec359dec','同季再見和二首復用韻以謝  其一','周紫芝','宋','宋诗','song-poetry','','[]','花似今年好，情非舊日春。',48,'全唐诗/poet.song.87000.json','["花似今年好，情非舊日春。", "光陰愁裏盡，風物眼前新。", "愛酒聊呼伴，無醯懶乞鄰。", "姓名誰掛口，肥瘠付秦人。"]'),
('2e89a91e-eb2b-407f-bd3d-15b2909213cd','同季再見和二首復用韻以謝  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','海內同爲客，西湖共送春。',48,'全唐诗/poet.song.87000.json','["海內同爲客，西湖共送春。", "定交前日意，識面此時新。", "一笑欣良會，餘生得善鄰。", "風流美無度，往往似前人。"]'),
('861b5f3e-deb2-4634-86e6-0fa3beeb7a93','送秦德久守安豐','周紫芝','宋','宋诗','song-poetry','','[]','師行朔野不記年，兩淮千里無炊烟。',144,'全唐诗/poet.song.87000.json','["師行朔野不記年，兩淮千里無炊烟。", "君王偃革似建武，始遣循吏來安邊。", "今日安豐非故壘，夜聞夷歌隔淮水。", "况當兩國不交兵，高塹深溝豈須爾。", "朝不鳴刁夜滅烽，吉語上聞天自喜。", "但令南畝棲餘糧，盡驅流冗歸故鄉。", "會見今年八九月，處處棗紅梨子黄。", "四郊無兵門有戟，淮上山青淮水碧。", "樽前一曲柳枝歌，釀酒擊鮮公燕客。"]'),
('dacb0385-c047-45f0-aa08-8d5036e363e6','客有爲予言笋不可食食之令人瘦者戲作二絕爲解嘲  其一','周紫芝','宋','宋诗','song-poetry','','[]','庾郎三韭坐清貧，眼看將軍肉十斤。',32,'全唐诗/poet.song.87000.json','["庾郎三韭坐清貧，眼看將軍肉十斤。", "會遣胸中有千畝，不妨人似沈休文。"]'),
('6d92cf07-5dd0-4aa0-8b98-3ad6a5f883d7','客有爲予言笋不可食食之令人瘦者戲作二絕爲解嘲  其二','周紫芝','宋','宋诗','song-poetry','','[]','園蔬本自不全貧，今日真成笋作斤。',32,'全唐诗/poet.song.87000.json','["園蔬本自不全貧，今日真成笋作斤。", "已恨此生相見少，更須儂作解嘲文。"]'),
('ecb8b647-102f-40c2-a8a5-7d98ed841035','今日林中頗得佳笋用前韻  其一','周紫芝','宋','宋诗','song-poetry','','[]','閑尋黑靨猫頭筍，自把長鑱雪色斤。',32,'全唐诗/poet.song.87000.json','["閑尋黑靨猫頭筍，自把長鑱雪色斤。", "恨我家無渭川竹，姓名不載馬遷文。"]'),
('d403424f-0dda-4439-b08d-10d9069de990','今日林中頗得佳笋用前韻  其二','周紫芝','宋','宋诗','song-poetry','','[]','作葅須趁笋如銀，莫待成竿費斧斤。',32,'全唐诗/poet.song.87000.json','["作葅須趁笋如銀，莫待成竿費斧斤。", "安用截筒纒五采，爲人催草弔湘文。"]'),
('4e774ec0-5697-4c2e-ba3b-886c2a1c8700','劉主簿許餉苦筍未至  其一','周紫芝','宋','宋诗','song-poetry','','[]','苦竹岡頭竹似雲，劉郎何事不揮斤。',32,'全唐诗/poet.song.87000.json','["苦竹岡頭竹似雲，劉郎何事不揮斤。", "杯盤倘使同吳俗，荼薺誰能作楚文。"]'),
('392bdb2d-a09a-424b-9bd5-5e3b31bd4f97','劉主簿許餉苦筍未至  其二','周紫芝','宋','宋诗','song-poetry','','[]','未敢煩君便指囷，且看分筍不論斤。',32,'全唐诗/poet.song.87000.json','["未敢煩君便指囷，且看分筍不論斤。", "此君自是盤中虎，空想斑斑箸下文。"]'),
('249b7c0f-5415-47de-ae89-13125c362ae9','西湖春事五首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩高南北擁烟鬟，渾在溟濛細雨間。',32,'全唐诗/poet.song.87000.json','["兩高南北擁烟鬟，渾在溟濛細雨間。", "寄語丹青王右相，不須水墨畫春山。"]'),
('effaa53f-06db-46c4-8927-de3f9f39e739','西湖春事五首  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老去無心作好春，曉來風雨故欺人。',32,'全唐诗/poet.song.87000.json','["老去無心作好春，曉來風雨故欺人。", "從教髪白桃花笑，不管簾垂燕子嗔。"]'),
('9a3ef741-6e35-4d19-9fed-b65a107bc7ac','西湖春事五首  其三','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','顛春柳絮風前落，臥水桃花鑑裏開。',32,'全唐诗/poet.song.87000.json','["顛春柳絮風前落，臥水桃花鑑裏開。", "沙上鴛鴦忽驚起，背人飛去不回來。"]'),
('c9b36e6a-5c76-41ab-b5ee-cf822882359d','西湖春事五首  其四','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒食人家畫鼓撾，踏歌聲裏月生華。',32,'全唐诗/poet.song.87000.json','["寒食人家畫鼓撾，踏歌聲裏月生華。", "無人來祭皇妃墓，空唱吳王陌上花。"]'),
('1708d02e-321b-4b18-a2c5-6db101687066','西湖春事五首  其五','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','半垂羅幕護紅粧，閑繫青驄在綠楊。',32,'全唐诗/poet.song.87000.json','["半垂羅幕護紅粧，閑繫青驄在綠楊。", "樓上日長時度曲，路邊風過忽吹香。"]'),
('54c1e92e-4171-48b1-8853-b00a04961ef8','晚出郡城','周紫芝','宋','宋诗','song-poetry','','[]','天街打鼓出城門，暝色侵衣欲破昏。',32,'全唐诗/poet.song.87000.json','["天街打鼓出城門，暝色侵衣欲破昏。", "湖上晚峰横玉玦，馬頭新月上金盆。"]'),
('1309e255-554c-47d0-afa4-b3a2530d5188','次韻强常州見寄','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','門前冠佩眼中稀，家在西湖水繞扉。',64,'全唐诗/poet.song.87000.json','["門前冠佩眼中稀，家在西湖水繞扉。", "每對鳯姿羞羽翼，更因魚目得珠璣。", "身閑聊伴蒼官語，詩瘦空慚笨伯肥。", "别後清言應亹亹，不知談麈爲誰揮。"]'),
('28b86e10-41c8-4981-9e07-d04fee212833','天申節湖上早歸','周紫芝','宋','宋诗','song-poetry','','[]','昨夜雨如許，今朝雲復開。',48,'全唐诗/poet.song.87000.json','["昨夜雨如許，今朝雲復開。", "鳥聲呼日出，湖水上隄來。", "贊祝人天喜，鏘鳴劍佩回。", "歸途似明鏡，影落翠鬟堆。"]'),
('c53a1f9f-53cd-44f3-bb73-22d7e292de94','食新秔有感','周紫芝','宋','宋诗','song-poetry','','[]','玉粒新秔五月黄，中含風露晚秋香。',32,'全唐诗/poet.song.87000.json','["玉粒新秔五月黄，中含風露晚秋香。", "但令雲子流匙滑，莫管吳儂眼下創。"]'),
('a3c34a69-3944-4443-a3e7-aa7c819b3c08','次韻曾同季悼其幼子','周紫芝','宋','宋诗','song-poetry','','[]','曾侯名家郎，家有玉頰兒。',72,'全唐诗/poet.song.87000.json','["曾侯名家郎，家有玉頰兒。", "渥洼出名駒，丹穴生長離。", "春風入庭户，獨秀蘭與芝。", "未乾弄麞墨，遽草騎龜詩。", "我昔少年日，屢作哭子癡。", "須煩六如偈，爲洗長年悲。"]'),
('af746129-3830-4ead-97d6-9db84a70e8e0','韋深道寄苕霅舟中六言五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','畫舸一帆烟浪，薫風十里荷花。',28,'全唐诗/poet.song.87000.json','["畫舸一帆烟浪，薫風十里荷花。", "更着千巖萬壑，相隨泛宅浮家。"]'),
('7105d7f6-4d45-427b-882b-263d74feac7b','韋深道寄苕霅舟中六言五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','水繞臥沙鸂鶒，浪翻擎雨芙蕖。',28,'全唐诗/poet.song.87000.json','["水繞臥沙鸂鶒，浪翻擎雨芙蕖。", "向晚柂樓獨倚，共誰同看跳珠。"]'),
('21b62bdf-f558-4471-ba9a-697dcf2f4844','韋深道寄苕霅舟中六言五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','韋郎無意剪白，次山亦漫爲官。',28,'全唐诗/poet.song.87000.json','["韋郎無意剪白，次山亦漫爲官。", "要遣苕溪風雨，飽君筆下波瀾。"]'),
('90fbf702-9c95-492c-b176-e5988afd32f8','韋深道寄苕霅舟中六言五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','滿眼紅粧迎笑，昔年遊客經行。',28,'全唐诗/poet.song.87000.json','["滿眼紅粧迎笑，昔年遊客經行。", "忽得風前麗句，似聞蓬底波聲。"]'),
('315fa071-4349-4347-b9ef-60cf946e4002','韋深道寄苕霅舟中六言五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','我作三吳短夢，小安近水茅茨。',28,'全唐诗/poet.song.87000.json','["我作三吳短夢，小安近水茅茨。", "解養能言鴨子，閑看似酒鵝兒。"]'),
('9fceb8cf-e5c1-40b5-a740-ad3e3e83de5e','西湖月夜','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月到中天火未流，水邊風露已含秋。',32,'全唐诗/poet.song.87000.json','["月到中天火未流，水邊風露已含秋。", "問誰乞取西湖角，紅藕花中著釣舟。"]'),
('a40087f1-bd69-4230-a36e-ddf8b28ab86c','菩提小軒驟雨晚晴','周紫芝','宋','宋诗','song-poetry','','[]','杭潁雌雄本自殊，淡粧濃抺是吳姝。',64,'全唐诗/poet.song.87000.json','["杭潁雌雄本自殊，淡粧濃抺是吳姝。", "滿傾漲玉千鍾酒，來看鎔銀百頃湖。", "白鳥去邊山潑黛，綠蒲疏處雨跳珠。", "不知能事王摩詰，貎得西山落照無。"]'),
('014d6f3c-91ef-4875-b4ae-9cba9862c4f2','早發北山由麥嶺飯大通登烟霞洞閣','周紫芝','宋','宋诗','song-poetry','','[]','瀕湖兩峰高，屹立曉相望。',204,'全唐诗/poet.song.87000.json','["瀕湖兩峰高，屹立曉相望。", "蒼凉昇海日，骯髒露千嶂。", "羸驂絕坡陁，巖谷飽追訪。", "緬懷洪荒初，藴蓄含萬象。", "渾沌久已死，倏忽真巧匠。", "誰令鑿空手，出此奇險狀。", "中虚納游雲，谷靜答幽唱。", "暗穴下無底，濤聲想悲壯。", "十八老聲聞，附石出遺像。", "誰其架脩椽，置屋雲雨上。", "青山不知數，遶屋森百丈。", "忽于兩峰間，萬頃見烟浪。", "澎湃海潮聲，往往入藜杖。", "天公知愛山，令我拜嘉貺。", "眇焉隔仙凡，欲往漫惆悵。", "便當學枯禪，綺語蠲宿妄。", "自足伴周旋，長年此遐放。"]'),
('0dd5341a-3a7a-4f5e-b452-b8969244168c','題孤山柏','周紫芝','宋','宋诗','song-poetry','','[]','臺城依舊繞長河，結綺臨春往事多。',64,'全唐诗/poet.song.87000.json','["臺城依舊繞長河，結綺臨春往事多。", "但見張妃似西子，不知擒虎是閻羅。", "當年已老瓊瑤樹，此去空留鐵石柯。", "喬木自存非故國，何須仍唱後庭歌。"]'),
('db134440-f601-4604-88b0-678d6e67a66b','次韻周秀實寺丞七夕三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','烏鵲橋成不恨遲，隔秋相見豈無期。',32,'全唐诗/poet.song.87000.json','["烏鵲橋成不恨遲，隔秋相見豈無期。", "姮娥空傍月中去，嫁得星郎是幾時。"]'),
('6638de81-6b6f-4c3c-a7f0-2643d32ea44d','次韻周秀實寺丞七夕三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','夜深閑把玉東西，月下樓空畫幕垂。',32,'全唐诗/poet.song.87000.json','["夜深閑把玉東西，月下樓空畫幕垂。", "人似天孫酒如玉，夢中猶憶少年時。"]'),
('bda97ec2-bc91-4ca5-959a-a7a3577df3b0','次韻周秀實寺丞七夕三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','無限欄階月下兒，遙瞻星旆却嫌遲。',32,'全唐诗/poet.song.87000.json','["無限欄階月下兒，遙瞻星旆却嫌遲。", "催教織女梳雲髻，想得無心理杼絲。"]'),
('73e22d4e-af1b-4ce5-a5db-d41dd7b71957','數日秋暑不復可堪馬上作此','周紫芝','宋','宋诗','song-poetry','','[]','江上豐隆醖秋熱，老病摧頹可堪說。',64,'全唐诗/poet.song.87000.json','["江上豐隆醖秋熱，老病摧頹可堪說。", "人行落日生黄塵，馬畏長塗汗流血。", "君看此處安得詩，空學吳牛喘殘月。", "北風何日掛駞裘，長嘯灞橋驢上雪。"]'),
('bc7b4711-0bf4-42f7-b00a-8ace2eef0575','葉宣義家壽祉堂','周紫芝','宋','宋诗','song-poetry','','[]','吉人爲善天所彰，效有遲速理則常。',264,'全唐诗/poet.song.87000.json','["吉人爲善天所彰，效有遲速理則常。", "葉侯天驥少未驤，讀書過眼下十行。", "易如翻水成文章，學既日富名日昌。", "謂取富貴如探囊，當時餘子皆擅場，呼不成盧空繞牀。", "直氣勇决何可當，買田築室龍池陽。", "夜光穿屋萬丈長，人言家有明珠雙。", "青衫歸侍讌几傍，仿彿月中丹桂香。", "要看玉樹爭芬芳，擊鮮不羨游諸郎。", "大裘執玉郊圓蒼，厖恩厚澤均四方。", "翁年九十鬢不霜，錫以命服閭里光。", "門前賀客俱奔忙，手持牛酒填康莊。", "遂摘天語名公堂，不須靈壽扶徜徉。", "高文戞玉鳴琳瑯，省郎言語如君房。", "天公報德殊未央，傳家奕葉壽且康。", "王母晝着雲錦裳，麻姑行酒傾瓊漿。", "壺中日永醉玉觴，赤松黄石相扶將。"]'),
('ad3d801e-19b8-4f17-aca1-8fde8f556968','孫仲益尚書以詩贈吳益先吳出巨軸索詩','周紫芝','宋','宋诗','song-poetry','','[]','少年名字滿賢關，薦墨誰能借一言。',64,'全唐诗/poet.song.87000.json','["少年名字滿賢關，薦墨誰能借一言。", "子産自應知季札，退之先已得何蕃。", "江無九肋空多士，樹有三珠且共門。", "晚路相逢歎流落，可憐不第獨劉蕡。"]'),
('9b26d293-275a-42d2-b5c6-476fdad2afa0','木犀方花一首','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖八九月，秋葉日夜凋。',168,'全唐诗/poet.song.87000.json','["西湖八九月，秋葉日夜凋。", "兩山各崢嶸，氣與秋爭高。", "天亦念幽絕，芬芳托孤標。", "要令列仙臞，一洗桃李驕。", "往往遣暗香，時時入高飇。", "綠葉未改色，微黄澹烟梢。", "可愛不可名，模寫徒自勞。", "向來蠟梅花，相去無絲毫。", "但恨此花遲，不借春雨膏。", "尚可配精蘂，傲霜分兩豪。", "金錢不知數，狼藉蒙譏嘲。", "可憐貴人家，漬蜜紛煎熬。", "坐令林下姿，半入金猊焦。", "閨房漫脂澤，此恨何由消。"]'),
('cb7d48fc-8238-472e-8161-a82dd7f93422','登北高峰一首','周紫芝','宋','宋诗','song-poetry','','[]','鼓楫去故里，攜孥客東吳。',168,'全唐诗/poet.song.87000.json','["鼓楫去故里，攜孥客東吳。", "湖山森照耀，魚鳥相嬉娛。", "舉目見兩高，欲上徒嗟吁。", "人言不可往，無路登雲衢。", "盡力賈餘勇，遂復酬宿逋。", "白鳥入蒼煙，滅没在太虚。", "曉日沸晹谷，萬川納歸墟。", "海門豁中開，怒濤喧朝晡。", "盡注百丈江，拱揖朝伍胥。", "銀湖大如許，僅可方覆盂。", "諸峰如培塿，瑣細不足圖。", "寸眸一俯仰，八極無遺餘。", "苐恨蒼凉日，悠悠迫懸車。", "臨風一悵惘，言旋戒危塗。"]'),
('36fb50bf-ecc7-4957-8d4f-fa483794b6b6','資國巨松伐爲東觀材','周紫芝','宋','宋诗','song-poetry','','[]','文字初離五阨餘，緗囊縹帙秘新儲。',32,'全唐诗/poet.song.87000.json','["文字初離五阨餘，緗囊縹帙秘新儲。", "何人合在天東壁，十八公堪作校書。"]'),
('60c71f10-3216-4165-9aee-c2e53e704abf','徐五十六索勤有種德二軒詩各賦一首  其一','周紫芝','宋','宋诗','song-poetry','','[]','平生長笑韓潮州，欲持讜議回冕旒。',128,'全唐诗/poet.song.87000.json','["平生長笑韓潮州，欲持讜議回冕旒。", "讀書城南晚所賦，無乃不爲韓符謀。", "人間達官可力取，釣名但以詩爲鈎。", "汗牛充宇作底用，富貴面熱渠當羞。", "書生有書但自讀，不必區區苦投俗。", "偶然一擲便成盧，雁塔朝題暮天祿。", "吾言可笑君必輕，奔軍之策何足憑。", "臨機應敵自子事，此是宋襄仁義兵。"]'),
('28899644-1771-48ca-bb70-420ec3c82d85','徐五十六索勤有種德二軒詩各賦一首  其二','周紫芝','宋','宋诗','song-poetry','','[]','結廬須種木，樂饑須種糓。',125,'全唐诗/poet.song.87000.json','["結廬須種木，樂饑須種糓。", "種木十年能幾長，種糓眼前無乃速。", "人生安得俟河清，誰能忍饑百年待德成。", "君不見千古一臯陶，此事世亦少。", "頗能化俗成唐虞，何乃滅國先六蓼。", "慎勿說夢與癡人，著意勸渠渠不曉。", "南鄰門耀三戟光，北鄰牛馬谷可量。", "浮雲變滅那得常，安樂只有襄陽龐。"]'),
('ce64dde0-50f0-49d8-8ede-17cb69291ff5','中秋携小兒步湖隄  其一','周紫芝','宋','宋诗','song-poetry','','[]','病裏三年月，相隨過兩州。',48,'全唐诗/poet.song.87000.json','["病裏三年月，相隨過兩州。", "爲儂分素魄，攜汝作清游。", "草樹悲今夕，家鄉隔去秋。", "有身真似夢，無地不關愁。"]'),
('588ddfef-a377-4c53-9a12-c996244e1c30','中秋携小兒步湖隄  其二','周紫芝','宋','宋诗','song-poetry','','[]','門接銀湖浪，居仍在寶坊。',48,'全唐诗/poet.song.87000.json','["門接銀湖浪，居仍在寶坊。", "更煩山吐月，來共水分光。", "葉冷初翻夜，蟲悲擬泣霜。", "幽人看不足，白露滿胡床。"]'),
('ffc39b76-c30a-4d5d-ad16-624b7a386ac1','送方元相還郊居','周紫芝','宋','宋诗','song-poetry','','[]','雲從南山來，邂逅成一雨。',120,'全唐诗/poet.song.87000.json','["雲從南山來，邂逅成一雨。", "秋風忽吹散，霢霂不到土。", "出固初何心，歸亦乃其所。", "但恨山中人，弔影無誰語。", "笑口曾未開，語離遽如許。", "到家應重陽，精蘂亦已吐。", "長衫隨父老，社甕酌田祖。", "悠悠臥黄雲，坎坎擊醉鼓。", "人生行樂耳，何必浪自苦。", "恨我繫微官，何由共鷄黍。"]'),
('add13e19-9fd9-44a5-8eb0-6edeb84421da','古風二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','夜夢乘輕舟，掛席浮天池。',144,'全唐诗/poet.song.87000.json','["夜夢乘輕舟，掛席浮天池。", "天池亦何有，濤瀾靡津涯。", "中有三神山，樓觀何巍巍。", "晶熒白玉闕，彩錯黄金旗。", "紫皇遣天風，下吹仙人衣。", "仙人不知名，人言是安期。", "我欲就與語，弱水隔渺瀰。", "鼓枻方少前，風動輒去之。", "仙人不得見，遙睇忍言歸。", "願言哀劬勞，舉手援塵姿。", "探囊得靈丹，往往分刀圭。", "使我生羽翼，桑榆增暮輝。"]'),
('d8905f08-1e6c-49dd-8914-27cd67d842ba','古風二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','矯首望寥廓，雲日清四方。',120,'全唐诗/poet.song.87000.json','["矯首望寥廓，雲日清四方。", "梟獍各屏跡，孔鸞亦高翔。", "鳯羽可爲儀，用以朝帝皇。", "八音奏韶濩，五色呈文章。", "帝皇在殊庭，斂珮方鏘鏘。", "顧瞻丹鳯儔，高目振鷺行。", "斥鷃獨何事，乘時亦飛揚。", "短羽無遠志，控地搶榆枋。", "卑飛固可笑，摧折亦足傷。", "願附翽翽翼，託身雲漢傍。"]'),
('f6345f95-3518-4276-b945-1f6555b175d4','放龜','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','老黥得龜規小利，小兒奪龜以爲戲。',64,'全唐诗/poet.song.87000.json','["老黥得龜規小利，小兒奪龜以爲戲。", "兒癡但作一笑看，槁死生存兩無意。", "乃翁不忍龜縮頭，何如去曳長江尾。", "流水長者亦念汝，清江繡衣何憂苦。"]'),
('757f65e1-9a44-4f3c-b5e6-2ddf060e3747','不睡效張文潛','周紫芝','宋','宋诗','song-poetry','','[]','寒沙宿鷺水無聲，湖月留人睡不成。',32,'全唐诗/poet.song.87000.json','["寒沙宿鷺水無聲，湖月留人睡不成。", "便擬閉門尋好夢，更聽鸜鵒轉三更。"]'),
('7125f804-2c05-49d9-8b42-05c6677fa5f3','觀潮示元龍','周紫芝','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','越山莽蒼吳山高，海門屹立通江濤。',128,'全唐诗/poet.song.87000.json','["越山莽蒼吳山高，海門屹立通江濤。", "江頭久客歸未得，來趁吳兒看晚潮。", "潮頭初來一線白，雪浪翻空忽千尺。", "地中鳴角何處來，水上六花人不識。", "驚濤倒射須臾空，千艘已落空濛中。", "錦帆半臂浪花裏，越商巴賈爭長雄。", "江湖險絕長如此，風靜潮平亦何事。", "人間萬法有乘除，却遣風波在平地。"]'),
('6d1001fb-2a81-4a9e-b4c3-e2addf3d70a1','客許惠木犀而花殊未開三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','秋雨不肯止，木犀殊未開。',24,'全唐诗/poet.song.87000.json','["秋雨不肯止，木犀殊未開。", "小齋寒索莫，誰剪一枝來。"]'),
('560e7c89-eb2f-406b-8d1b-899bab4f9686','客許惠木犀而花殊未開三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','黄菊無多子，孤芳正要渠。',24,'全唐诗/poet.song.87000.json','["黄菊無多子，孤芳正要渠。", "誰能把秋色，分付木芙蕖。"]'),
('52d689c2-66a4-44a5-84d1-26827149a97f','客許惠木犀而花殊未開三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','舊日江南路，霜裘曉樹間。',24,'全唐诗/poet.song.87000.json','["舊日江南路，霜裘曉樹間。", "無香供晏坐，有夢到秋山。"]'),
('7cd8fd2c-885b-4b1b-8431-1cc8a0fd0bef','客許惠木犀而花殊未開三絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','秋夜旅懷栖栖羈客眼長開，蔌蔌清燈落曉灰。',68,'全唐诗/poet.song.87000.json','["秋夜旅懷栖栖羈客眼長開，蔌蔌清燈落曉灰。", "北雁有情書未到，寒衾無夢雨頻來。", "今年白髪看仍少，去日青春挽不回。", "别後故山應好在，小窗辜負翠雲堆。"]'),
('8b9441b5-2be2-4b5d-b360-ff012c142d49','次韻飛卿','周紫芝','宋','宋诗','song-poetry','','[]','隨計京華憶去年，夢魂合眼到家山。',64,'全唐诗/poet.song.87000.json','["隨計京華憶去年，夢魂合眼到家山。", "早無半菽能餬口，晚得三鍾只汗顔。", "老懶不堪朱墨裏，此心終在水雲間。", "尺椽分我江邊路，留與他年作往還。"]'),
('27434e67-9f71-46c2-8440-551daca0c520','次韻李子至與陳相之定尋梅之約篇尾見及','周紫芝','宋','宋诗','song-poetry','','[]','謝朓樽前憶語離，别來懷抱只愁知。',64,'全唐诗/poet.song.87000.json','["謝朓樽前憶語離，别來懷抱只愁知。", "鶺鴒原近識君晚，鴻雁書遙寄客遲。", "何事不嫌霜後鬢，尚邀同醉雪殘枝。", "今年新得梅花句，華萼詩中第幾詩。"]'),
('ca7de692-f524-46e4-acf9-ff6f8f6dee46','次韻相之和李子至尋梅詩','周紫芝','宋','宋诗','song-poetry','','[]','江南洛社各天涯，何事高人亦見思。',64,'全唐诗/poet.song.87000.json','["江南洛社各天涯，何事高人亦見思。", "句法風流雲爛漫，旅情飄泊燕差池。", "樽前病骨難供醉，花下枯藤可强枝。", "莫喚孤山林處士，揚州何遜自能詩。"]'),
('b1e15e06-15e0-47b0-a33f-1265e7e43d72','劉文卿燒木犀沉爲作長句','周紫芝','宋','宋诗','song-poetry','','[]','海南萬里水沉樹，江南九月木犀花。',160,'全唐诗/poet.song.87000.json','["海南萬里水沉樹，江南九月木犀花。", "不知誰作造化手，幻出此等無品差。", "劉郎嗜好與衆異，煮蜜成香出新意。", "短窗護日度春深，石鼎生雲得煙細。", "夢回依約在秋山，馬上清香撲霜霽。", "平生可笑范蔚宗，甲煎淺俗語未公。", "此香似有郢人質，能受匠石斤成風。", "不須百和費假合，成一種性無異同。", "能知二物本同氣，鼻觀已有香嚴通。", "聊將戲事作薄相，辦此一笑供兒童。"]'),
('4ab30118-e055-4726-92d0-f53d4dc4dde2','曉雪','周紫芝','宋','宋诗','song-poetry','','[]','湖色催清曉，風前一雪輕。',48,'全唐诗/poet.song.87000.json','["湖色催清曉，風前一雪輕。", "不妨梅自笑，要與水争明。", "萬木雲遮盡，千巖玉琢成。", "可憐青竹葉，寒甚與誰傾。"]'),
('acc0135f-96e3-4143-85bb-3d59baf12802','時宰生日樂府四首 御燕曲','周紫芝','宋','宋诗','song-poetry','','[]','新陽入谷春欲回，瑤池春早桃花開。',144,'全唐诗/poet.song.87000.json','["新陽入谷春欲回，瑤池春早桃花開。", "黄金三尺瑞獸暖，雲横霧繞珠簾垂。", "碧腴分香自紫府，百壺流泉酒如許。", "御厨排燕羅八珍，更飭梨園賜歌舞。", "黄門宣詔天上來，歡喜時聞傳帝語。", "紅鑾畫幕密護遮，參差吹竹凌丹霞。", "雙成持觴萼綠勸，五雲遙望羣仙家。", "仙家日月真長久，地久天長聖恩厚。", "願公歲歲復年年，長带宮花飲宮酒。"]'),
('e1641281-e047-4c4e-9b6e-b45395a87b98','時宰生日樂府四首 班師行','周紫芝','宋','宋诗','song-poetry','','[]','漢兵出塞將軍行，棘門灞上空屯營。',160,'全唐诗/poet.song.87000.json','["漢兵出塞將軍行，棘門灞上空屯營。", "羽書夜半急如火，淮田千里無春耕。", "廟堂有議如建武，十歲邊頭不鳴鼓。", "君王無事兩國歡，長樂宮中瞻聖母。", "鷹饑虎飽不足圖，三軍漸欲銷兵符。", "紅旗盡卷夜烽冷，銅花繡甲金糢糊。", "横議當年蝟毛起，公持一言天自喜。", "盡收諸將入神京，十六衛閑清似水。", "榆關一騎不動塵，陰功何止活萬人。", "封侯鑄印不足說，朱顔一笑三千春。"]'),
('f709e618-256b-4017-a2db-d233404eb17b','時宰生日樂府四首 昇平謠','周紫芝','宋','宋诗','song-poetry','','[]','負石填海海可乾，鑄鐵削山山可栞。',192,'全唐诗/poet.song.87000.json','["負石填海海可乾，鑄鐵削山山可栞。", "俟河之清豈易得，眼見太平真復難。", "春風輦路宮槐綠，花繞漢宮三十六。", "喜入天顔人盡知，奉常新奏昇平曲。", "前年被袞郊圓天，今年執玉朝塗山。", "漢官威儀久不見，三代禮樂俱追還。", "太師功大非人力，早向壺天賜新宅。", "消得官家駐六飛，畫鼓咽咽燕瑤席。", "紫宸朝散千官行，四方警奏虛封章。", "袞司無事鈴索静，牙牌報漏春晝長。", "但聞羣賢歲歌舞，壽曲聲中玉觴舉。", "青衫小吏亦復歡，自採民謠裨樂府。"]'),
('9a69a3a3-328b-49e4-8349-2c4a813cc7e2','時宰生日樂府四首 祈年歌','周紫芝','宋','宋诗','song-poetry','','[]','十雨五風年歲熟，萬落千村俱種粟。',195,'全唐诗/poet.song.87000.json','["十雨五風年歲熟，萬落千村俱種粟。", "人從南畝把金犁，誰在廟堂調玉燭。", "昔年避地今安居，前日荷戈今佩犢。", "開元宰相不開邊，當時米賤斗數錢。", "自從罷武銷劍戟，外户不閉俱安眼。", "人蒙更生家受賜，父老歡喜兒童顛。", "君不見天上宸章燦星斗，翔鸞驚飛翠蛟走。", "爲言一德似阿衡，上格皇天贊元后。", "皇天報德亦可知，仁者必壽天無私。", "但願天心錫難老，貂冠畫袞常光輝。", "四國無兵誰不喜，共說昇平自今始。", "黄帝垂衣坐法宮，千歲常師廣成子。"]'),
('8d40c99b-00f8-4b50-a0ea-02afc89ca231','冬至前九日湖水盡冰後二日晚晴小舟循湖心而歸冰已稍開書是日所見','周紫芝','宋','宋诗','song-poetry','','[]','積雨凝宿陰，寒冰結湖背。',120,'全唐诗/poet.song.87000.json','["積雨凝宿陰，寒冰結湖背。", "鷗鷺不敢前，龜魚各潛晦。", "敲冰得湖心，鼓棹作澎湃。", "萬玉朝明堂，丁冬響環珮。", "誰來貝闕中，小現銀色界。", "夕陽似知人，微温散珠琲。", "爲我開糢糊，遙山影空翠。", "境勝不可名，語惡聊自悔。", "安得王右丞，萬象歸綵繪。", "遙憐西子寒，眉目增點綴。"]'),
('589fffd4-a298-47f7-9242-8df9b2efc327','將登南高示同舍  其一','周紫芝','宋','宋诗','song-poetry','','[]','萬壑千巖要盡窮，漫將筋力試衰翁。',32,'全唐诗/poet.song.87000.json','["萬壑千巖要盡窮，漫將筋力試衰翁。", "請君速辦尋山屐，同上南高第一峰。"]'),
('a8e77dfc-87b4-4474-b5bb-7b123cb13c71','將登南高示同舍  其二','周紫芝','宋','宋诗','song-poetry','','[]','三年身在翠鬟堆，慣見湖山眼厭開。',32,'全唐诗/poet.song.87000.json','["三年身在翠鬟堆，慣見湖山眼厭開。", "要上雲峰最高處，試看潮過海門來。"]'),
('104a5320-eb68-43b8-9deb-f2a3d4dfa8fd','過趙德莊官居有懷其人','周紫芝','宋','宋诗','song-poetry','','[]','送君南浦草青青，記得江邊一醉醒。',64,'全唐诗/poet.song.87000.json','["送君南浦草青青，記得江邊一醉醒。", "騎馬却來尋舊處，依然蒼竹近寒廳。", "讀君古錦囊中句，可是紅蓮幕下才。", "試問風流李長吉，如何不寄近詩來。"]'),
('269b6e10-3c16-47bc-aa55-ec2985a99556','次韻關子東聞太常新樂','周紫芝','宋','宋诗','song-poetry','','[]','今歲塗山禹會成，俟河真得見河清。',32,'全唐诗/poet.song.87000.json','["今歲塗山禹會成，俟河真得見河清。", "官麤無路朝元去，臥聽鈞天奏樂聲。"]'),
('b8b128e6-716a-411f-a13e-641672fcdd2c','湖上雜賦三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','青腰載雨入菰蒲，旋斫漁竿學釣魚。',32,'全唐诗/poet.song.87000.json','["青腰載雨入菰蒲，旋斫漁竿學釣魚。", "小向湖心作容與，天教來此伴舂鋤。"]'),
('2efcbfc5-fa36-4b42-88f2-c2827f6abbab','湖上雜賦三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','山邊騎馬醉王孫，湖裏撐船晚過門。',32,'全唐诗/poet.song.87000.json','["山邊騎馬醉王孫，湖裏撐船晚過門。", "寄語金丸莫輕彈，我無花鴨觧人言。"]'),
('1c699d40-cb85-49f6-8680-91360ad9730c','湖上雜賦三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','三年原不下胡床，飲盡山光與水光。',32,'全唐诗/poet.song.87000.json','["三年原不下胡床，飲盡山光與水光。", "莫把渠儂作官看，此身便是賀知章。"]'),
('98044525-5750-4eb6-9273-d748c6b33e56','次韻何子楚題吳傳朋石渠大字','周紫芝','宋','宋诗','song-poetry','','[]','中郎往昔游鴻都，眼見帚堊心成書。',128,'全唐诗/poet.song.87000.json','["中郎往昔游鴻都，眼見帚堊心成書。", "乃知隸法亦天授，後世豈復斯人徒。", "周王百度新復古，道家山是圖書府。", "吳侯妙翰絕古今，高榜横空近風雨。", "大字三尺古所難，細書不要烏絲欄。", "四蹄自抉水邊石，兩翮忽舉空中鸞。", "知君自是文中虎，便恐聲名傳帝所。", "借令頭白下凌雲，寄語韋郎耐辛苦。"]'),
('f39f6f68-61df-4304-9ba9-f7622270654a','次韻庭藻雨中不出湖上','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幅巾飽看西湖春，徐行當車不動塵。',160,'全唐诗/poet.song.87000.json','["幅巾飽看西湖春，徐行當車不動塵。", "有時乘興未遽反，武林無此尋春人。", "湖山如螺湖水白，幾見青天月生魄。", "年年馬上看吳娃，舞袖雙裁越羅窄。", "長安貴人百不憂，胡爲亦復多窮愁。", "出門載酒不可往，倚杖看雨如窮秋。", "萬事不由人作計，我欲除愁唯一醉。", "此生已老復何求，五字但知公臭味。", "春風吹雨山澤晴，青山有約翁有情。", "故人官高少閑暇，可喚白鷗同此盟。"]'),
('59bfad34-637e-434e-abab-43e846fa1650','梅花爲風雨所殘三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','五更風雨各無端，留取殘枝與客看。',32,'全唐诗/poet.song.87000.json','["五更風雨各無端，留取殘枝與客看。", "何遜借花心欲折，玉奴愁雨曉應寒。"]'),
('c45d657b-805a-42dc-ae78-062bf66d6306','梅花爲風雨所殘三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','山西鐵面故將軍，新種梅花十里春。',32,'全唐诗/poet.song.87000.json','["山西鐵面故將軍，新種梅花十里春。", "此地數枝留不得，東風可是惡欺人。"]'),
('f28bd3e3-e42e-48ad-b047-7ad9e00de35e','梅花爲風雨所殘三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','先生舊日經行處，聞有寒枝笑曉林。',32,'全唐诗/poet.song.87000.json','["先生舊日經行處，聞有寒枝笑曉林。", "便倩東風吹雨去，急携藜杖與僧尋。"]'),
('2353459c-ff49-45f0-a1a5-35134ef596a9','梅盡一首','周紫芝','宋','宋诗','song-poetry','','[]','昔家大江南，沮洳不堪處。',132,'全唐诗/poet.song.87000.json','["昔家大江南，沮洳不堪處。", "五月梅子黄，江雲日成雨。", "頻年客東吳，蝸椽坐羈旅。", "墮鳶忽當前，海氣復如許。", "食無山鞠窮，爲病入腰膂。", "游鯈與争席，共此一洲渚。", "人生能幾何，生理亦良苦。", "今朝有奇事，兒童報佳語。", "送梅喜追餞，入伏寧傴僂。", "便當掛西窗，悠然望南浦。", "借風翻綠荷，分香度清暑。"]'),
('11058d4f-6ba0-4f76-a57e-9ebd9cde5e65','陳相之許惠近作久而未至雪中偶書二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','春意方回臘，梅花又滿枝。',48,'全唐诗/poet.song.87000.json','["春意方回臘，梅花又滿枝。", "自憐爲客久，頗恨得君遲。", "涉世身猶爾，攻愁酒若爲。", "人生俱昨夢，消遣可無詩。"]'),
('153568fe-2b71-4e91-9a7a-fed6174e228c','陳相之許惠近作久而未至雪中偶書二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','短策何由去，長鬚喚不來。',48,'全唐诗/poet.song.87000.json','["短策何由去，長鬚喚不來。", "詩今如此少，門欲爲誰開。", "净几塵飛盡，寒窗雪自堆。", "無人伴牢落，燈火送殘杯。"]'),
('0d5a94a0-63ea-4a4f-8ffb-fa7558f707fc','奉答相之再示兩詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','白髪劉郎在，無心唱竹枝。',48,'全唐诗/poet.song.87000.json','["白髪劉郎在，無心唱竹枝。", "倦游閑未得，見事老尤遲。", "與世知何用，求田便可爲。", "元龍人物勝，况有建安詩。"]'),
('ef75c7d6-2df0-4ffb-b565-b7e317af2baf','奉答相之再示兩詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','老愧才都盡，人愁雨不來。',48,'全唐诗/poet.song.87000.json','["老愧才都盡，人愁雨不來。", "酒樽無客把，詩卷爲君開。", "山色螺分翠，江濤雪擁堆。", "新篇慰愁眼，喜色動寒杯。"]'),
('9d278831-48e3-4fb6-93e7-bbabe7820442','次韻關子東湖上雜書四絕 清照庵','周紫芝','宋','宋诗','song-poetry','','[]','道人結屋在林邱，俗子何由得少留。',32,'全唐诗/poet.song.87000.json','["道人結屋在林邱，俗子何由得少留。", "一閉衡門三十載，爲公今過虎溪頭。"]'),
('f6867081-8e81-4a7e-924a-a2d240b03a39','次韻關子東湖上雜書四絕 壽星寺','周紫芝','宋','宋诗','song-poetry','','[]','上方重閣到雲天，一落天星今幾年。',32,'全唐诗/poet.song.87000.json','["上方重閣到雲天，一落天星今幾年。", "不見老坡寒碧句，滿林風玉自蒼然。"]'),
('71f0abfe-2a02-495b-be12-55f374c0d6fa','次韻關子東湖上雜書四絕 水荇','周紫芝','宋','宋诗','song-poetry','','[]','舊聞春草滿池塘，何事新題荇蘂黄。',32,'全唐诗/poet.song.87000.json','["舊聞春草滿池塘，何事新題荇蘂黄。", "寄語藕花從此去，不須滿意著紅粧。"]'),
('36f2bfd1-ef87-463c-8f69-f5cc3a62e7c6','次韻關子東湖上雜書四絕 子規','周紫芝','宋','宋诗','song-poetry','','[]','兩邊山木子規啼，不管還鄉客夢稀。',32,'全唐诗/poet.song.87000.json','["兩邊山木子規啼，不管還鄉客夢稀。", "應爲老翁推不去，故將好語勸人歸。"]'),
('495588d9-11f4-4d7c-bd6d-ff7e61649a43','再寄李司農二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','不作徽州夢，空吟楚水邊。',48,'全唐诗/poet.song.87000.json','["不作徽州夢，空吟楚水邊。", "倉皇相别日，歡喜得書年。", "客有誰投轄，詩應我執鞭。", "長安望歸日，消息幾時傳。"]'),
('52efb51a-1d3a-435a-b049-88d4f120ee92','再寄李司農二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','衰薄功名晚，羈棲歲月深。',48,'全唐诗/poet.song.87000.json','["衰薄功名晚，羈棲歲月深。", "篇章唯楚些，兒女盡吳音。", "見面知何日，從公話此心。", "時光肯相待，白髪已如林。"]'),
('d8cc2804-a585-47c2-80b2-109d432d4bbd','頃與徐美祖汪養源同遊杯渡道場余來錢塘而二君再遊以詩見寄','周紫芝','宋','宋诗','song-poetry','','[]','當年三士各清狂，下馬同尋古道場。',64,'全唐诗/poet.song.87000.json','["當年三士各清狂，下馬同尋古道場。", "人在諸峰朝著屐，天教我輩夜分床。", "勝遊已是成陳迹，晚路何堪更異鄉。", "聞道重來苦相憶，爲君日轉九廻腸。"]'),
('a7d728d7-b268-4d58-92f7-0db0ad7d46e6','苦筍','周紫芝','宋','宋诗','song-poetry','','[]','庾郎鮭菜不滿腹，三歲杯盤入吳俗。',160,'全唐诗/poet.song.87000.json','["庾郎鮭菜不滿腹，三歲杯盤入吳俗。", "江頭四月烏賊來，經日楊梅雨中熟。", "是時苦竹方生兒，錦綳時露駢頭玉。", "杭人嚇飯正要虎，日以千金換盈束。", "人莫不食鮮知味，妙理聽君論反覆。", "舌頭誰識苦中甜，今乃苦口後爲福。", "蔗中佳境甘似飴，厚味可人終腊毒。", "江南山多豈無此，苦甚何止秋荼酷。", "天公時爲餉饞人，雨洗風吹滿山谷。", "從今不敢料吳儂，但煮蝦蟆當粱肉。"]'),
('59338818-2281-4b4f-9cbf-8b8770958a97','和張元明食生荔子','周紫芝','宋','宋诗','song-poetry','','[]','五月麦秋閩嶺寒，嶺頭風雨荔子丹。',160,'全唐诗/poet.song.87000.json','["五月麦秋閩嶺寒，嶺頭風雨荔子丹。", "舊從圖畫見眉目，何曾生食知甘酸。", "天生尤物亦甚慳，路遠致之良復難。", "宮中妃子一破顔，猶須驛騎來長安。", "絳紗囊小欣乍識，晚上蘇臺醉瑤席。", "人如玉筍擘輕紅，詩似春雲驚坐客。", "書生饞相絕可憐，誦詩口角空流涎。", "何時遂作七閩客，日啖玉肌三百丸。", "猶勝窮愁杜陵老，暮年奔走巴山道。", "萬里瀘戎摘荔枝，一生辛苦無人知。"]'),
('16ae3e0e-63c1-4b92-82b8-d0c804f2bc42','將别湖居二首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔年嘗判武林丞，来伴西湖寺下僧。',32,'全唐诗/poet.song.87000.json','["昔年嘗判武林丞，来伴西湖寺下僧。", "又作移家新活計，却携行脚舊枯藤。"]'),
('97c9d841-8837-4847-ada2-b543df992b3e','將别湖居二首  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子湖邊一短窗，幾年和雨看湖光。',32,'全唐诗/poet.song.87000.json','["西子湖邊一短窗，幾年和雨看湖光。", "青山換得微官去，魚鳥應須笑漫郎。"]'),
('7c21b2ff-b57e-466d-9489-95de5a518589','與同舍郎觀潮分韻得還字一字江字三首一字江字爲坐客作  其一','周紫芝','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','人生如微塵，同一霄壤間。',156,'全唐诗/poet.song.87000.json','["人生如微塵，同一霄壤間。", "可笑蠛蠓眼，但窺甕中天。", "錢塘俯滄海，八月壯濤瀾。", "始疑疋練横，旋作萬馬翻。", "海門屹中開，方壺忽當前。", "不知何巨鰲，爲我戴三山。", "銀光射傑閣，玉筍垂朱欄。", "須臾擊飛雪，噴薄上簾顔。", "相見各驚顧，日暮殊未還。", "那知在空濛，但怪毛髪寒。", "平生雲夢胸，始信宇宙寛。", "安得凌雲手，大筆如脩椽。", "盡挽卷天浪，參差入豪端。"]'),
('3758ed59-6ee9-4770-b1ee-dc2aa536a349','與同舍郎觀潮分韻得還字一字江字三首一字江字爲坐客作  其二','周紫芝','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','烈風驚洪濤，浩蕩吹海立。',120,'全唐诗/poet.song.87000.json','["烈風驚洪濤，浩蕩吹海立。", "迅雷忽飜空，掩耳嗟不及。", "漢兵百萬騎，已奪秦關入。", "擊石驚倒流，勢若三峽急。", "滄波忽喧豗，衆目俱駭慄。", "人言海潮來，昔爲子胥屈。", "誰當語馮夷，四海今已一。", "王春會塗山，白玉執萬笏。", "江河及喬嶽，祠祀已咸秩。", "海神會當知，萬歲拱帝室。"]'),
('e56db887-ecb0-46d8-98aa-d0bffe51d4aa','與同舍郎觀潮分韻得還字一字江字三首一字江字爲坐客作  其三','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u94b1\u5858\u6c5f"]','神州古都會，有美東南邦。',96,'全唐诗/poet.song.87000.json','["神州古都會，有美東南邦。", "壯哉八月濤，卷地奔長江。", "驚濤裂巨石，洪鐘殷朝撞。", "萬瓦響飛雹，千艘碎舽艭。", "灧澦不足數，况乃峽與瀧。", "翩翩坐中客，才器俱無雙。", "九牛可逆拽，五鼎乃獨扛。", "詩成咄嗟頃，惡語徒喧哤。"]'),
('1f1215be-96dc-4e0b-994a-6cedd4eb5745','次韻徐美祖梅花','周紫芝','宋','宋诗','song-poetry','','[]','我得孤山已恨遲，水邊無復昔年枝。',64,'全唐诗/poet.song.87000.json','["我得孤山已恨遲，水邊無復昔年枝。", "花隨此老俱成夢，詩似徐郎今有誰。", "隴使醉将春作信，廣平應解玉爲肌。", "五更笑語香中意，只有羅浮曉月知。"]'),
('7c58612d-5cfb-4d0f-a291-ebf087768365','人日雨一首','周紫芝','宋','宋诗','song-poetry','','[]','王春雪三尺，人日雨一犁。',132,'全唐诗/poet.song.87000.json','["王春雪三尺，人日雨一犁。", "五種雖未入，二麥頗亦宜。", "人情豈不悦，天意似可期。", "官居著窮巷，睡味無人知。", "起焚石鼎烟，爛讀離騷詞。", "看雲生屋角，聽雨鳴空墀。", "綠水添清瑤，孤芳悦華姿。", "萬物有佳趣，吾生日已衰。", "貪癡速奇禍，安分傷寒饑。", "乘除理已定，智巧那得移。", "不如酌我酒，此事姑置之。"]'),
('1c4f548b-8822-4d81-b8f6-ade2fe772b23','次韻艾主管二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','三徑頻招客，羈懷可自寛。',48,'全唐诗/poet.song.87000.json','["三徑頻招客，羈懷可自寛。", "湖分一水近，窗納數峰寒。", "好句貧猶得，衰顔醉亦丹。", "官閑樂如許，何地更求安。"]'),
('03d8c1cb-36b6-476c-8453-ad9c62c1c8d2','次韻艾主管二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','病畏空緣淺，愁知醉境寛。',48,'全唐诗/poet.song.87000.json','["病畏空緣淺，愁知醉境寛。", "五窮空抱藝，六巧豈勝寒。", "鶴骨全憑杖，霜毛不受丹。", "春雲莫成雪，僵臥有袁安。"]'),
('f8aa0592-08be-42cc-9f1c-8783ff68fc7e','二月十四日過初師房','周紫芝','宋','宋诗','song-poetry','','[]','故國三年夢，青春二月餘。',48,'全唐诗/poet.song.87000.json','["故國三年夢，青春二月餘。", "閑尋窗窈窕，來伴客踟蹰。", "花倩風調護，愁應酒破除。", "老夫乘興罷，歸了讀殘書。"]'),
('6494743b-b2d4-4157-860f-aa2913475004','次韻李彥恢簡錢侍郎因叙將别之意','周紫芝','宋','宋诗','song-poetry','','[]','兩淮持莭記當年，奏計歸來雪滿顛。',64,'全唐诗/poet.song.87000.json','["兩淮持莭記當年，奏計歸來雪滿顛。", "應念故人今老矣，載瞻行旆只依然。", "欲知鴻雁劬勞日，便是鵷鸞咫尺天。", "况有金蘭在坡禁，一生交分豈輕捐。"]'),
('9d892bd3-dcba-48a8-8092-47a6c04382d4','次韻彦恢再示前作','周紫芝','宋','宋诗','song-poetry','','[]','此生難數絳人年，高位由來免疾顛。',64,'全唐诗/poet.song.87000.json','["此生難數絳人年，高位由來免疾顛。", "自笑晚途聊復爾，相逢雲路豈其然。", "歸心只欲開三徑，薄宦何由託二天。", "他日據鞍如可强，故人雖老未輕捐。"]'),
('3826e567-2fd0-441f-a85c-9ea7e0b7dcdb','次韻趙簽判用李漕韻見示','周紫芝','宋','宋诗','song-poetry','','[]','九陌塵中度歲年，不堪烏帽著華顛。',64,'全唐诗/poet.song.87000.json','["九陌塵中度歲年，不堪烏帽著華顛。", "名雖已愧周公瑾，詩或時參孟浩然。", "豈料晚途蓮幕客，肯來同醉玉壺天。", "人間富貴須公等，佩楪從今可盡捐。"]'),
('d805aa50-e703-48fb-a134-631f7bcd055a','彥恢被旨使京西将歸待次用前韻送别因呈鄉里親舊','周紫芝','宋','宋诗','song-poetry','','[]','知公直節自當年，終不留衣與大顛。',64,'全唐诗/poet.song.87000.json','["知公直節自當年，終不留衣與大顛。", "胸次已能呑夢澤，功名寧復愧燕然。", "登車莫厭塵吹帽，移棹應思水拍天。", "歸去交遊如問我，爲言百事老俱捐。"]'),
('f29277b6-0630-4842-a925-64835dc3ed7c','胡夫人出塵庵詩四首  其一','周紫芝','宋','宋诗','song-poetry','','[]','漫說丹砂乞轉精，安期瓜大幾時生。',32,'全唐诗/poet.song.87000.json','["漫說丹砂乞轉精，安期瓜大幾時生。", "會令方寸無荆棘，火棗交梨亦易成。"]'),
('b3377559-aafb-44b5-9c0e-96e9c49d8079','胡夫人出塵庵詩四首  其二','周紫芝','宋','宋诗','song-poetry','','[]','看著桃花兩度春，尚須香火奉高真。',32,'全唐诗/poet.song.87000.json','["看著桃花兩度春，尚須香火奉高真。", "世間安得無塵鏡，人似靈犀觧辟塵。"]'),
('f16c6dd5-e328-4601-bcec-a1a9763bb9ef','胡夫人出塵庵詩四首  其三','周紫芝','宋','宋诗','song-poetry','','[]','當日飛昇雲路賒，夫人原屬舊仙家。',32,'全唐诗/poet.song.87000.json','["當日飛昇雲路賒，夫人原屬舊仙家。", "莫將林下能詩女，輕比神仙萼綠華。"]'),
('39bbeee7-cda5-4cbc-8252-c9b9b55941d4','胡夫人出塵庵詩四首  其四','周紫芝','宋','宋诗','song-poetry','','[]','瑤池人摘幾番桃，月下猶吹弄玉簫。',32,'全唐诗/poet.song.87000.json','["瑤池人摘幾番桃，月下猶吹弄玉簫。", "爲病書符何日了，雲軿看即下丹霄。"]'),
('993f1efc-2526-4968-bb79-257da2229bcb','次韻君叙湖上偶作','周紫芝','宋','宋诗','song-poetry','','[]','政恐情須我輩鍾，畫船同載舞衣紅。',64,'全唐诗/poet.song.87000.json','["政恐情須我輩鍾，畫船同載舞衣紅。", "可憐燕子無人管，不忍桃花過眼空。", "客睡喜聽門剝啄，君詩來送玉丁東。", "何時却覓孤山路，共弔梅花樹下翁。"]'),
('9ce781a5-b13c-41bd-8016-b8fe5b28a039','次韻君叙雨中偶作','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春風作意惱春懷，更落殘紅上紫苔。',64,'全唐诗/poet.song.87000.json','["春風作意惱春懷，更落殘紅上紫苔。", "無限好詩飛得去，幾人今雨肯重來。", "夢回故國空千里，酒憶徴君共一杯。", "看取西湖天下勝，客愁應爲此時開。"]'),
('8a2e1315-34c1-4761-8e03-95b6d689c8d4','冷泉亭放閘  其一','周紫芝','宋','宋诗','song-poetry','','[]','呼猿洞口水潺潺，忽卷奔流下九天。',32,'全唐诗/poet.song.87000.json','["呼猿洞口水潺潺，忽卷奔流下九天。", "乞得少陵三峽句，爲君題作倒流泉。"]'),
('b88c5810-ebab-49dd-9820-bb8a0b6b55df','冷泉亭放閘  其二','周紫芝','宋','宋诗','song-poetry','','[]','萬里西興浦口潮，浪花真似海門高。',32,'全唐诗/poet.song.87000.json','["萬里西興浦口潮，浪花真似海門高。", "誰將一夜山中雨，喚作滄江八月濤。"]'),
('f9acf840-7c13-43ab-976e-adfb9007219a','西窗見榴花分韻得花字','周紫芝','宋','宋诗','song-poetry','','[]','青春苦難挽，白日良易斜。',120,'全唐诗/poet.song.87000.json','["青春苦難挽，白日良易斜。", "花飛尚滿砌，柳密驚藏鴉。", "寒窗忽當日，山崦知誰家。", "紅榴笑疏林，始著三兩花。", "繁陰護朱閣，芳姿奪明霞。", "頗憶少年日，千金醉繁華。", "當時石榴裙，六幅圍絳紗。", "美人隔秋水，相望天一涯。", "想像繫楚腰，依稀似丹葩。", "對花誰與論，搔首空歎嗟。"]'),
('cef1cb65-30cc-40dd-823b-eafe24e5afd2','次韻同舍四月十日迎駕二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','日來金闕麗蒼龍，風入宮牆展鹿葱。',32,'全唐诗/poet.song.87000.json','["日來金闕麗蒼龍，風入宮牆展鹿葱。", "夾道焚香迎步輦，兩班鳴玉從羣公。"]'),
('b67d3d4e-f114-4cfd-9d73-1bf2d2a4c0f3','次韻同舍四月十日迎駕二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','時平廊廟半夔龍，趙將何人說李葱。',32,'全唐诗/poet.song.87000.json','["時平廊廟半夔龍，趙將何人說李葱。", "一見黄麾識全仗，始知赤舄有三公。"]'),
('b46cae41-2ce1-412f-a39f-093fd04570f7','次韻艾主管四月十日迎駕','周紫芝','宋','宋诗','song-poetry','','[]','十年不見羽書馳，萬里風塵静九圍。',32,'全唐诗/poet.song.87000.json','["十年不見羽書馳，萬里風塵静九圍。", "又薦櫻桃入原廟，春來無事幾家肥。"]'),
('20ded16c-e6c5-4cc8-b855-c9830333e134','次韻庭藻天申節錫燕書事','周紫芝','宋','宋诗','song-poetry','','[]','千秋舞馬初登床，新歌樂府傳霓裳。',192,'全唐诗/poet.song.87000.json','["千秋舞馬初登床，新歌樂府傳霓裳。", "當時提封三萬里，人間何處無農桑。", "邇來重見太平日，侍臣復上開元觴。", "雲門一闋天樂奏，瑞獸三尺南金黄。", "師臣擁珮燕旨酒，虎臣杖節嚴秋霜。", "成功乃自師尚父，異姓不數汾陽王。", "紫皇萬歲壽明主，斗魁六宿來文昌。", "三呼往往出靈嶽，由漢以來無此祥。", "諸公自是列宿數，玉階合望重瞳光。", "聖朝御極日杲杲，風雨順序天蒼蒼。", "虞階已復罷干羽，漢郡會看開樂浪。", "小臣拜手亦稽首，願祝地久仍天長。"]'),
('82a89075-0e20-4023-895a-985956f42483','次韻庭藻再賦天申節錫燕書事','周紫芝','宋','宋诗','song-poetry','','[]','蓬萊殿角薰風凉，法宮無事垂衣裳。',192,'全唐诗/poet.song.88000.json','["蓬萊殿角薰風凉，法宮無事垂衣裳。", "人間樂奏萬斯曲，枝上日轉咸池桑。", "天皇初開紫府燕，御前催賜黄金觴。", "誰乘風雲依日月，臣有力牧君軒黄。", "望雲仰見天不遠，簪花莫厭鬢如霜。", "五風十雨自中國，語從重譯傳名王。", "年年五月熟荔子，又見北使朝連昌。", "聖君當宁占寶曆，太史執筆書殊祥。", "雲間雙闕日五色，下被四表同堯光。", "風姿矯矯華省郎，珩璜結佩鳴水蒼。", "但將兩耳聽韶濩，付與孺子歌滄浪。", "傳杯遙想水殿冷，畫鼓咽咽清晝長。"]'),
('8c7ae05b-ee3d-4b60-a77e-2ec6c33d7a5f','諸公約遊諸山而雨分韻得蓮字','周紫芝','宋','宋诗','song-poetry','','[]','華省繆通籍，羣公接蟬聯。',132,'全唐诗/poet.song.88000.json','["華省繆通籍，羣公接蟬聯。", "坐曹苦無事，笑語相周旋。", "蛛塵生印窠，雌黄入遺編。", "賜沐不反舍，環湖走層巔。", "况乃三神祠，仿彿在雲烟。", "蓐食戒明發，著鞭飛曉韉。", "白石望磊磊，跳珠忽濺濺。", "咫尺不得往，使我意惘然。", "誰當却豐隆，曠蕩開青天。", "同昇太華頂，共摘玉井蓮。", "斯盟可重尋，慎勿輕棄捐。"]'),
('3ec8e5b9-2528-4c9f-8817-ea6f73e0ae4d','次韻王興周齋宿省舍','周紫芝','宋','宋诗','song-poetry','','[]','念昔始觧事，結交少年場。',180,'全唐诗/poet.song.88000.json','["念昔始觧事，結交少年場。", "一生徒苦辛，兩鬢今成霜。", "頗亦恨晚歲，始得同舍郎。", "邂逅笑語間，仿彿芝蘭香。", "朝吟共棐几，暮歸霑餘觴。", "忽奉太室祠，共薦房俎羊。", "曉陪奉常班，瓊珮參翺翔。", "只今坐齋宮，夜雨誰對床。", "王事間何闊，咫尺遙相望。", "聊持鷓鴣椀，爲澆冰雪腸。", "五字忽鼎來，古錦翻詩囊。", "無力攻長城，有眼驚夜光。", "跂彼笑織女，不復成報章。", "何當畢祠事，共上南山岡。", "更約顔李蕭，一笑同徜徉。"]'),
('8d0975d0-9023-4dbb-8a2f-00a9bdac0212','次韻蘇君叙暑雨大有秋意','周紫芝','宋','宋诗','song-poetry','','[]','五月癡雲爛不收，麥風先借一天秋。',64,'全唐诗/poet.song.88000.json','["五月癡雲爛不收，麥風先借一天秋。", "聊煩細雨催幽句，更把新涼洗客愁。", "人物似君真楚楚，功名憐我亦悠悠。", "謾將無限思歸意，欲向回中著釣舟。"]'),
('27a54929-a1f5-4f60-ada0-0fc85ddb9e24','次韻艾主管觀僕楚詞贅說見貽','周紫芝','宋','宋诗','song-poetry','','[]','傳記區區考異同，文章空愧楚人功。',32,'全唐诗/poet.song.88000.json','["傳記區區考異同，文章空愧楚人功。", "窮年弄筆知何事，芸葉香中作蠧蟲。"]'),
('d7f95c80-6173-44d8-b94a-854e6db0ebb5','次韻袁時良司理二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','白頭身落亂書叢，粗遣殘年不記功。',32,'全唐诗/poet.song.88000.json','["白頭身落亂書叢，粗遣殘年不記功。", "乞得閑官歌楚些，始知君德被昆蟲。"]'),
('8cea456f-f7f1-413f-b62e-9eb3624bfbdb','次韻袁時良司理二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','人說篇章晚更雄，建安諸子未爲功。',32,'全唐诗/poet.song.88000.json','["人說篇章晚更雄，建安諸子未爲功。", "今朝春草傳新句，昨夜燈花綴玉蟲。"]'),
('2cf42f06-783e-4e90-a72f-d72971a19366','再酬艾主管袁司理二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','鼯鼠終成五技窮，老於文字苦無功。',32,'全唐诗/poet.song.88000.json','["鼯鼠終成五技窮，老於文字苦無功。", "謾將平日雕龍口，細爲離騷說豸蟲。"]'),
('fc24117b-8773-4841-aa33-fc2ce1e98faf','再酬艾主管袁司理二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','兩公才力可争雄，翰墨頻收戰勝功。',32,'全唐诗/poet.song.88000.json','["兩公才力可争雄，翰墨頻收戰勝功。", "笑我窮年辨烏舄，却將人事校鷄蟲。"]'),
('ae259e06-af49-4ebf-8daa-3ec866a2397a','孫耘老惠龍尾硯漆煙墨報以二詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','自喜新交得管城，政愁無地喚陶泓。',32,'全唐诗/poet.song.88000.json','["自喜新交得管城，政愁無地喚陶泓。", "孫郎不惜分龍尾，付與詩人了一生。"]'),
('7598f68c-4228-4972-8a1c-b42f961b0914','孫耘老惠龍尾硯漆煙墨報以二詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','詩翁無復思如泉，墨客能回漆作煙。',32,'全唐诗/poet.song.88000.json','["詩翁無復思如泉，墨客能回漆作煙。", "何意峥嶸四君子，肯來相伴一燈前。"]'),
('bd2cdfcc-4391-47fa-a6c6-d7e21faf93c7','今歲中秋無月閏八月十五日夜月色明甚二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','月欲離滄海，雲猶暗夕樓。',48,'全唐诗/poet.song.88000.json','["月欲離滄海，雲猶暗夕樓。", "天教雙病眼，重看後中秋。", "玉色依然在，霜華只自羞。", "一杯遙酹汝，容易莫西沈。"]'),
('05238954-2d09-46b8-9109-2370e0a2f036','今歲中秋無月閏八月十五日夜月色明甚二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','秋意關心切，蟾光見面難。',48,'全唐诗/poet.song.88000.json','["秋意關心切，蟾光見面難。", "欲成邀月飲，頗恨與誰看。", "天近瞻銀闕，雲空見玉盤。", "老夫渾不寐，歡喜一憑欄。"]'),
('49fb25d2-6ada-4a70-bb10-febe5bf2f43d','次韻庭藻秋懷三絕因以見招  其一','周紫芝','宋','宋诗','song-poetry','','[]','擬趁牛山九日杯，煩公催取菊花開。',32,'全唐诗/poet.song.88000.json','["擬趁牛山九日杯，煩公催取菊花開。", "青天有月無人喚，却喚樽前惡客來。"]'),
('c6d927ca-fca2-420f-848b-825f909cb8e7','次韻庭藻秋懷三絕因以見招  其二','周紫芝','宋','宋诗','song-poetry','','[]','山横鳥外白雲邊，酒滿秋風落帽前。',32,'全唐诗/poet.song.88000.json','["山横鳥外白雲邊，酒滿秋風落帽前。", "老子要詩那得句，湖天欲買不須錢。"]'),
('bf4a9020-d2a9-449e-8198-73e06885916c','次韻庭藻秋懷三絕因以見招  其三','周紫芝','宋','宋诗','song-poetry','','[]','不見元龍少日豪，還將萬事等秋毫。',32,'全唐诗/poet.song.88000.json','["不見元龍少日豪，還將萬事等秋毫。", "只今風味猶如許，醉看霜前斫兩螯。"]'),
('d5a4455f-0984-4b4c-9f0f-65d7d9137c34','奉酬陳彦育用庭藻韻示三詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','欲遣新愁入酒杯，好懷知復爲誰開。',32,'全唐诗/poet.song.88000.json','["欲遣新愁入酒杯，好懷知復爲誰開。", "此生憐我星星久，何事令君得得來。"]'),
('f9f27d98-0f46-4eed-89b6-c8c15ab03fad','奉酬陳彦育用庭藻韻示三詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','廣文貧甚坐無氈，白璧朝來忽滿前。',32,'全唐诗/poet.song.88000.json','["廣文貧甚坐無氈，白璧朝來忽滿前。", "但喜囊餘長吉句，絕勝家有窟郎錢。"]'),
('7c5bbf47-c564-45d2-8c08-e0f8299edc47','奉酬陳彦育用庭藻韻示三詩  其三','周紫芝','宋','宋诗','song-poetry','','[]','南徐隱士詩兄弟，君更眉間有白毫。',32,'全唐诗/poet.song.88000.json','["南徐隱士詩兄弟，君更眉間有白毫。", "一染函牛鼎中指，暮年方悔嚼空螯。"]'),
('d1e84d3c-b88e-4d65-892d-7dbc9533ec10','次韻庭藻觀潮','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u94b1\u5858\u6c5f"]','八月既望秋風高，羣飛海水催江濤。',160,'全唐诗/poet.song.88000.json','["八月既望秋風高，羣飛海水催江濤。", "水來中州八萬里，至吳乃折微傷豪。", "當日潮來如箭激，萬弩迎潮射鳴鏑。", "風吹海立猶至今，雪卷千堆濺青壁。", "人間有海詩有翁，健如駕浪長江風。", "詩成便可作圖畫，歲好莫漫占凶豐。", "坐中客怕噤不語，憑高下看馮夷舞。", "殘音到石未肯回，澎湃猶能作宮羽。", "人生快意難預謀，眼辜盛事心懷羞。", "老病無人喚我出，閉門枉度三中秋。"]'),
('af45e582-5837-4809-a9fc-4f6b97f1bf10','次韻庭藻再賦觀潮','周紫芝','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','海門白浪如山高，還從巨海驅洪濤。',160,'全唐诗/poet.song.88000.json','["海門白浪如山高，還從巨海驅洪濤。", "何人戲出此偉觀，撩公傑句争雄豪。", "詩成飛電欲争激，戰勝何甞費鋒鏑。", "更復盡出武庫兵，不念長卿家四壁。", "當時年少今老翁，愁將白髪吹秋風。", "來趁千人萬人出，尚記時節如元豐。", "袖手人知公作語，歌兒停歌復停舞。", "越山迎浪看潮頭，白玉傳觴急飛羽。", "胸中如公多廟謀，八珍未獻伊鼎羞。", "笑人欲買江邊宅，看潮飽度殘年秋。"]'),
('f50683a6-c97c-404e-ab1a-30ae5bca9d8e','次韻彭叔容','周紫芝','宋','宋诗','song-poetry','','[]','彭郎作詩調最高，語中起伏多波濤。',160,'全唐诗/poet.song.88000.json','["彭郎作詩調最高，語中起伏多波濤。", "維其有之是以似，千佛名經中一豪。", "潮從海來與山激，彭郎詩成疾飛鏑。", "詞鋒何止却千軍，脆敵何堪守堅壁。", "去年載酒呼衰翁，蕭蕭兩鬢吹江風。", "手持氂尾白玉柄，坐中風味王安豐。", "今年不出無一語，想像紅旌浪中舞。", "臥聽東來響怒濤，安得西飛有雙羽。", "晚歲莵裘誰與謀，有如此江真可羞。", "會待潮來復潮落，短蓑獨速吳江秋。"]'),
('a689d408-fd77-487d-88c3-0c8d14fc91df','次韻李宗丞秋懷二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','河朔三株樹，霜高不受侵。',48,'全唐诗/poet.song.88000.json','["河朔三株樹，霜高不受侵。", "日邊初識面，詩裏復論心。", "愁莫令知處，杯須略放深。", "弟兄俱絕唱，一世少知音。"]'),
('3758618d-8159-4bb3-9d44-17c7033a74ea','次韻李宗丞秋懷二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','身作三吴去，霜從兩鬢侵。',48,'全唐诗/poet.song.88000.json','["身作三吴去，霜從兩鬢侵。", "羈棲臨老日，牢落少年心。", "好句何曾得，清秋幾度深。", "越江憐久客，時送海潮音。"]'),
('2d44be22-aee2-496a-a763-e892beb91320','曉色','周紫芝','宋','宋诗','song-poetry','','[]','曉色明龍闕，金爐近御床。',48,'全唐诗/poet.song.88000.json','["曉色明龍闕，金爐近御床。", "黄簾猶卷月，清蹕已鳴霜。", "海宇無兵革，公師在廟堂。", "但聞宮樹鳥，日日囀朝陽。"]'),
('c6c8eb5f-0ae9-4fea-a8ed-4981b5c6ac7e','紹興丙寅歲當郊祀積雨彌月已而大雪前事之夕雪霽月出越翌日天宇開霽日色晏温天子乃躬祀於郊丘賦詩二十韻','周紫芝','宋','宋诗','song-poetry','','[]','寶曆三千歲，龍飛二十春。',240,'全唐诗/poet.song.88000.json','["寶曆三千歲，龍飛二十春。", "胡弓不窺月，塞馬自無塵。", "禮樂湮淪久，君臣制作新。", "誠心躬廟饗，大祀肅郊禋。", "密雪埋羣嶂，凝陰翳上旻。", "九枝騰曉日，萬騎出嚴宸。", "輦路晴沙輭，宮城宿霧勻。", "崇壇方肇造，蒼璧遂前陳。", "秀色霜明俎，華滋露濕裀。", "馨香登秬黍，繭栗薦黄犉。", "月引笙簫度，風傳贊祝頻。", "依稀望璇極，髣髴降天神。", "皎皎星垂象，沉沉夜嚮晨。", "一人宣玉册，百執奉朝紳。", "欲識蒼穹意，當知肸蠁臻。", "歷年綿聖祚，敷錫惠斯民。", "回駕蒼龍闕，旋軍羽衛屯。", "拜恩元老重，沛澤萬方均。", "盛世無遺典，中華有聖人。", "書生亦何幸，奔走綴祠臣。"]'),
('b8ab40d3-1ba0-4f5b-89f3-b93ef1988edc','次韻艾主管約同居酬唱','周紫芝','宋','宋诗','song-poetry','','[]','老年無句上詩壇，晚向荆州始識韓。',64,'全唐诗/poet.song.88000.json','["老年無句上詩壇，晚向荆州始識韓。", "馬歷險艱知足健，樹從黄落見根蟠。", "不妨論好同膠漆，已復書盟在肺肝。", "許我三冬共燈火，不須衝雨過蘇端。"]'),
('ac6d09ee-7d77-4286-89a5-69f40879d426','再次韻艾主管','周紫芝','宋','宋诗','song-poetry','','[]','艾侯人物似芝蘭，不數淮陰袴下韓。',64,'全唐诗/poet.song.88000.json','["艾侯人物似芝蘭，不數淮陰袴下韓。", "筆底波瀾驚浩渺，胸中書傳想縈蟠。", "厲施固自無妍醜，楚越何曾異膽肝。", "一笑相從亦何事，共看明月上雲端。"]'),
('5b825bc9-0f2e-4df3-973e-7fabf408b237','次韻蔡仲平梅花用玉局海南韻','周紫芝','宋','宋诗','song-poetry','','[]','老翁腸斷江南村，誰將楚些招歸魂。',128,'全唐诗/poet.song.88000.json','["老翁腸斷江南村，誰將楚些招歸魂。", "月明常憶看花處，斷橋流水天黄昏。", "一行作吏此事廢，日涉漫記柴桑園。", "天憐羈客老且病，玉琢妙語清而温。", "當時飽喫惠州飯，十年來負蠻鄉暾。", "花飛白雪颶欲起，瘴濕黄茅人閉門。", "爲公復誦海南句，寒窗掩卷凄無言。", "傷心起酹玉局老，夜半獨瀝鴟夷樽。"]'),
('aa374b1a-77ab-4e0d-ab43-0431495b09a1','次韻仲平雪中之作','周紫芝','宋','宋诗','song-poetry','','[]','少年何嘗屈此膝，自料一生能幾屐。',128,'全唐诗/poet.song.88000.json','["少年何嘗屈此膝，自料一生能幾屐。", "誰知臘月雪蔽空，三日衡門斷人迹。", "心知無事止坐詩，天觧窮人無乃力。", "故山欲放雪中梅，空恨此中無鐵石。", "中郎官熱亦怕寒，著意說窮聊作劇。", "北風吹酒天始愁，玉雪滿空心自懌。", "想君鹽絮方入詩，憐我鬢鬚同一色。", "山行安得趁驊騮，快踏瓊田四蹄疾。"]'),
('aec6e26c-5576-43e7-bb77-e71556ccadbd','時宰相生日樂府三首  其一','周紫芝','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','帝居七星中紫宸，黄金掣銷天開門。',224,'全唐诗/poet.song.88000.json','["帝居七星中紫宸，黄金掣銷天開門。", "中人傳詔不動塵，御府拜賜天爐芬。", "鬱金蘇合百和匀，雙虬鏤合盤雕紋。", "雲錦織帕勞天孫，金狻猊擁春空雲。", "流霞一酌千日醺，壽公遐齡天語温。", "朱絃白雪聲調新，洞庭之樂人皆聞。", "官家異禮尊帝臣，八師七友無此勳。", "聖賢一出五百歲，開闢以來能幾人。", "東方曼倩何足數，三食仙桃識王母。", "何當移植上林中，歲歲年年見花吐。", "溪上人家自一川，武陵邂逅非神仙。", "但令父老不識戰，人間何處無桃源。", "自從罷武得生活，垂髫小女皆能言。", "肯爲八方開壽域，廟堂政要公調元。"]'),
('bb4d2050-777d-46d0-a51d-d40f06c6f386','時宰相生日樂府三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','甘泉羽書久不至，六樂初成禮初備。',224,'全唐诗/poet.song.88000.json','["甘泉羽書久不至，六樂初成禮初備。", "萬兩黄金鑄景鍾，八級層壇築圓陛。", "侍臣曉入明光宮，彤庭暖日升曈曨。", "弦匏鼎俎耀前列，大聖制作垂無窮。", "太常爲旂玉爲輅，路穩沙平試天步。", "日邊風雨曉前收，夜半笙簫月中度。", "君臣有道道格天，五星同色三台圓。", "千官拜舞皇輿旋，青城路遠聞鳴鞭。", "黄麾羽葆識全仗，繡衣靁鼓鳴鈞天。", "羽林騎士如流水，未央宮闕明山川。", "千門萬戶不知數，盡捲簾幕瞻龍顔。", "道傍父老百歲許，醉倚春風自相語。", "昔年舊事一日新，廊廟功成不因武。", "羣生欲報知何緣，再拜願壽公千年。"]'),
('7acabcb1-14b9-407c-aacb-31ac0c9cce21','時宰相生日樂府三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','海上神仙不知數，無人觧說三山路。',208,'全唐诗/poet.song.88000.json','["海上神仙不知數，無人觧說三山路。", "舟中彷彿見霞裾，弱水波深不堪度。", "青天那得白日昇，仁能愛物功乃成。", "秦漢之君俱好武，枉從方士求長生。", "從來定亂必以戰，公以不戰爲中興。", "兩朝歲活數百萬，報公福祿知難名。", "只今潭潭開二府，富貴如山澤如雨。", "經殿時聞御幄香，日對清光接天語。", "歸來下馬復過庭，一德樓邊柳陰舞。", "天上頻移瑇瑁筵，瓊漿賜酒如流泉。", "盛事傳觀作圖畫，蕊珠何處求羣仙。", "皇天報德何時足，政恐天心似人欲。", "會從四世數五公，何止長年是公福。"]'),
('daad540f-8d3a-45e1-94bd-35e5db34a8fb','次韻蘇元藻對雪長句','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晚來風定雪初平，到手杯行不暫停。',64,'全唐诗/poet.song.88000.json','["晚來風定雪初平，到手杯行不暫停。", "夜色遠欺江月白，天花寧羡野梅馨。", "遙瞻玉闕心先喜，一見瑤林眼自青。", "回首西湖在何許，借君詩作遠山屏。"]'),
('953b92fd-2ac6-40c6-98da-042e4565d9f7','次韻艾主管歲除有感','周紫芝','宋','宋诗','song-poetry','','[]','藍尾先迎替臘春，流光依約似行雲。',64,'全唐诗/poet.song.88000.json','["藍尾先迎替臘春，流光依約似行雲。", "功名如夢日月晚，兒女滿前恩意勤。", "此夜自傾桑落酒，誰家政舞石榴裙。", "窮諳歲歲年年事，老坐奇奇怪怪文。"]'),
('500bfcb6-c9a3-40c0-a72e-c4eee58b9d21','雨中梅花猶有存者','周紫芝','宋','宋诗','song-poetry','','[]','江雨無情不管人，殘梅有韻故相親。',32,'全唐诗/poet.song.88000.json','["江雨無情不管人，殘梅有韻故相親。", "閉門無事仍無客，花作羞娥酒當春。"]'),
('792f8df1-136b-450e-8d45-25798e94dc3e','正月二十八日雪晴睡起  其一','周紫芝','宋','宋诗','song-poetry','','[]','沉水空濛睡欲醒，寒窗窈窕日初晴。',32,'全唐诗/poet.song.88000.json','["沉水空濛睡欲醒，寒窗窈窕日初晴。", "誰將昨夜堆簷雪，爲作空階滴雨聲。"]'),
('7b727d2a-891a-4006-9e9c-4424fcb6523e','正月二十八日雪晴睡起  其二','周紫芝','宋','宋诗','song-poetry','','[]','梅樹花邊日脚紅，鳥偷微暖囀東風。',32,'全唐诗/poet.song.88000.json','["梅樹花邊日脚紅，鳥偷微暖囀東風。", "寒窗喚起無人見，獨倚欄杆看雪融。"]'),
('45ce53c7-0c54-46c6-bc68-aeb96cd8ae0b','次韻余宅仲答陳先生','周紫芝','宋','宋诗','song-poetry','','[]','何曾留得守囊錢，長坐羈愁只斷編。',64,'全唐诗/poet.song.88000.json','["何曾留得守囊錢，長坐羈愁只斷編。", "我已自成窮活計，君猶爲看小行年。", "莫驚久客推難去，况有吟詩盡可傳。", "更看同升門下士，中興自昔要真賢。"]'),
('f32447d3-b8c2-4ee0-ad84-d3028285ea20','送錢端修侍郎二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','人間編削要研摩，富貴聲名不奈多。',64,'全唐诗/poet.song.88000.json','["人間編削要研摩，富貴聲名不奈多。", "似我豈容窺玉海，如公真合上鑾坡。", "依光日月心應在，回首湖山意若何。", "白鷺洲前留不得，却歸京洛擁鳴珂。"]'),
('7b1ca864-dde0-4c56-ba27-e61a7d794735','送錢端修侍郎二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚竊官囊五斗陳，笑談猶喜奉冠巾。',64,'全唐诗/poet.song.88000.json','["晚竊官囊五斗陳，笑談猶喜奉冠巾。", "望塵羅拜何曾觧，拄笏看山了不嗔。", "自古知心能有幾，如公厚德更何人。", "錦帆畫舸江邊路，愁看飛花落絮春。"]'),
('26716a59-7768-47b3-b33a-d5fd734fdfae','次韻陳先生','周紫芝','宋','宋诗','song-poetry','','[]','羞對湖山照病容，浮家全似陸龜蒙。',64,'全唐诗/poet.song.88000.json','["羞對湖山照病容，浮家全似陸龜蒙。", "掃除故里三年夢，邂逅幽人一笑同。", "酒會驅愁常恐薄，詩能窮我不須工。", "兩家好客今安有，爲作緇衣補國風。"]'),
('9ee0d15a-6242-496d-b5fe-f89df074c5d1','三月二日同游西湖諸公有詩次韻','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水繞青山寺，人携白玉觴。',48,'全唐诗/poet.song.88000.json','["水繞青山寺，人携白玉觴。", "晴春方爛漫，醉眼自微茫。", "舟穩欺風軟，杯深送日長。", "誰家載歌管，紅袖立斜陽。"]'),
('05dfe1a9-e226-4bae-a927-ccc77e670858','上巳日雨中熟睡二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','吳波越嶠翠争流，過盡殘春懶出遊。',32,'全唐诗/poet.song.88000.json','["吳波越嶠翠争流，過盡殘春懶出遊。", "花下看誰飛白馬，雨中憐我擁黄紬。"]'),
('994176a1-a93c-4376-99d4-329dd160114c','上巳日雨中熟睡二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','細數蘭亭歲月長，當年舊事久凄凉。',32,'全唐诗/poet.song.88000.json','["細數蘭亭歲月長，當年舊事久凄凉。", "但欣越女山前雨，暗入羅敷陌上桑。"]'),
('0f8117cd-7ee9-4ee1-acc3-0511f39af685','次韻孫子紹山礬','周紫芝','宋','宋诗','song-poetry','','[]','造化出尤物，餘芳若爲容。',120,'全唐诗/poet.song.88000.json','["造化出尤物，餘芳若爲容。", "遙知補陀山，天香落巖風。", "題評付大手，妙質煩天公。", "捧心陋嫫母，彼美唯孟庸。", "但恐兩無情，一笑花遂空。", "賴此絕世姿，墮君幽句中。", "相識苦恨晚，著語今復仝。", "願偕九畹蘭，結根永相從。", "可憐金錢花，亦薦白玉鍾。", "勿遣倡條滋，亂我風露叢。"]'),
('e8b81f7f-0150-4fe8-9e9e-49d8a3433b2b','趙觀察作齋名煙艇孫耘老作唐律相邀同賦乃次其韻','周紫芝','宋','宋诗','song-poetry','','[]','知君心本在滄洲，故掲寒齋作釣舟。',64,'全唐诗/poet.song.88000.json','["知君心本在滄洲，故掲寒齋作釣舟。", "已遣江湖頻入夢，便呼鷗鳥與同遊。", "浮驂未可追前事，畫舫猶堪擬勝流。", "笠澤有家歸未得，斷腸蘆葉荻花秋。"]'),
('7c35c3e3-38a6-4b24-bae6-f3b45effc6de','次韻方元相見寄','周紫芝','宋','宋诗','song-poetry','','[]','數椽元著亂山叢，强入天街踏軟紅。',64,'全唐诗/poet.song.88000.json','["數椽元著亂山叢，强入天街踏軟紅。", "老去只思青眼舊，詩來猶數白頭翁。", "身游吳越千山外，春落邯鄲一枕中。", "賴有可人俱在眼，舉杯惟欠與君同。"]'),
('2d258c8d-1264-4a93-8590-e75f76e8e1a7','睡餘飛絮滿庭有感而作是詩','周紫芝','宋','宋诗','song-poetry','','[]','春水綠波南浦路，兩岸誰栽楊柳樹。',64,'全唐诗/poet.song.88000.json','["春水綠波南浦路，兩岸誰栽楊柳樹。", "含桃熟盡未聞鶯，荷葉生時已飛絮。", "絮將春去不可回，人伴雲閑更須住。", "我亦隨君似落花，欲趁春風到何處。"]'),
('ecdf9bee-c8a5-4f89-bdab-20f708b406c5','酴醿小壺色香俱絕燈下戲題二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','芳條秀色净如霜，折得殘枝近筆床。',32,'全唐诗/poet.song.88000.json','["芳條秀色净如霜，折得殘枝近筆床。", "月冷燈青花欲睡，可憐虛度此時香。"]'),
('dd46deb9-c9c2-4337-a37a-bbfc2309f3c0','酴醿小壺色香俱絕燈下戲題二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','春事何時屬老人，好花知復爲誰分。',32,'全唐诗/poet.song.88000.json','["春事何時屬老人，好花知復爲誰分。", "何當碧玉壺中雪，飛作香羅髻上雲。"]'),
('7949c1d8-e0e0-466b-b8a2-c8dad396c9a1','次韻庭藻酴醿','周紫芝','宋','宋诗','song-poetry','','[]','憶昔在江國，屢醉酴醿春。',120,'全唐诗/poet.song.88000.json','["憶昔在江國，屢醉酴醿春。", "平生看花眼，老暗京洛塵。", "王城一見之，玉顔猶可珍。", "但恐花見憐，憔悴非昔人。", "是事姑且置，飲我樽中醇。", "幽姿不可名，清芬難具陳。", "誰登玉宸殿，與梅差等倫。", "山礬豈其弟，月姊當與親。", "頗笑凡質陋，始喜國色新。", "此論那可廢，此冤聊可伸。"]'),
('c3f39900-3224-4c6e-a73b-32d27036b362','效王建體二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','金獸分香賜老臣，全家望闕拜君恩。',32,'全唐诗/poet.song.88000.json','["金獸分香賜老臣，全家望闕拜君恩。", "教坊催樂排春燕，中使傳宣勸御樽。"]'),
('b4b3ff10-df84-4163-bd31-67cd8ceb0531','效王建體二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','日轉彤庭柳影移，微凉殿閣麦秋時。',32,'全唐诗/poet.song.88000.json','["日轉彤庭柳影移，微凉殿閣麦秋時。", "侍臣朝罷歸來晚，又見金盤賜荔枝。"]'),
('647e0239-d6e6-420c-a419-2da1a6ea144e','送馮遠猷使君  其一','周紫芝','宋','宋诗','song-poetry','','[]','雨露朝來下九天，左魚還得舊青氈。',64,'全唐诗/poet.song.88000.json','["雨露朝來下九天，左魚還得舊青氈。", "莫辭去國逾千里，猶勝爲郎動十年。", "客至何妨常有酒，民殘政自不須鞭。", "欲安遠俗惟無事，聖主休兵本息邊。"]'),
('bb1d3e5c-3c2d-49fa-b005-caf8b6a74d0d','送馮遠猷使君  其二','周紫芝','宋','宋诗','song-poetry','','[]','江上當年憶語離，相逢雖健鬢如絲。',64,'全唐诗/poet.song.88000.json','["江上當年憶語離，相逢雖健鬢如絲。", "心知涉世著幾屐，眼見承流換兩麾。", "臺閣異時須獻納，廟堂今日要招携。", "九江太守多仁政，此去知公得吏師。"]'),
('82b85ff1-8083-4301-ad63-92c35c709a87','涷雨行','周紫芝','宋','宋诗','song-poetry','','[]','五月江天未徂暑，日日江雲釀江雨。',211,'全唐诗/poet.song.88000.json','["五月江天未徂暑，日日江雲釀江雨。", "眼驚雪浪打秋濤，卷地風來雨如許。", "窮人賦屋纔一椽，茅茨零落仰見天。", "風棲不定夜未曉，旅食過午庖無烟。", "家無鞠窮病在腹，兩股重膇成蹣跚。", "麥雖黄落雨未止，雲欲漫亂風還顛。", "詩成有淚收不得，人生如此亦可憐。", "君不見章臺走馬張京兆，彈壓功成在談笑。", "不將鉤距作神明，自此長安無惡少。", "邇來持莭鎮七州，令行幕府如清秋。", "尚書地已八座貴，况復功方三輔優。", "應笑南來雙病鳥，千里依人作昏曉。", "鄧林有木暗如山，誰與安巢著林杪。"]'),
('4e28159b-7304-4eee-ac3c-b0a13023724d','閬州太守以桃竹卭杖二物遺余宅仲而宅仲出以示僕喜而作詩','周紫芝','宋','宋诗','song-poetry','','[]','萬里何嘗入巴蜀，少陵詩中識桃竹。',192,'全唐诗/poet.song.88000.json','["萬里何嘗入巴蜀，少陵詩中識桃竹。", "更言九節奉真仙，無乃卭山有遺族。", "平生二物幾到眼，誰與周旋慰幽獨。", "忽然渡海飛蒼龍，夭矯當前峙雙玉。", "江心石竹誇堅剛，摩挲紫焰生寒光。", "孤筇莭高不可及，外雖似曲中直方。", "閬州得此不敢藏，亟遣二士相扶將。", "余侯新佩太府章，六尺骯髒身健强。", "未須御府賜靈壽，行勒金狨朝未央。", "老人勃窣不足數，惟有泉石成膏肓。", "東吴自是山水窟，心雖欲往身未償。", "會須呼客共蠟屐，借君拄杖聊徜徉。"]'),
('fc8a64e5-5f05-4140-8745-617b7994b107','送袁司理歸天台  其一','周紫芝','宋','宋诗','song-poetry','','[]','長安少年郎，意傾裘馬中。',48,'全唐诗/poet.song.88000.json','["長安少年郎，意傾裘馬中。", "水鳧偶相值，蘭臭豈復同。", "誰令千金璧，照此白髪翁。", "得之非人力，捨去真天窮。"]'),
('bdc60831-82b6-49e0-b82e-e4753f7b068a','送袁司理歸天台  其二','周紫芝','宋','宋诗','song-poetry','','[]','五月畏塗暑，千里苦炎熇。',48,'全唐诗/poet.song.88000.json','["五月畏塗暑，千里苦炎熇。", "天台大士廬，妙境在寥廊。", "解鞍修淨供，茗椀應自瀹。", "安得從君遊，享此方外樂。"]'),
('778bf633-9751-4b27-b0a4-57db6a7d39a6','送袁司理歸天台  其三','周紫芝','宋','宋诗','song-poetry','','[]','妙哉揭陽君，文起八代衰。',48,'全唐诗/poet.song.88000.json','["妙哉揭陽君，文起八代衰。", "平生誦公文，手自不停披。", "只今老眼暗，刮膜無金篦。", "天台有巨刻，君其爲致之。"]'),
('6ae69346-12eb-4678-948a-d986724aa042','次韻文若與余相遇武林之作','周紫芝','宋','宋诗','song-poetry','','[]','南來衝雨著征衣，山下黄梅正熟時。',64,'全唐诗/poet.song.88000.json','["南來衝雨著征衣，山下黄梅正熟時。", "老大相逢真是夢，寒温以外只談詩。", "樂丞游宦聊因酒，陶令絃歌政坐饑。", "人物似君那易得，一蓑歸釣未應遲。"]'),
('a5e2ed2f-20ee-46e8-bcb3-4623a7fe08a8','送曾宏父守南徐','周紫芝','宋','宋诗','song-poetry','','[]','異時連佩漢魚符，兩奏殊庭報政書。',64,'全唐诗/poet.song.88000.json','["異時連佩漢魚符，兩奏殊庭報政書。", "黄屋要聞當日句，朱幡又擁使君車。", "風流舉世推前輩，文采須公侍禁廬。", "想得西樓未回首，已催尺一到南徐。"]'),
('67b50481-44b9-4417-a21f-3b6a0fc203fd','雨中對竹清甚效江西作六言一首','周紫芝','宋','宋诗','song-poetry','','[]','雨色挼藍潑黛，風莖戞玉鳴珂。',28,'全唐诗/poet.song.88000.json','["雨色挼藍潑黛，風莖戞玉鳴珂。", "不復作可人語，奈此數君子何。"]'),
('86d93700-13b6-4f1e-9bfc-25456a410816','次韻伯遠食楊梅十五韻','周紫芝','宋','宋诗','song-poetry','','[]','徐侯嗜吳梅，健啖殊未闌。',180,'全唐诗/poet.song.88000.json','["徐侯嗜吳梅，健啖殊未闌。", "喜氣入新詩，脱手如彈丸。", "遙想蒼玉枝，尚带白露漙。", "日食三百顆，語客疑誕謾。", "何妨携束書，常作東南官。", "掇彼南山粲，奉君一酌歡。", "南山有佳樹，采采何時殫。", "恨我無報章，上可追建安。", "誰知丹砂粒，亦滿黄金盤。", "回甘似蔗境，嚼齒餘詩酸。", "安得移此種，飛舟下驚湍。", "紅園奪朝霞，翠密回翔鸞。", "大勝萬里來，日曬中枯乾。", "歸期渺何許，且復同甘餐。", "調冰漬崖蜜，却暑資微寒。"]'),
('46cb8942-023e-4615-a865-84a32f6896cf','與叔容上天真臺題石壁用坐中語也','周紫芝','宋','宋诗','song-poetry','','[]','我生猶得問天真，净洗頻年馬上塵。',32,'全唐诗/poet.song.88000.json','["我生猶得問天真，净洗頻年馬上塵。", "此地何妨來著我，老僧原自不嗔人。"]'),
('93f67b88-c699-4764-bb42-ea93251258c6','天真寺白拒霜','周紫芝','宋','宋诗','song-poetry','','[]','天上登雲寺，人間白拒霜。',48,'全唐诗/poet.song.88000.json','["天上登雲寺，人間白拒霜。", "山僧方宴坐，魔女不施粧。", "玉色寧非韻，冰姿不受香。", "須當和月看，夜宿贊公房。"]'),
('63a782da-ddd6-4ca2-82b1-ebc167af7693','次韻仲平十八日觀潮','周紫芝','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','吳兒輕生命如線，赤脚翻身踏江練。',192,'全唐诗/poet.song.88000.json','["吳兒輕生命如線，赤脚翻身踏江練。", "南人慣看心不驚，北客平生眼希見。", "海上潮來雪不如，中郎詩成錦初爛。", "句法豈但窺澄江，壯士何從挽天漢。", "飛流濺沫不足論，萬壑千巖此爲冠。", "觧言越嶠翠摩空，歲與浪花爭隱見。", "我亦蒼顔閲九州，始問江神得奇玩。", "六年東望西興雲，歲月崩奔一飛箭。", "擬將匹練作江圖，歸與故人誇偉觀。", "倘從江海識波濤，分逐秋篷共流轉。", "試令海若語馮夷，慚色自應須滿面。", "誰當更草海潮篇，詞采風流付王翰。"]'),
('ceea0bfd-32d7-42e2-8c93-cbf8ec74380d','次韻相之木犀三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','木犀韻勝無人畫，合在詩翁阿堵中。',32,'全唐诗/poet.song.88000.json','["木犀韻勝無人畫，合在詩翁阿堵中。", "已寫幽姿入新句，莫將遺恨怨秋風。"]'),
('fc0cc557-c9bc-4326-8ec0-5a52c1a49a3f','次韻相之木犀三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','異時茅屋東邊樹，黄粟吹香趁水流。',32,'全唐诗/poet.song.88000.json','["異時茅屋東邊樹，黄粟吹香趁水流。", "旋買殘枝供燕几，爲誰辜負故山秋。"]'),
('3ea98fdb-f1b2-4b37-9eff-30ca36c20020','次韻相之木犀三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','蘭芳九畹是同流，薜荔江蘺格未優。',32,'全唐诗/poet.song.88000.json','["蘭芳九畹是同流，薜荔江蘺格未優。", "不爲巖花作佳傳，靈均空說楚江秋。"]'),
('9fb5d7e0-4a65-4748-8953-993a5d3fa1a6','雨後頓有秋意得小詩四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','九衢殘暑厭風埃，兩日陰雲遂不開。',32,'全唐诗/poet.song.88000.json','["九衢殘暑厭風埃，兩日陰雲遂不開。", "造物固應知客意，急催新雨送秋來。"]'),
('975e47c9-53ab-4718-89de-f4784aa42ec0','雨後頓有秋意得小詩四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','只今風露欲凋荷，前月牽牛已渡河。',32,'全唐诗/poet.song.88000.json','["只今風露欲凋荷，前月牽牛已渡河。", "絡緯獨知秋色晚，芭蕉添得雨聲多。"]'),
('139f4e7f-9cbc-4f6b-8ba5-657c81e86866','雨後頓有秋意得小詩四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','近曉殘更挽不留，窺簷起看月西流。',32,'全唐诗/poet.song.88000.json','["近曉殘更挽不留，窺簷起看月西流。", "空庭草樹俱無語，只有寒螿觧說愁。"]'),
('94b5eb80-6030-4b52-a49f-1d7c064ce37d','雨後頓有秋意得小詩四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','秋深時節在家鄉，憶得黄花未著霜。',32,'全唐诗/poet.song.88000.json','["秋深時節在家鄉，憶得黄花未著霜。", "故國不堪回首望，綠樽辜負五重陽。"]'),
('31c494fc-019a-47d6-8d7b-87dff9837639','次韻子紹雨中游北山禮白衣大士','周紫芝','宋','宋诗','song-poetry','','[]','官冷長如賜沐閑，門雖漫設晝常關。',64,'全唐诗/poet.song.88000.json','["官冷長如賜沐閑，門雖漫設晝常關。", "勞君馬上風前句，畫我湖邊雨外山。", "落木半巖秋色裏，曲欄千尺暮雲間。", "白衣大士應憐我，忍對高人不厚顔。"]'),
('0ebdd1eb-e6ae-4d23-aa7e-f11b29725345','九日陪李德儀兄弟游石屋','周紫芝','宋','宋诗','song-poetry','','[]','秋雲易雨秋日出，九日陰晴苦難測。',224,'全唐诗/poet.song.88000.json','["秋雲易雨秋日出，九日陰晴苦難測。", "氣如昨夜太暄妍，雲似今朝好天色。", "天公要渠作好語，著意安排費天力。", "重到孤峰最上頭，四年不見煙霞秋。", "吳山長與越山對，海水自隨江水流。", "江水相見只如此，老大豈知爾許愁。", "上山燃火入山腹，下山騎馬尋石屋。", "十八大士棲兩巖，共向山中禮尊宿。", "人言石縫泉作珠，却繞山根走鳴玉。", "珠泉得名固不虛，虎泉作酌不滿欲。", "山僧應復笑我曹，醉中泉石蒙譏嘲。", "涇渭分流正須爾，美惡賢愚亦如此。", "寧將鷄肋奉尊拳，莫著陽秋在皮裏。", "此語如何可便參，聊供山僧一笑喜。"]'),
('bf2a4bf6-47c2-4eeb-bce1-3e8286553ae1','題齊安新刻雪堂圖','周紫芝','宋','宋诗','song-poetry','','[]','名駒汗血久不聞，天遣兩蘇空馬羣。',192,'全唐诗/poet.song.88000.json','["名駒汗血久不聞，天遣兩蘇空馬羣。", "當時二十出西蜀，已說賈生能過秦。", "玉堂詞翰不起草，建隆以來能幾人。", "功名後世只忠讜，流落一生常苦辛。", "心知才大難爲用，小折波濤入嘲弄。", "偶結江邊一把茅，來作黄州十年夢。", "勸君慎勿剪柔柯，雪堂楊柳公親種。", "扁舟夜入赤壁江，手持杯酒酹周郎。", "酒醒月落賦已就，東方欲白天相將。", "邇來不知誰好事，盡寫公詩畫圖裏。", "短軸雖在人已亡，空著江波接天起。", "浮雲滅盡名不磨，千古長流似江水。"]'),
('e7f8e8a4-5fd3-46bd-ba32-1acbcbdb9391','次韻庭藻題寒林渭川二圖二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','煙水蒼茫認翠巒，寒林正在有無間。',32,'全唐诗/poet.song.88000.json','["煙水蒼茫認翠巒，寒林正在有無間。", "何人乞與并州剪，分取江南一半山。"]'),
('023dc635-f5cd-4eb7-8ea0-e0d5d9cbce76','次韻庭藻題寒林渭川二圖二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','煙梢零亂一川寒，換得天孫錦繡端。',32,'全唐诗/poet.song.88000.json','["煙梢零亂一川寒，換得天孫錦繡端。", "却憶東窗舊時竹，年來新筍盡成竿。"]'),
('4648dc38-673f-462c-950d-afdcb8b43b9d','送蘇元藻','周紫芝','宋','宋诗','song-poetry','','[]','蘇侯新拜外臺官，目送扁舟杳靄間。',64,'全唐诗/poet.song.88000.json','["蘇侯新拜外臺官，目送扁舟杳靄間。", "我亦漫同千里月，天教飽看七州山。", "欲知此别無窮恨，政坐相逢一笑閑。", "携酒却來湖上寺，不堪重對小孱顔。"]'),
('209d11ee-5a21-44e2-9f69-99663e4f3d26','游多福寺寺有佛牙光色殊勝而安定郡王墓在其後二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','吹盡青絲兩鬢華，旋裁林下老生涯。',32,'全唐诗/poet.song.88000.json','["吹盡青絲兩鬢華，旋裁林下老生涯。", "已携齋鉢分僧飯，更炷香雲禮佛牙。"]'),
('594e3714-74f5-4ce6-9bca-1a20ff00e705','游多福寺寺有佛牙光色殊勝而安定郡王墓在其後二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','千古風流挽不回，滿山秋葉寄餘哀。',32,'全唐诗/poet.song.88000.json','["千古風流挽不回，滿山秋葉寄餘哀。", "奏璈人去今何在，誰釀黄柑薦一杯。"]'),
('0753a551-7eba-4049-a0a6-66737880d48e','蠅館晨起效柳子厚','周紫芝','宋','宋诗','song-poetry','','[]','拂席坐清晨，幸脱塵事窘。',96,'全唐诗/poet.song.88000.json','["拂席坐清晨，幸脱塵事窘。", "閑焚石鼎熏，細誦華嚴品。", "從迷索初心，悟意嗟歲晚。", "庭蕪日延蔓，零落費鋤墾。", "何當略邊幅，乃或窮奥閫。", "餘年倘無恙，願就一廛隱。", "悠悠藉至言，廓廓窮妙本。", "會須師瞿曇，未足慕嵇阮。"]'),
('6828237c-aa67-4971-9fbe-ca2a0b0f8711','勅局晨入效柳子厚','周紫芝','宋','宋诗','song-poetry','','[]','朝陽下屋角，白露收莓苔。',120,'全唐诗/poet.song.88000.json','["朝陽下屋角，白露收莓苔。", "蒼黥知我至，鈎簾喚風回。", "破曉中庭花，時傍修竹開。", "事簡吏亦暇，日高官未來。", "取我囊中詩，炷香拂輕埃。", "所恨諸公間，疲駑愧非才。", "敲茶驚午夢，共瀹風前杯。", "支頤坐晝寂，細影移高槐。", "斯須各回鞭，跨鞍尚徘徊。", "雖非大三昧，亦號小蓬萊。"]'),
('11f03025-6b3e-472e-951c-538e36ab68af','寄題閻郎中家園亭四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','人間建業江山地，天上星郎水石居。',32,'全唐诗/poet.song.88000.json','["人間建業江山地，天上星郎水石居。", "擬作扣門看竹客，可能容我小踟蹰。"]'),
('d0865858-8c3c-407c-b56e-10631599ec20','寄題閻郎中家園亭四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','嶺上孤松欹落照，水中花島散餘霞。',32,'全唐诗/poet.song.88000.json','["嶺上孤松欹落照，水中花島散餘霞。", "人疑五柳先生宅，又似三堂刺史家。"]'),
('fbdd6f60-1413-47bc-ab9a-490c8ef89413','寄題閻郎中家園亭四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','築成凉榭初宜月，剪盡繁枝始見山。',32,'全唐诗/poet.song.88000.json','["築成凉榭初宜月，剪盡繁枝始見山。", "天亦料公閑未得，故教幽事頗相關。"]'),
('1acc7cd9-993f-41b9-84b7-8164854cd5a1','寄題閻郎中家園亭四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','屬玉雙飛下綠蒲，小溪分水照林廬。',32,'全唐诗/poet.song.88000.json','["屬玉雙飛下綠蒲，小溪分水照林廬。", "疏泉漫作江湖意，不種封君萬尾魚。"]'),
('740b63ca-988b-48ab-adb0-987d82b72526','相之庭藻邀賦齊氏赤芝詩','周紫芝','宋','宋诗','song-poetry','','[]','歸雁亭空劍戟場，天教人物發幽光。',64,'全唐诗/poet.song.88000.json','["歸雁亭空劍戟場，天教人物發幽光。", "書傳父祖人猶說，名到仍雲澤轉長。", "朱草只今應有譜，紫蘭何處不聞香。", "我無筆下芝房曲，付與南宮二省郎。"]'),
('9e871993-0231-4df2-9a49-7e71923a8990','九月十六日示內二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','又見黄花日，清觴且對飛。',48,'全唐诗/poet.song.88000.json','["又見黄花日，清觴且對飛。", "白頭夫婦少，無事笑談稀。", "官小何時去，家貧幾日肥。", "更須煩德曜，相伴老殘暉。"]'),
('35a66bf7-24a6-465d-a442-da3b9a2841be','九月十六日示內二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','小閣秋風冷，青燈病眼昏。',48,'全唐诗/poet.song.88000.json','["小閣秋風冷，青燈病眼昏。", "酒重斟壽醆，兒喜有雙親。", "書種吾家事，郎曹汝舊門。", "人生唯老健，餘合付乾坤。"]'),
('7cafbf2d-454f-441b-ad26-2554c899f8c6','木魚歌和碧巖子','周紫芝','宋','宋诗','song-poetry','','[]','秋蟾欲落霜滿屋，道人懸魚擊刳木。',64,'全唐诗/poet.song.88000.json','["秋蟾欲落霜滿屋，道人懸魚擊刳木。", "誰將發發水邊聲，驚斷齁齁鼻中曲。", "此生自是在家僧，便恐箇中緣已熟。", "安得華鯨吼夜廊，去趁雲堂五更粥。"]'),
('83999aa8-ddc2-427f-acb7-ba08fe0888c8','劉蘄州見和木魚歌再賦二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','秋雨平欺玉川屋，向曉寒窗風撼木。',64,'全唐诗/poet.song.88000.json','["秋雨平欺玉川屋，向曉寒窗風撼木。", "道人閑作木魚歌，使君肯和無絃曲。", "枯魚剝啄渠自鳴，客夢依稀我方熟。", "此身安得在蘄州，去覓君家咄嗟粥。"]'),
('31d2583c-d114-4f8e-ae63-44a29ac51a1c','劉蘄州見和木魚歌再賦二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','五更木魚鳴繞屋，喚起烏衣曉登木。',64,'全唐诗/poet.song.88000.json','["五更木魚鳴繞屋，喚起烏衣曉登木。", "敲殘千疊萬疊聲，亂盡長清短清曲。", "天邊孤月猶復明，世上黄粱欲炊熟。", "老人雖起亦何營，但飲南窗一杯粥。"]'),
('04a58f0e-663f-43f8-9637-c583d7b9446e','碧巖子作詩爲小兒求紋褓戲作三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','近來聞道得明珠，丹鳳今年第幾雛。',32,'全唐诗/poet.song.88000.json','["近來聞道得明珠，丹鳳今年第幾雛。", "會遣夢中分赤錦，不妨衣上有天吴。"]'),
('9d5b96c7-b8fa-4ecc-a46a-afe188c1eb9d','碧巖子作詩爲小兒求紋褓戲作三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','逸驥忽生千里馬，新詩來乞百家衣。',32,'全唐诗/poet.song.88000.json','["逸驥忽生千里馬，新詩來乞百家衣。", "老夫安得天孫段，只有羊裘坐釣磯。"]'),
('276821b2-58c2-4657-aa9d-4044b4ab34f7','碧巖子作詩爲小兒求紋褓戲作三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','舊來人說陳驚坐，真有詩如孟浩然。',32,'全唐诗/poet.song.88000.json','["舊來人說陳驚坐，真有詩如孟浩然。", "莫厭敲門覓紋褓，此翁衣鉢要渠傳。"]'),
('cc2a8fa8-ba72-499d-a779-b3b2221be9fe','次韻庭藻與陳相之李子至定尋梅之約見示','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u897f\u6e56"]','西湖三見青春面，無人共醉山間梅。',144,'全唐诗/poet.song.88000.json','["西湖三見青春面，無人共醉山間梅。", "晚逢詩老看古雅，如入周廟觀山罍。", "我所思兮在何許，昔望長江隔淮楚。", "三月春前始識君，倚杖看花聽君語。", "我今欲赴同襟期，老情可得如年時。", "清歡既少飲不足，枯膓欲盡詩應遲。", "衣冠此地多佳客，相逢四海無南北。", "天將此樂付公等，一枝方訪春消息。", "老夫老矣何能爲，折花夢作春山歸。"]'),
('e8ab1d30-cc1c-4bb7-b71e-82cb62ff4fae','次韻庭藻折梅懷周秀實','周紫芝','宋','宋诗','song-poetry','','[]','風流掃地難挽回，二老人物似蘇梅。',144,'全唐诗/poet.song.88000.json','["風流掃地難挽回，二老人物似蘇梅。", "時從花底飲落雪，醉臥沙頭雙玉罍。", "平時交分心相許，晚歲相思各秦楚。", "孤山籬落固依然，縱有此花無此語。", "周郎别去當有期，歸來不復如瓜時。", "天應知客頗有恨，花亦憶君尚未遲。", "我游東吳身是客，夢到江南與江北。", "安得馬背如孤鴻，萬里從君聊一息。", "只今春草還萋萋，會須急喚王孫歸。"]'),
('5138d971-1708-42f9-92d6-07c965259a10','次韻庭藻追記去歲與余游西湖舟中聞火而歸','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漫郎移舟入小回，醉著幅巾歌落梅。',144,'全唐诗/poet.song.88000.json','["漫郎移舟入小回，醉著幅巾歌落梅。", "老夫但倚紫藤杖，袖手恥看黄金罍。", "忽漫相逢遽如許，醉後高談俱楚楚。", "百尺君臥元龍樓，醇酎我羞公瑾語。", "從來悲樂難預期，人生快意能幾時。", "紅光屬漢勢未已，短艇掠水歸嫌遲。", "只今俱是京塵客，君居巷南我巷北。", "天寒饑餓不出門，遣騎時來問消息。", "江邊久客知何爲，白頭拾遺徒步歸。"]'),
('54736eee-17f5-4ff1-b9b0-022d87be9af3','蔚齋','周紫芝','宋','宋诗','song-poetry','','[]','山雲未成雨，斂藏方寸間。',144,'全唐诗/poet.song.88000.json','["山雲未成雨，斂藏方寸間。", "會當不崇朝，一雨膏人寰。", "人言隱霧豹，依約在南山。", "試從管中窺，何止見一斑。", "人生患無才，富貴天豈慳。", "二士偉人物，萬里來間關。", "行陳治安策，遂拜咫尺顔。", "豈容十里湖，長吟對煙鬟。", "願君如鸞鵠，摩霄共追攀。", "雲出豹亦變，何止銅與綸。", "舉首望長途，分當落榛菅。", "鵬飛君方高，鳥倦我亦還。"]'),
('d29e34b3-9bab-4599-b4d6-151cfbde8310','次韻庭藻讀少陵集  其一','周紫芝','宋','宋诗','song-poetry','','[]','李杜文章萬丈高，就中詩律少陵豪。',32,'全唐诗/poet.song.88000.json','["李杜文章萬丈高，就中詩律少陵豪。", "風流自是渠家事，奴僕從來可命騷。"]'),
('c9dbed57-3bb5-48e6-aca0-184b9470d8af','次韻庭藻讀少陵集  其二','周紫芝','宋','宋诗','song-poetry','','[]','濯錦江頭可一杯，碧鷄坊口草堂開。',32,'全唐诗/poet.song.88000.json','["濯錦江頭可一杯，碧鷄坊口草堂開。", "十年劍外無相識，黄四娘家幾度來。"]'),
('44fc7b14-db2a-4964-b60a-d2ad8d8daeb8','次韻庭藻讀少陵集  其三','周紫芝','宋','宋诗','song-poetry','','[]','玉燭初調大曆年，先生偶脱萬兵前。',32,'全唐诗/poet.song.88000.json','["玉燭初調大曆年，先生偶脱萬兵前。", "誰教早獻千金賦，可得看囊更有錢。"]'),
('d4ba2e3d-da2c-4b36-b312-5f5c490734bf','睡餘賦東牆雪竹','周紫芝','宋','宋诗','song-poetry','','[]','飽食枕方便，過午茶未杵。',96,'全唐诗/poet.song.88000.json','["飽食枕方便，過午茶未杵。", "撥火理殘香，倚窗翻故楮。", "尋我東牆隅，枝筇散腰膂。", "朔風寒蕭蕭，修竹静楚楚。", "枝頭雪猶在，秀色乃如許。", "竹固不受寒，豈但不受暑。", "老翁日日來，相期伴君語。", "誰能與俗人，昵昵作兒女。"]'),
('8ca95feb-7a35-49fc-84e0-e0b746cd2457','章彦漙决獄五羊歸登鬰孤臺得東坡石刻見遺報以小詩','周紫芝','宋','宋诗','song-poetry','','[]','一見蒼碑眼自開，便疑身在鬰孤臺。',32,'全唐诗/poet.song.88000.json','["一見蒼碑眼自開，便疑身在鬰孤臺。", "可憐决獄章廷尉，不带將軍薏苡來。"]'),
('fef13e2a-195b-41dd-a7a3-a169a397e549','四聖觀後山亭','周紫芝','宋','宋诗','song-poetry','','[]','附山結真祠，朱門照湖水。',120,'全唐诗/poet.song.88000.json','["附山結真祠，朱門照湖水。", "湖流中入池，秀色歸净几。", "風簾邃旌幢，神衛森劍履。", "清芬宿華殿，瑞霧蒙玉扆。", "仿彿還神京，想像輪奐美。", "祈年開新宮，祝釐奉天子。", "良辰復難會，歲暮得斯喜。", "况乃清樾中，飛樓見千里。", "雲車倘可乘，吾事良已矣。", "當賦遠遊篇，未可回屐齒。"]'),
('edf8f2c6-4068-441f-97ec-f7d8884b52b9','太一宮成奏告禮畢秦樞密有詩示秘閣次韻一首三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','聖主均休錫庶民，親祠遙望屬車塵。',64,'全唐诗/poet.song.88000.json','["聖主均休錫庶民，親祠遙望屬車塵。", "雲旗欲下精誠格，絳闕初成制作新。", "肅肅衣冠嚴祀事，雝雝簫鼓降明神。", "椒漿一酌能多少，散作人間萬國春。"]'),
('29f00363-5ffb-4a1b-96f9-af413f41fa00','太一宮成奏告禮畢秦樞密有詩示秘閣次韻一首三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','漢家何事築通天，漫費當年九府錢。',32,'全唐诗/poet.song.88000.json','["漢家何事築通天，漫費當年九府錢。", "躋世本期開壽域，祝釐端合報長年。"]'),
('cd307d85-b530-4c10-9fd6-d74f1e5b1025','太一宮成奏告禮畢秦樞密有詩示秘閣次韻一首三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','玉帛新祠太一神，廟堂生育轉洪鈞。',32,'全唐诗/poet.song.88000.json','["玉帛新祠太一神，廟堂生育轉洪鈞。", "侍臣俱從甘泉駕，萬世何人繼後塵。"]'),
('920249cc-da66-424e-9e07-c6cbb6d30990','太一宮成奏告禮畢秦樞密有詩示秘閣次韻一首三絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','至治非關黍稷香，可須巫覡降殊祥。',32,'全唐诗/poet.song.88000.json','["至治非關黍稷香，可須巫覡降殊祥。", "公今重草周公頌，不和東皇第一章。"]'),
('b2b4c3e1-b760-4b17-b143-5e233bdb205f','次韻伯遠梅花','周紫芝','宋','宋诗','song-poetry','','[]','徐侯頓朱墨，豈復知花時。',72,'全唐诗/poet.song.88000.json','["徐侯頓朱墨，豈復知花時。", "美人忽含笑，臨鏡窺漣漪。", "朝來摩兩眼，喜作雲霧披。", "須煩春草句，詠此玉雪枝。", "小窗惜無人，共賞林下姿。", "毛褚二三子，亦足相遨嬉。"]'),
('51e7ce2b-96c4-4fe2-8fb1-6933ddc428e8','立春三絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','暖風融雪晴方好，春意催年老自悲。',32,'全唐诗/poet.song.88000.json','["暖風融雪晴方好，春意催年老自悲。", "故國未歸空有夢，梅花欲動又題詩。"]'),
('bce6e50b-e124-48d1-9d4c-5c1a95173cd5','立春三絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','地下青風欲到時，土牛何得觧先知。',32,'全唐诗/poet.song.88000.json','["地下青風欲到時，土牛何得觧先知。", "牆邊雪裏梅花樹，已借清香入舊枝。"]'),
('68248457-6785-4a01-be83-ab033968aa28','立春三絕句  其三','周紫芝','宋','宋诗','song-poetry','','[]','多病誰憐澤國人，眼明羞見綵幡新。',32,'全唐诗/poet.song.88000.json','["多病誰憐澤國人，眼明羞見綵幡新。", "滿傾吳地千鍾酒，細說長安六度春。"]'),
('9411329c-5bc2-41d0-8f9e-2f0631a33ced','再賦立春效王建三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','蒼龍闕角曉光明，日近彤庭瑞霧温。',32,'全唐诗/poet.song.88000.json','["蒼龍闕角曉光明，日近彤庭瑞霧温。", "殿下百官猶未入，閣門催引謝春幡。"]'),
('0f69d07e-a33a-478d-9404-b249871efbab','再賦立春效王建三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','御溝冰暖欲生渦，律管灰飛氣自和。',32,'全唐诗/poet.song.88000.json','["御溝冰暖欲生渦，律管灰飛氣自和。", "已進玉堂春帖子，六宮無事笑聲多。"]'),
('8edcd1e8-c7fa-4088-a7c6-92b65d24603d','再賦立春效王建三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','聖明天子見昇平，二紀頒春下禁庭。',32,'全唐诗/poet.song.88000.json','["聖明天子見昇平，二紀頒春下禁庭。", "今歲御前争進表，明年七十賀慈寧。"]'),
('997dbf91-70f2-4d28-b5b7-3f282aa25145','七閩山中竹皆有實多至萬斛民賴以食歲且不饑作樂府短歌以紀異事將以俟採詩者擇焉蓋詩人之職也','周紫芝','宋','宋诗','song-poetry','','[]','七閩山中地不足，往往連山暗脩竹。',160,'全唐诗/poet.song.88000.json','["七閩山中地不足，往往連山暗脩竹。", "今年是處生竹花，竹米登囷日千斛。", "大家炊飯餉田夫，小家作糜饑飫腹。", "官雖賦田無上地，民不扶犁得中熟。", "福唐太守不敢藏，青版成囊獻黄屋。", "黔黎鼓腹慰天心，宣付汗青書日錄。", "山中父老雪滿頭，何曾眼見天雨粟。", "漫將葆旅屬珠星，誰問廟堂調玉燭。", "人言丹鳯餐竹實，玉粒先來自山谷。", "會見雙飛入建章，萬年枝並看鸞宿。"]'),
('45748a2b-dc11-4b55-822e-ebcc99ca2280','奉和黄文若贈刁文叔','周紫芝','宋','宋诗','song-poetry','','[]','昔日風流守，流傳父老知。',48,'全唐诗/poet.song.88000.json','["昔日風流守，流傳父老知。", "諸孫今若此，天意了無疑。", "醉裏開愁眼，燈前得近詩。", "聞名真已久，識面更何時。"]'),
('44fb7b36-037b-4cb9-8b40-642e7e6dc311','次韻文若贈黄叔魚','周紫芝','宋','宋诗','song-poetry','','[]','倦客愁如許，他鄉歲屢更。',48,'全唐诗/poet.song.88000.json','["倦客愁如許，他鄉歲屢更。", "衰顔人共笑，遺恨老難平。", "我欲隨歸夢，君誰共月明。", "嗣宗賢叔姪，况有各才名。"]'),
('829883bb-44ec-4df2-8231-0a378f6562ca','曉枕不寐書所感三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','昔年殘夢曉初回，花上啼禽近小齋。',32,'全唐诗/poet.song.88000.json','["昔年殘夢曉初回，花上啼禽近小齋。", "可笑只今春夢裏，五更欹枕聽籠街。"]'),
('beeeb3cc-9b22-4904-984e-1b56267e5553','曉枕不寐書所感三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','南市津頭憶買船，花姑溪上釣晴煙。',32,'全唐诗/poet.song.88000.json','["南市津頭憶買船，花姑溪上釣晴煙。", "老來安得孤篷夜，横枕蓑衣聽雨眠。"]'),
('30b31c0d-fd6d-4223-9f6a-abc8989f28bc','曉枕不寐書所感三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','白髪心知萬事休，力耕猶欲種春疇。',32,'全唐诗/poet.song.88000.json','["白髪心知萬事休，力耕猶欲種春疇。", "五更臥聽雞催曉，殘月開門起飯牛。"]'),
('1b96f7de-538b-45e7-bacf-31ae73fd461c','晚霽欲歸三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','雨後兒童喜欲顛，老翁不出自欣然。',32,'全唐诗/poet.song.88000.json','["雨後兒童喜欲顛，老翁不出自欣然。", "晴天霽色渾無用，只乞斜陽了斷編。"]'),
('7f29152a-8253-45d9-9078-919a7b5f86f9','晚霽欲歸三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','花樹窗前睡足時，斜陽忽到雨邊枝。',32,'全唐诗/poet.song.88000.json','["花樹窗前睡足時，斜陽忽到雨邊枝。", "白頭可笑閑居士，又寫春晴入小詩。"]'),
('f4ef4bae-ee72-4362-9777-560d041ab86a','晚霽欲歸三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','印顆初封馬在庭，杖藜猶傍竹邊行。',32,'全唐诗/poet.song.88000.json','["印顆初封馬在庭，杖藜猶傍竹邊行。", "老兵莫漫催人去，且聽幽禽說晚晴。"]'),
('d350d7c6-219c-4abe-99c2-f9d7d133cc56','分雙魚箋贈徐伯遠','周紫芝','宋','宋诗','song-poetry','','[]','水底雙魚不上鈎，粉金翻樣滑如流。',32,'全唐诗/poet.song.88000.json','["水底雙魚不上鈎，粉金翻樣滑如流。", "我無三昧詩中手，乞與君脩五鳯樓。"]'),
('bb5ec13e-1095-4ee0-851a-41cc887e61ac','次韻戴文舉陳季陵見索故稿','周紫芝','宋','宋诗','song-poetry','','[]','短兵無力可交綏，强敵當前敢出奇。',64,'全唐诗/poet.song.88000.json','["短兵無力可交綏，强敵當前敢出奇。", "况我龍鍾臨老日，值君三五少年時。", "擬將衝雪騎驢句，換取看花走馬詩。", "病思誰能更搜索，但拳雙臂作支頤。"]'),
('fb1b9418-3d5d-47a5-bc11-c2d3730fd413','送文若歸嘉禾二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','烏帽猶衝九陌塵，扁舟誰釣兩溪春。',64,'全唐诗/poet.song.88000.json','["烏帽猶衝九陌塵，扁舟誰釣兩溪春。", "久憑歸夢尋香國，忽喜清樽對故人。", "滿眼窮愁嗟我老，此生交舊獨君真。", "華亭一水無多地，細作來書莫厭頻。"]'),
('ff0cbede-cc09-45f0-92c8-1fc25d0e2ab8','送文若歸嘉禾二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','將軍十載半鳴珂，才武憐君中異科。',64,'全唐诗/poet.song.88000.json','["將軍十載半鳴珂，才武憐君中異科。", "但把長吟作回雪，不妨瀕海看熬波。", "方愁隻影身如寄，便買扁舟意若何。", "一别應須五年事，好詩從此爲誰哦。"]'),
('aa36a080-e15e-4351-842d-896f3d8d3e80','西湖詞二首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳中小女結煙鬟，自打青腰唱採蓮。',32,'全唐诗/poet.song.88000.json','["吳中小女結煙鬟，自打青腰唱採蓮。", "欲趁歌聲過南浦，藕花深處不通船。"]'),
('5afe4c80-4186-427b-bb85-1bd0a281a100','西湖詞二首  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖天無盡月如霜，露濕荷花别是香。',32,'全唐诗/poet.song.88000.json','["湖天無盡月如霜，露濕荷花别是香。", "何處漁郎觧吹笛，並頭驚起兩鴛鴦。"]'),
('46e53ba7-4c74-4d8a-b153-260755edad11','次韻吕仁父十九日朝謁初自宮南門','周紫芝','宋','宋诗','song-poetry','','[]','未央宮闕轉光風，誰識蕭何第一功。',64,'全唐诗/poet.song.88000.json','["未央宮闕轉光風，誰識蕭何第一功。", "禁殿潮連銀海闊，御樓霞似赤城紅。", "舊來雙舄飛翻處，今在春秋贊祝中。", "自此翔麟駕君輦，試從紫陌看方瞳。"]'),
('36ed48c0-2601-4b78-967d-6a62df6c4e96','月中與兒曹露坐二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','葛巾藤杖竹方牀，旋掃花陰坐晚凉。',32,'全唐诗/poet.song.88000.json','["葛巾藤杖竹方牀，旋掃花陰坐晚凉。", "兒小但隨翁看月，夜長誰念客思鄉。"]'),
('e43bfc49-8e7e-49cb-a309-c7953248a466','月中與兒曹露坐二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','客去無人與對牀，風微聊借月爲凉。',32,'全唐诗/poet.song.88000.json','["客去無人與對牀，風微聊借月爲凉。", "杯中小友多情甚，勾引衰翁入醉鄉。"]'),
('e7c3c537-77c1-445b-9b9c-189436927dd7','罌粟將成','周紫芝','宋','宋诗','song-poetry','','[]','庾郎十飯九不肉，家無斗儲飯不足。',147,'全唐诗/poet.song.88000.json','["庾郎十飯九不肉，家無斗儲飯不足。", "窮兒朝來忽乍富，牆下千罌俱有粟。", "只今錦爛花争妍，想見雲翻釡初熟。", "一飲醍醐生玉池，再飲沆瀣充朝饑。", "味雖似淡中實美，暖能扶老甘歸脾。", "黄粱歲割一萬斛，謾飼穀伯如猪肥。", "君不見蛾眉仙人家海涯，自種紫芋羮蹲鴟。", "尚說人間無此味，天酥酡固不可知。", "願借東坡玉糁句，題作此窗罌粟詩。"]'),
('bdd016b1-810d-4ca4-b518-e6c62d614d89','小兒燈下讀細書戲作','周紫芝','宋','宋诗','song-poetry','','[]','一生青白强錙銖，老眼昏昏亦廢書。',64,'全唐诗/poet.song.88000.json','["一生青白强錙銖，老眼昏昏亦廢書。", "長劍竟辜真事業，短檠空照舊蟲魚。", "臨風忘酒殊妨事，隔霧看花不管渠。", "猶與蠅頭較多寡，小兒曹合戒前車。"]'),
('03e63e83-153d-42a5-827c-44e800f16529','次韻鮑仲山官居臨大池傍鮑題以協趣取謝宣城所謂後協滄洲趣之句也','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','參軍詩古清而臞，清瑤繞屋分西湖。',128,'全唐诗/poet.song.88000.json','["參軍詩古清而臞，清瑤繞屋分西湖。", "長安城中開八陌，心知此地人皆無。", "草閣波平少傍舍，臥看晴沙鳥飛下。", "眼無公事兒自癡，句有澄江官頗暇。", "吾生已老心懷羞，爲饑索米亦有求。", "聞君稍動謝守趣，令我轉憶江南洲。", "詩成况復終少味，五字故堅不知畏。", "可憐未識故將軍，應似當年灞陵尉。"]'),
('6b859674-753e-4edd-9714-ea892182334b','次韻仲山再示協趣韻','周紫芝','宋','宋诗','song-poetry','','[]','青衫老吏骨亦臞，身游魏闕心江湖。',128,'全唐诗/poet.song.88000.json','["青衫老吏骨亦臞，身游魏闕心江湖。", "眼看白髪不勝數，夢繞故鄉何日無。", "况我携家得官舍，背水開門故牆下。", "不見湖光意闕然，欲喚歸舟心未暇。", "一聞羞處令人羞，人生如此當何求。", "春動飛來屬玉起，無人貌得河中洲。", "我生嚼蠟元無味，鮑謝詩高心獨畏。", "西風長怨草蟲秋，自笑酸寒溧陽尉。"]'),
('26da9ed5-a733-480c-9d39-798a7fe9e074','次韻仲平喜雨二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','旱欲流金水欲裂，百千火聚作此熱。',64,'全唐诗/poet.song.88000.json','["旱欲流金水欲裂，百千火聚作此熱。", "秋風忽送雨一犁，應念田夫汗流血。", "廟堂調燭隨弛張，五色線補虞帝裳。", "書生擬作豐年頌，臨窗弄筆鬢如霜。"]'),
('b6d6fd83-eb79-4239-b448-980efc3e15d2','次韻仲平喜雨二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','田作何郎炊餅裂，飲冰不救中腸熱。',64,'全唐诗/poet.song.88000.json','["田作何郎炊餅裂，飲冰不救中腸熱。", "千山雲路鳥欲飛，六月行人駒汗血。", "風師偃旆那復張，雷師鞭雨沾帷裳。", "雨中仿彿雲子香，行看玉粒秋飽霜。"]'),
('cb352075-884e-4656-a0e9-08017470a19e','題蔡仲平博士行田記唱詩軸二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','當年車騎兩聯翩，來按鍾陵水復田。',32,'全唐诗/poet.song.88000.json','["當年車騎兩聯翩，來按鍾陵水復田。", "可但癡兒了公事，尚餘詩思入風煙。"]'),
('023a65a4-128e-47a2-9520-2a9d5526ed41','題蔡仲平博士行田記唱詩軸二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','令君頗似太邱賢，水旱憂君記昔年。',32,'全唐诗/poet.song.88000.json','["令君頗似太邱賢，水旱憂君記昔年。", "父老猶能談舊事，想隨佳句共流傳。"]'),
('7513e27c-10ed-4c79-b272-371ceb6eb8cc','次韻孫子紹判院喜雨之作','周紫芝','宋','宋诗','song-poetry','','[]','豐隆欲鞭車，風伯不借便。',144,'全唐诗/poet.song.88000.json','["豐隆欲鞭車，風伯不借便。", "我欲訟風伯，雲意亦復變。", "帝命誰敢遲，民事那可緩。", "油雲始膚寸，崇朝忽瀰漫。", "深憂軫淵衷，凍雨洗霜霰。", "知誰挽銀河，傾瀉落天半。", "喜氣同雨來，孫郎語良健。", "應憐占籍者，就食免流轉。", "天子坐法宮，斯民樂芳甸。", "雲山倘可尋，野水不辭亂。", "幽人得新凉，妙作寄三嘆。", "君鋒不可當，我復那能殿。"]'),
('df8a3c3f-a4ad-4f3b-b225-e36a45d5c162','錢塘初見黄爵','周紫芝','宋','宋诗','song-poetry','','[]','儂家大江東，黄爵家江西。',175,'全唐诗/poet.song.88000.json','["儂家大江東，黄爵家江西。", "江東黄爵不忍喫，江西黄爵賤如泥。", "赤罌封口上有印，白綿臥酒中含脂。", "君不見浯口漫郎真漫仕，萬事平生不如意。", "一囊紅粟不一咽，千里苞苴誰復寄。", "有時鮭菜念故鄉，并刀落膾思飽霜。", "青龜未堪聊入俗，黄爵那知亦渡江。", "時平漫說爾可咀，擊鮮誰遣今得嘗。", "殘杯欲盡客欲去，臛雁烹魚豈論此。", "酒聞風味不可名，惟有此郎難著句。", "九原誰喚儋耳翁，添入當年老饕賦。"]'),
('8ada491a-48bc-4fb3-816f-3f85ac8755cb','花次元嘯齋','周紫芝','宋','宋诗','song-poetry','','[]','手種琅玕歲已成，要聽風雨近窗鳴。',64,'全唐诗/poet.song.88000.json','["手種琅玕歲已成，要聽風雨近窗鳴。", "戲將落月千尋影，幻作長離半嶺聲。", "蕙帳夢殘秋雨急，錦囊詩了夜燈清。", "便須寫入朱弦曲，安用能回越石兵。"]'),
('e6399480-9a42-4a26-afbf-49cb4a6d3d79','七月二十日秘閣曝書二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','芸香時近曝書筵，縹帙緗囊得縱觀。',32,'全唐诗/poet.song.88000.json','["芸香時近曝書筵，縹帙緗囊得縱觀。", "不是聖時修故事，豈知藏室有清官。"]'),
('f6095366-e80c-479b-8b49-21885a49bc9e','七月二十日秘閣曝書二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','香羅剪帕金描鳯，紅字排方玉作籖。',32,'全唐诗/poet.song.88000.json','["香羅剪帕金描鳯，紅字排方玉作籖。", "身到蓬山瞻御墨，眼驚奎宿射珠簾。"]'),
('e93b596c-cd27-49a0-a3fd-54bd7bc69c09','題徐季功畫墨梅木犀二首六言  其一','周紫芝','宋','宋诗','song-poetry','','[]','夜色無人能畫，徐郎挽上寒枝。',28,'全唐诗/poet.song.88000.json','["夜色無人能畫，徐郎挽上寒枝。", "仿彿孤山盡處，黄昏月到花時。"]'),
('4861ed4c-7181-4afe-90ed-9243c4c873d3','題徐季功畫墨梅木犀二首六言  其二','周紫芝','宋','宋诗','song-poetry','','[]','細雨欲催秋晚，幽花已著寒枝。',28,'全唐诗/poet.song.88000.json','["細雨欲催秋晚，幽花已著寒枝。", "似我江南九月，西風馬上歸時。"]'),
('fb6132cc-f80b-46c0-ace6-79bf97f2d4de','題徐季功畫二古木二首六言  其一','周紫芝','宋','宋诗','song-poetry','','[]','千尺龍蛇夭矯，半山風雨憑陵。',28,'全唐诗/poet.song.88000.json','["千尺龍蛇夭矯，半山風雨憑陵。", "誰爲梅花賦手，能回古木寒藤。"]'),
('aa3f0b1c-4619-4440-822a-6cf3155ad784','題徐季功畫二古木二首六言  其二','周紫芝','宋','宋诗','song-poetry','','[]','何處千年雙榦，未嫌雪虐風饕。',28,'全唐诗/poet.song.88000.json','["何處千年雙榦，未嫌雪虐風饕。", "楚士兩龔介潔，孤竹二子清高。"]'),
('44ac0253-c01e-458d-a6df-e2c05ebba4be','剪蘆藩出木犀二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','小窗幽絕爲誰通，分得清陰落坐中。',32,'全唐诗/poet.song.88000.json','["小窗幽絕爲誰通，分得清陰落坐中。", "可笑森嚴木居士，肯来相伴竹坡翁。"]'),
('ff1d0b09-1605-4869-adb6-4ec44638815f','剪蘆藩出木犀二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','特地移藩喚木犀，眼明初見歲寒枝。',32,'全唐诗/poet.song.88000.json','["特地移藩喚木犀，眼明初見歲寒枝。", "臨風想像香來處，不到黄昏滿樹時。"]'),
('67187a2a-d727-4dbd-a183-34c55c59b342','題王季共蓬齋','周紫芝','宋','宋诗','song-poetry','','[]','小結茅廬寄一椽，夜燈聊與客周旋。',64,'全唐诗/poet.song.88000.json','["小結茅廬寄一椽，夜燈聊與客周旋。", "聞知急雨來何處，題作蓬齋亦偶然。", "政欲搔君江上寄，莫嫌驚我醉中眠。", "老翁辜負漁竿久，何日煙蓑上釣船。"]'),
('37be6f80-d97d-49ba-b3bc-c4bff966fd5c','次韻子紹游壽星寺寒碧軒','周紫芝','宋','宋诗','song-poetry','','[]','好竹連山萬壑青，落星天近接飛甍。',64,'全唐诗/poet.song.88000.json','["好竹連山萬壑青，落星天近接飛甍。", "流盃共把人須勝，風玉相看眼倍明。", "故老舊遊雲已散，孫郎長嘯鳯重鳴。", "閑來却倚朱欄看，蒼雪依然入句清。"]'),
('3cf3570f-3fad-4e8d-9df7-ca7095b28cf3','别方桐川','周紫芝','宋','宋诗','song-poetry','','[]','一麾投老始專城，共理聊煩助聖明。',64,'全唐诗/poet.song.88000.json','["一麾投老始專城，共理聊煩助聖明。", "欲識斯民元不病，要知循吏本無聲。", "官閑莫道州如斗，客滿何妨飲似鯨。", "它日桐川樓下酒，會須分與故人傾。"]'),
('08c07989-d96f-4032-91e7-8d4ee588c623','秋懷二首示陳李二省曹  其一','周紫芝','宋','宋诗','song-poetry','','[]','客枕難禁夜，醨樽不觧愁。',48,'全唐诗/poet.song.88000.json','["客枕難禁夜，醨樽不觧愁。", "秋聲歸草樹，霜力到衣裘。", "依約江南夢，留連海畔州。", "君休問新句，只有大刀頭。"]'),
('ce841432-6101-4936-92f3-95aa50749e6a','秋懷二首示陳李二省曹  其二','周紫芝','宋','宋诗','song-poetry','','[]','細數平生舊，誰人到白頭。',48,'全唐诗/poet.song.88000.json','["細數平生舊，誰人到白頭。", "飄零無藉在，生死任羈愁。", "太白今詩伯，元龍昔勝流。", "吾衰已如許，何得奉君遊。"]'),
('dccbbf0f-f62b-41b9-b31e-fe98d56f9c05','次韻李郎中休日不出二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','文昌不作吏曹忙，賜沐歸來日更長。',64,'全唐诗/poet.song.88000.json','["文昌不作吏曹忙，賜沐歸來日更長。", "青士寒生庭下雨，木奴香借樹頭霜。", "喚回短夢知何事，尋得新詩又夕陽。", "遙想南窗卷疏箔，起看雙鷺入鵷行。"]'),
('9ceae65c-1464-494e-bcf8-36bdb08a2b54','次韻李郎中休日不出二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','簿領癡兒作底忙，閑中得味獨君長。',64,'全唐诗/poet.song.88000.json','["簿領癡兒作底忙，閑中得味獨君長。", "登臨莫負山如玉，歲月還成鬢作霜。", "誰把酒澆陶靖節，天將詩付沈東陽。", "明朝湖上看雙璧，兄弟聯鑣作雁行。"]'),
('2a55a36e-321c-45a7-84e9-a19f5a4ea7d0','次韻楊吉老秋懷古風','周紫芝','宋','宋诗','song-poetry','','[]','相思復相思，一别遽如許。',96,'全唐诗/poet.song.88000.json','["相思復相思，一别遽如許。", "相望隔參商，相期邈秦楚。", "遡洄願從之，道路長且阻。", "道阻不足憂，歲暮心獨苦。", "踏車繰絲娘，頭緒幾千縷。", "寒螿聲酸嘶，入我肺與腑。", "自我之來思，悠悠六寒暑。", "賴此同社郎，清風生玉麈。"]'),
('5637270b-4f7f-411e-9a2e-49bf0589667a','送馮清叟使虜三首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上盡西湖幾翠峰，偶依征驛度邊風。',32,'全唐诗/poet.song.88000.json','["上盡西湖幾翠峰，偶依征驛度邊風。", "遙知載酒尋山句，盡入彎弓落雁中。"]'),
('eea16993-6617-4fc4-b6b5-5eee17c0b596','送馮清叟使虜三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','君王慈儉不臨戎，國好長因漢使通。',32,'全唐诗/poet.song.88000.json','["君王慈儉不臨戎，國好長因漢使通。", "遙想南歸寒已盡，榆關草色正春風。"]'),
('8e0627b6-65eb-4ac2-99da-367b55d073ce','送馮清叟使虜三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','黄雲朔雪馬凌兢，去踏河邊六尺冰。',32,'全唐诗/poet.song.88000.json','["黄雲朔雪馬凌兢，去踏河邊六尺冰。", "博望封侯君亦喜，歸來洗眼看飛騰。"]'),
('23748fd4-d24f-460c-9d87-dc48bc8710e0','實錄院與道山隔牆堂後修竹僕飲餘必曳杖婆娑其下時聞奉常閲樂之聲故詩中有雲韶之語','周紫芝','宋','宋诗','song-poetry','','[]','風條無葉自蕭騷，玉立修篁不受凋。',64,'全唐诗/poet.song.88000.json','["風條無葉自蕭騷，玉立修篁不受凋。", "咫尺蓬瀛横雪觀，依稀絲竹度雲韶。", "天憐人老悲雙鬢，官似僧閑占一寮。", "日日杖藜摩飽腹，未知何以答清朝。"]'),
('f3d1d630-5e99-4b6d-8ad3-6043ea4d6305','次韻王參猷用前韻見寄','周紫芝','宋','宋诗','song-poetry','','[]','文字何當僕命騷，餘年雖在鬢全凋。',64,'全唐诗/poet.song.88000.json','["文字何當僕命騷，餘年雖在鬢全凋。", "元無舊曲能三歎，爲借新章作九韶。", "千里奉祠猶去國，一官何地可同僚。", "吹噓直上青天去，誰挽斯人入聖朝。"]'),
('052a2407-3541-4350-9ef8-ffe826a31425','謝曾使君惠丹邱集','周紫芝','宋','宋诗','song-poetry','','[]','舊說江西一派禪，公家得法自當年。',64,'全唐诗/poet.song.88000.json','["舊說江西一派禪，公家得法自當年。", "回風流雪何人似，寶鉢天衣幾世傳。", "後學安能窺制作，老夫猶喜奉周旋。", "寒窗讀罷無人語，只有燈花欲鬬妍。"]'),
('51d0967f-6da3-4de5-b783-6b1dcdfda71a','題吸川亭','周紫芝','宋','宋诗','song-poetry','','[]','三峰擁中州，二水俱北匯。',96,'全唐诗/poet.song.88000.json','["三峰擁中州，二水俱北匯。", "狀如吸川鯨，有屋負鯨背。", "主人頌酒德，量與劉阮對。", "會令百川流，入我三尺喙。", "回視瓮間人，無乃真鼠輩。", "天風駕鯨波，風静水可愛。", "想當持翠螺，時依太白酹。", "尔曹固何知，此意有君在。"]'),
('ada055af-4ce7-469f-a9d2-40fabf45d30f','題控鼇亭','周紫芝','宋','宋诗','song-poetry','','[]','神仙邈何許，仿彿在中天。',96,'全唐诗/poet.song.88000.json','["神仙邈何許，仿彿在中天。", "弱水不可渡，况乃風引船。", "六鼇戴三山，來此知何年。", "上有百尺樓，縹緲翔飛煙。", "平生持巨釣，一舉遂可連。", "以手控六鼇，于此相周旋。", "可恨世俗眼，未識方壺仙。", "絕境不可到，望望空惘然。"]'),
('d6408c0f-aa53-44df-ad01-252841e3b26a','次韻劉尉雪後東岡尋梅','周紫芝','宋','宋诗','song-poetry','','[]','雪壓東岡千樹梅，忍寒誰肯爲渠來。',32,'全唐诗/poet.song.88000.json','["雪壓東岡千樹梅，忍寒誰肯爲渠來。", "却愁花底人如玉，羞得南枝不敢開。"]'),
('742fa170-405e-4705-af5b-91117a3e8fff','贈趙德莊','周紫芝','宋','宋诗','song-poetry','','[]','赫奕宗枝秀，棱層玉樹新。',48,'全唐诗/poet.song.88000.json','["赫奕宗枝秀，棱層玉樹新。", "相逢又殘歲，話酒幾青春。", "病不妨詩否，家應入望頻。", "少寛歸去日，去别易愁人。"]'),
('2aa08290-06e7-4877-9520-aa2d73700bbf','時宰生日詩三十絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','從來建鄴是王都，天産臯夔爲帝謨。',32,'全唐诗/poet.song.88000.json','["從來建鄴是王都，天産臯夔爲帝謨。", "可笑晉人無眼目，渡江惟笑見夷吾。"]'),
('e3a20259-cf82-4d5f-a277-c54849f826dc','時宰生日詩三十絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','繡袞貂冠舉世榮，陰功難報本難名。',32,'全唐诗/poet.song.88000.json','["繡袞貂冠舉世榮，陰功難報本難名。", "令公清德流無盡，依舊秦淮繞故城。"]'),
('186a6387-bd96-486a-b03b-3bc4a7b38476','時宰生日詩三十絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','秦漢功由百戰成，廟堂何代不談兵。',32,'全唐诗/poet.song.88000.json','["秦漢功由百戰成，廟堂何代不談兵。", "凌烟閣上從頭數，誰觧垂衣致太平。"]'),
('58b2f3f0-ccc8-44e0-be9e-e6a97d0b163c','時宰生日詩三十絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','向來諸將各雲屯，一折渠魁世自分。',32,'全唐诗/poet.song.88000.json','["向來諸將各雲屯，一折渠魁世自分。", "但見鷹揚稱尚父，不聞跋扈有將軍。"]'),
('51336768-199d-4e77-bd01-427103e7184c','時宰生日詩三十絕  其五','周紫芝','宋','宋诗','song-poetry','','[]','梯山蕃使入疆頻，歲捧瑤觴奉至尊。',32,'全唐诗/poet.song.88000.json','["梯山蕃使入疆頻，歲捧瑤觴奉至尊。", "申觀萬年方祝聖，王春正月更朝元。"]'),
('76aa3dd9-af1e-4681-97b9-de3dc678d84f','時宰生日詩三十絕  其六','周紫芝','宋','宋诗','song-poetry','','[]','萬騎邊聲久不聞，蓬萊宮殿日長春。',32,'全唐诗/poet.song.88000.json','["萬騎邊聲久不聞，蓬萊宮殿日長春。", "君王勤儉無行樂，閑作宸奎賜近臣。"]'),
('b24862fe-89e8-47b2-9e64-e02bc78501f7','時宰生日詩三十絕  其七','周紫芝','宋','宋诗','song-poetry','','[]','黄帕蒙韉御坐來，臨戎久不按龍媒。',32,'全唐诗/poet.song.88000.json','["黄帕蒙韉御坐來，臨戎久不按龍媒。", "內前沙路平如掌，玉輅觀成試輦回。"]'),
('b2a8e6a2-abe9-46c0-bdfd-1b374460dd56','時宰生日詩三十絕  其八','周紫芝','宋','宋诗','song-poetry','','[]','紹興天子聖神孫，明道宣和典故存。',32,'全唐诗/poet.song.88000.json','["紹興天子聖神孫，明道宣和典故存。", "曾與諸生迎御輦，又瞻青耜載耕根。"]'),
('a12a9ba6-85de-4533-8160-6c71d8a9f529','時宰生日詩三十絕  其九','周紫芝','宋','宋诗','song-poetry','','[]','當年輪奐落成均，法駕天臨近至尊。',32,'全唐诗/poet.song.88000.json','["當年輪奐落成均，法駕天臨近至尊。", "萬國儒生瞻聖化，一聲清蹕在橋門。"]'),
('b8b1ab2a-71dc-48dd-afe4-0ad40fb88558','時宰生日詩三十絕  其一○','周紫芝','宋','宋诗','song-poetry','','[]','天祿初成幸翠華，隆儒恩意日尤加。',32,'全唐诗/poet.song.88000.json','["天祿初成幸翠華，隆儒恩意日尤加。", "只應東壁圖書府，便是瀛洲學士家。"]'),
('80327a50-32a2-40ad-94ce-611c1f5c5fef','時宰生日詩三十絕  其一一','周紫芝','宋','宋诗','song-poetry','','[]','仲春之日祀高禖，天仗親臨曉霧開。',32,'全唐诗/poet.song.88000.json','["仲春之日祀高禖，天仗親臨曉霧開。", "壇下百官稱賀了，鈞天聲裏带花回。"]'),
('1cd89080-7a0e-4fd1-b2e5-5d1835d0cd70','時宰生日詩三十絕  其一二','周紫芝','宋','宋诗','song-poetry','','[]','雙闕傍邊是玉津，禁園花柳一時新。',32,'全唐诗/poet.song.88000.json','["雙闕傍邊是玉津，禁園花柳一時新。", "樂游原上無行幸，分作慈寧殿裏春。"]'),
('987f724b-6bf7-44ee-afd8-383e6e95eb2a','時宰生日詩三十絕  其一三','周紫芝','宋','宋诗','song-poetry','','[]','誰移蓬島在人寰，詔賜新居五百間。',32,'全唐诗/poet.song.88000.json','["誰移蓬島在人寰，詔賜新居五百間。", "紫塞無兵清似洗，丹樓不動屹如山。"]'),
('75204aca-bbfc-412c-90d9-f2121c26aedb','時宰生日詩三十絕  其一四','周紫芝','宋','宋诗','song-poetry','','[]','御墨親書六字牌，閣名新賜屬元台。',32,'全唐诗/poet.song.88000.json','["御墨親書六字牌，閣名新賜屬元台。", "內前夾道爐煙裏，争看翔鸞舞鳯來。"]'),
('ea762ed2-1ffa-4d17-96ad-5271f475444d','時宰生日詩三十絕  其一五','周紫芝','宋','宋诗','song-poetry','','[]','御府分香壽老人，紫皇親賜玉壺新。',32,'全唐诗/poet.song.88000.json','["御府分香壽老人，紫皇親賜玉壺新。", "聖恩無極年無盡，恰似長生殿裏春。"]'),
('0d07c3c7-b86b-4391-8398-18d618d40d54','時宰生日詩三十絕  其一六','周紫芝','宋','宋诗','song-poetry','','[]','大事因緣意未深，知公濟物自初心。',32,'全唐诗/poet.song.88000.json','["大事因緣意未深，知公濟物自初心。", "聊將石室巖前雨，來作商家旱歲霖。"]'),
('9acc1a56-c0e2-44e9-8d99-09131f13a379','時宰生日詩三十絕  其一七','周紫芝','宋','宋诗','song-poetry','','[]','一語能平百戰塵，兩朝赤子盡歸仁。',32,'全唐诗/poet.song.88000.json','["一語能平百戰塵，兩朝赤子盡歸仁。", "十年困臥邊亭鼓，同祝公年是幾人。"]'),
('a68abcd1-33a8-4a29-8d75-231c67899e15','時宰生日詩三十絕  其一八','周紫芝','宋','宋诗','song-poetry','','[]','南北交歡萬國寧，不將黔首比金繒。',32,'全唐诗/poet.song.88000.json','["南北交歡萬國寧，不將黔首比金繒。", "時人未會新盟意，要與思陵作中興。"]'),
('cde6f570-1e47-4f3e-b467-f29465aa2f16','時宰生日詩三十絕  其一九','周紫芝','宋','宋诗','song-poetry','','[]','時相論功固自賢，真儒一出定千年。',32,'全唐诗/poet.song.88000.json','["時相論功固自賢，真儒一出定千年。", "能回鑾御歸長樂，何止龜陰得舊田。"]'),
('35db21e7-4a92-488c-a06d-ba758148bf1a','時宰生日詩三十絕  其二○','周紫芝','宋','宋诗','song-poetry','','[]','北海來歸幾過年，朱顔依舊照貂冠。',32,'全唐诗/poet.song.88000.json','["北海來歸幾過年，朱顔依舊照貂冠。", "不將一節更夷險，誰觧如公耐歲寒。"]'),
('d17aedab-e393-49c3-95ee-eef6bb3e8ab6','時宰生日詩三十絕  其二一','周紫芝','宋','宋诗','song-poetry','','[]','知公清德自天然，猶復遊心到簡編。',32,'全唐诗/poet.song.88000.json','["知公清德自天然，猶復遊心到簡編。", "應笑向來張相國，後堂賓客少彭宣。"]'),
('9f5063e3-45e2-4405-a513-62749c8e8ffd','時宰生日詩三十絕  其二二','周紫芝','宋','宋诗','song-poetry','','[]','黄金新鑄景鐘鳴，公作銘詩紀告成。',32,'全唐诗/poet.song.88000.json','["黄金新鑄景鐘鳴，公作銘詩紀告成。", "從此聖朝郊祀典，文章無復數西京。"]'),
('5892701e-b967-4549-abde-81ed8a61f295','時宰生日詩三十絕  其二三','周紫芝','宋','宋诗','song-poetry','','[]','袞衣調鼎春光軒，經術傳家侍禁筵。',32,'全唐诗/poet.song.88000.json','["袞衣調鼎春光軒，經術傳家侍禁筵。", "試問一門三畫戟，何如隔座兩貂蟬。"]'),
('c824b3fa-bd6b-46db-b5ec-cb2f78e923bc','時宰生日詩三十絕  其二四','周紫芝','宋','宋诗','song-poetry','','[]','四海文衡孰主張，半隨西路擅詞章。',32,'全唐诗/poet.song.88000.json','["四海文衡孰主張，半隨西路擅詞章。", "三君八俊今何處，知有宗師在廟堂。"]'),
('1d726f18-65b0-4469-aa5a-f6cebfb2fb68','時宰生日詩三十絕  其二五','周紫芝','宋','宋诗','song-poetry','','[]','太平和筆一番新，瑞表丹邱亦異聞。',32,'全唐诗/poet.song.88000.json','["太平和筆一番新，瑞表丹邱亦異聞。", "不遣楓榆作連理，誰知六合已同文。"]'),
('03bb29d5-68da-4dc7-8b17-6babcceebc13','時宰生日詩三十絕  其二六','周紫芝','宋','宋诗','song-poetry','','[]','葆旅占星固異常，閩山竹秀米千囊。',32,'全唐诗/poet.song.88000.json','["葆旅占星固異常，閩山竹秀米千囊。", "天公已遺鸞鳯食，便恐雙飛入建章。"]'),
('89dd6986-4ced-48fa-8afa-afc7325ad66c','時宰生日詩三十絕  其二七','周紫芝','宋','宋诗','song-poetry','','[]','胸中治國計誰良，只有休兵是秘方。',32,'全唐诗/poet.song.88000.json','["胸中治國計誰良，只有休兵是秘方。", "肯爲八荒開壽城，能仁須號大醫王。"]'),
('613b9aa2-172d-413c-bc6e-74bf7b67a23b','時宰生日詩三十絕  其二八','周紫芝','宋','宋诗','song-poetry','','[]','住世神仙五百年，長生本出笑談間。',32,'全唐诗/poet.song.88000.json','["住世神仙五百年，長生本出笑談間。", "不從方士論爐鼎，自有陰功觧駐顔。"]'),
('c776f625-c640-4be7-ba91-e2c7c4ae49ca','時宰生日詩三十絕  其二九','周紫芝','宋','宋诗','song-poetry','','[]','帝城春近俗煕煕，師宰功高不事知。',32,'全唐诗/poet.song.88000.json','["帝城春近俗煕煕，師宰功高不事知。", "天上中人傳詔日，御前蕃使賀年時。"]'),
('99c2d4c8-59c4-43d5-b2cc-5a79c7e51b3c','歲抄四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','湖上青山一水邊，暮雲樓閣九重天。',32,'全唐诗/poet.song.88000.json','["湖上青山一水邊，暮雲樓閣九重天。", "春旛影裏迎新歲，爆竹聲中送舊年。"]'),
('5c716cfe-4971-4d08-ba7a-d99aa9e669f0','歲抄四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','天寒細雨還成雪，日暖晴雲却護霜。',32,'全唐诗/poet.song.88000.json','["天寒細雨還成雪，日暖晴雲却護霜。", "可惜梅花殘臘月，十分天色似江鄉。"]'),
('778b30ac-4e2b-4624-9c78-746a96bfd31b','歲抄四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','此生無事不隨緣，世路何心更著鞭。',32,'全唐诗/poet.song.88000.json','["此生無事不隨緣，世路何心更著鞭。", "年盡未歸真偶爾，春來若健亦欣然。"]'),
('98e60e26-45d6-4792-b161-ad77c1168a6b','歲抄四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','端門行欲賀新元，竊食無功只厚顔。',32,'全唐诗/poet.song.88000.json','["端門行欲賀新元，竊食無功只厚顔。", "可笑腐儒黄卷客，亦隨朝士紫宸班。"]'),
('3af37a33-c1bb-4452-8f9f-6f2952dfad27','虛飄飄  其一','周紫芝','宋','宋诗','song-poetry','','[]','虛飄飄，虛飄飄，姮娥臨月榭，神女渡仙橋。',64,'全唐诗/poet.song.88000.json','["虛飄飄，虛飄飄，姮娥臨月榭，神女渡仙橋。", "風撼花浮水，霜吹葉落條。", "飛雲轉眼下三峽，密雪滿空來九霄。", "虛飄飄，虛飄飄，比人生命猶堅牢。"]'),
('28a48b91-560c-45d9-9106-8945900b1699','虛飄飄  其二','周紫芝','宋','宋诗','song-poetry','','[]','虛飄飄，虛飄飄，水邊看海市，雲際現天橋。',64,'全唐诗/poet.song.88000.json','["虛飄飄，虛飄飄，水邊看海市，雲際現天橋。", "弱柳綿吹徑，嫣花錦綴條。", "臥雲雌霓飲滄海，過眼夕陽低碧霄。", "虛飄飄，虛飄飄，比人生世猶堅牢。"]'),
('3e5be617-267d-4c21-840e-35b9114717c0','戊辰除夜四絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','千里家山一望間，白頭夫婦且樽前。',32,'全唐诗/poet.song.88000.json','["千里家山一望間，白頭夫婦且樽前。", "詩中游戲無三昧，客裏光陰又一年。"]'),
('eb9f8d95-536b-4896-a668-7cef4aa5c4c2','戊辰除夜四絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','七年長夢採江蘺，此夜樽前倒接籬。',32,'全唐诗/poet.song.88000.json','["七年長夢採江蘺，此夜樽前倒接籬。", "莫問年來何歲月，諸孫言語似吳兒。"]'),
('83d9e154-79b5-461b-a85b-848ee9b60d67','戊辰除夜四絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','無功飽食愧侏儒，贏得霜添白頷鬚。',32,'全唐诗/poet.song.88000.json','["無功飽食愧侏儒，贏得霜添白頷鬚。", "已是再逢新太歲，何須羞飲後屠蘇。"]'),
('53ef5054-c374-4c47-a38b-1333066cb4fa','戊辰除夜四絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','新春皓薄曉鐘聲，殘燭晶熒守歳檠。',32,'全唐诗/poet.song.88000.json','["新春皓薄曉鐘聲，殘燭晶熒守歳檠。", "年向白駒光裏度，詩隨藍尾酒中成。"]'),
('dbdc8b9e-0c3f-4eab-abf1-bcba46cebfa3','立春前五日史館對雪二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','九天飛下玉花繁，喜入長安十二門。',32,'全唐诗/poet.song.88000.json','["九天飛下玉花繁，喜入長安十二門。", "獨醉且須温臘酒，迎新又欲带青幡。"]'),
('7b8071c3-ad9b-4cd1-9bcc-ef68510c22da','立春前五日史館對雪二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','昔年蹤跡寄江頭，雪屋梅村自一邱。',32,'全唐诗/poet.song.88000.json','["昔年蹤跡寄江頭，雪屋梅村自一邱。", "醉裏却疑身是夢，爛銀樓閣看瀛洲。"]'),
('2a6c386f-eebf-4663-8ab9-f834bbc85685','韓信','周紫芝','宋','宋诗','song-poetry','','[]','韓信功高世共知，區區安用假王爲。',32,'全唐诗/poet.song.88000.json','["韓信功高世共知，區區安用假王爲。", "固應渫血長安日，已在滎陽躡足時。"]'),
('67c4ee86-9cc8-48e7-bfb5-3b3b0a812b2f','范增','周紫芝','宋','宋诗','song-poetry','','[]','西楚興王亦有人，半扶炎祚作謀臣。',32,'全唐诗/poet.song.88000.json','["西楚興王亦有人，半扶炎祚作謀臣。", "老生不觧歸明主，事去方知是失身。"]'),
('4423b227-6053-44b7-bec2-a88a395d098b','次韻子紹立春二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','自息中山鬬，長安幾見春。',48,'全唐诗/poet.song.88000.json','["自息中山鬬，長安幾見春。", "司天得南正，迎日法高辛。", "送老年華速，催耕雨意新。", "又聞寛大詔，飛舞下天津。"]'),
('a068479d-2d0c-4a3c-8066-e0f6121c5a65','次韻子紹立春二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','客久悲殘歲，春生尚薄寒。',48,'全唐诗/poet.song.88000.json','["客久悲殘歲，春生尚薄寒。", "簪花人似夢，卷白意先闌。", "黄犢還驚眼，青葅已入盤。", "新年有行樂，老去逐君難。"]'),
('64124058-54ca-4803-889e-7c173ad700eb','聞西湖梅盡桃花已有開者  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不到西湖忽換年，今朝欲掛杖頭錢。',32,'全唐诗/poet.song.88000.json','["不到西湖忽換年，今朝欲掛杖頭錢。", "催成柳色多如許，落盡梅花最可憐。"]'),
('458fab51-cad5-4730-a21f-4f92fc355162','聞西湖梅盡桃花已有開者  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','日日湖邊踏淺沙，西湖久住已成家。',32,'全唐诗/poet.song.88000.json','["日日湖邊踏淺沙，西湖久住已成家。", "劉郎去後空腸斷，憶著玄都觀裏花。"]'),
('223c1ea5-154b-4a98-95fa-2e5852d121a1','送葉泉州二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','近日泉南守，新除武部郎。',48,'全唐诗/poet.song.88000.json','["近日泉南守，新除武部郎。", "漢廷多長者，循吏得惟良。", "海國蠻珍聚，兵厨臘酒香。", "不妨聊臥治，未要薄淮陽。"]'),
('917dc5cb-d1cc-4b1b-829e-e31e35a57ad9','送葉泉州二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','天上星郎貴，人間五馬榮。',48,'全唐诗/poet.song.88000.json','["天上星郎貴，人間五馬榮。", "倒樽知客滿，閉閣自詩成。", "閩嶺千山隔，吳船一水輕。", "九重宣密詔，何日問歸程。"]'),
('ce1d1a4a-3d9a-42e9-9fc9-79867a7362ff','送馮均州二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','聞說京西道，均房虎更多。',48,'全唐诗/poet.song.88000.json','["聞說京西道，均房虎更多。", "定須歎來暮，政欲飲無何。", "過客虛厨傳，饑氓費撫摩。", "君看歸諫議，爲郡拙催科。"]'),
('95862c76-5d87-4e24-a300-f4ec345d7017','送馮均州二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','從事持三尺，將軍控萬弦。',48,'全唐诗/poet.song.88000.json','["從事持三尺，將軍控萬弦。", "廟堂應記憶，江漢久流傳。", "又復分新壘，歸來更幾年。", "他時休怪我，今日自華顛。"]'),
('45077ae8-751e-44fc-8326-77b241322a70','寓宿省直有懷方元伯','周紫芝','宋','宋诗','song-poetry','','[]','古屋頽牆久寂寥，寒廳依舊長芭蕉。',32,'全唐诗/poet.song.88000.json','["古屋頽牆久寂寥，寒廳依舊長芭蕉。", "主人應在花深處，獨對東風醉小橋。"]'),
('69b5303d-711e-4ed8-a8cd-20880c3c8c88','次韻子紹題竹坡二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','孫郎忽唾寒窗玉，來過當年玉川屋。',32,'全唐诗/poet.song.88000.json','["孫郎忽唾寒窗玉，來過當年玉川屋。", "更作縱横一尺書，爲榜南坡兩三竹。"]'),
('6e88cf18-e94e-408b-b498-17b214804527','次韻子紹題竹坡二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','結廬歸臥今尚無，白頭寄食猶中都。',32,'全唐诗/poet.song.88000.json','["結廬歸臥今尚無，白頭寄食猶中都。", "移栽自種短牆底，他時此計知何如。"]'),
('5c074948-0d62-4d39-80b5-4a2f13e26b9e','次韻季共月夜見懷竹坡用子紹韻  其一','周紫芝','宋','宋诗','song-poetry','','[]','五十九年蘧伯玉，家無擔石居無屋。',32,'全唐诗/poet.song.88000.json','["五十九年蘧伯玉，家無擔石居無屋。", "喜君馬上風前詩，似我南坡月中竹。"]'),
('28a6a51b-202d-4937-8a38-a008a95c37cd','次韻季共月夜見懷竹坡用子紹韻  其二','周紫芝','宋','宋诗','song-poetry','','[]','寒窗有意過我無，雍容車騎子甚都。',32,'全唐诗/poet.song.88000.json','["寒窗有意過我無，雍容車騎子甚都。", "更當爲作子虛賦，王郎文彩今相如。"]'),
('6b7b37d8-8594-40ae-a628-4db1b5660960','次韻季共月夜見懷竹坡用子紹韻  其三','周紫芝','宋','宋诗','song-poetry','','[]','烏衣諸郎美如玉，笑我秋風卷茅屋。',32,'全唐诗/poet.song.88000.json','["烏衣諸郎美如玉，笑我秋風卷茅屋。", "才高渠是判花人，頭白吾羞汗青竹。"]'),
('a75f9f18-14c0-47ae-855c-cc47127ca820','次韻季共月夜見懷竹坡用子紹韻  其四','周紫芝','宋','宋诗','song-poetry','','[]','此君那可一日無，桃花不復怨玄都。',32,'全唐诗/poet.song.88000.json','["此君那可一日無，桃花不復怨玄都。", "得公明月千斛珠，我羞魚目真不如。"]'),
('39404c1d-e786-450d-b9e5-24bd3aaf2177','次韻季共月夜見懷竹坡用子紹韻  其五','周紫芝','宋','宋诗','song-poetry','','[]','無方可試藍田玉，空想雲庵臥玉屋。',32,'全唐诗/poet.song.88000.json','["無方可試藍田玉，空想雲庵臥玉屋。", "賴有人間百尺樓，下臨此地千尋竹。"]'),
('e8250c2f-e951-4c1f-b7a8-e30e10c83c66','次韻季共月夜見懷竹坡用子紹韻  其六','周紫芝','宋','宋诗','song-poetry','','[]','衰翁久已一故無，聊睇逸驥方過都。',32,'全唐诗/poet.song.88000.json','["衰翁久已一故無，聊睇逸驥方過都。", "公是風流小摩詰，我爲無用長僑如。"]'),
('09dfdc76-e871-4b8c-99c1-8d876be1cdaa','次韻季共月夜見懷竹坡用子紹韻  其七','周紫芝','宋','宋诗','song-poetry','','[]','鉛刀不可切堅玉，敝筐豈能持大屋。',32,'全唐诗/poet.song.88000.json','["鉛刀不可切堅玉，敝筐豈能持大屋。", "强驅跛鱉當前鋒，看公詩成如破竹。"]'),
('6ff0f321-abbf-4e42-ae38-8e687ea3d17c','次韻季共月夜見懷竹坡用子紹韻  其八','周紫芝','宋','宋诗','song-poetry','','[]','君房言語舉世無，射策未許蒙帝都。',32,'全唐诗/poet.song.88000.json','["君房言語舉世無，射策未許蒙帝都。", "巴人下里不足數，雲韶九奏方純如。"]'),
('eccdc306-265e-4224-8604-4026a50cae0c','次韻季共月夜見懷竹坡用子紹韻  其九','周紫芝','宋','宋诗','song-poetry','','[]','藴石知公似荆玉，誰作璵璠薦王屋。',32,'全唐诗/poet.song.88000.json','["藴石知公似荆玉，誰作璵璠薦王屋。", "白髯應笑虎頭癡，青衫謾把魚須竹。"]'),
('cd2d3d40-e0bd-401f-9f17-19123556e3e6','次韻季共月夜見懷竹坡用子紹韻  其一○','周紫芝','宋','宋诗','song-poetry','','[]','老此安能爲有無，曹會豈可當大都。',32,'全唐诗/poet.song.88000.json','["老此安能爲有無，曹會豈可當大都。", "彈丸脱手盤走珠，句然如此今誰如。"]'),
('d471647f-656c-4441-a116-ef2f7af5d7a4','次韻季共月夜見懷竹坡用子紹韻  其一一','周紫芝','宋','宋诗','song-poetry','','[]','平世欲獻初無玉，何嘗生存夢華屋。',32,'全唐诗/poet.song.88000.json','["平世欲獻初無玉，何嘗生存夢華屋。", "苦遭田父亦與飲，不問主人時看竹。"]'),
('7b14cc7f-15af-4571-a531-842db4023ec3','次韻季共月夜見懷竹坡用子紹韻  其一二','周紫芝','宋','宋诗','song-poetry','','[]','十事如意八九無，暮年猶喜見子都。',32,'全唐诗/poet.song.88000.json','["十事如意八九無，暮年猶喜見子都。", "那能從公得三絕，但可一身觀六如。"]'),
('46e210c4-1b62-4ac3-a900-239e7fc03687','次韻季共月夜見懷竹坡用子紹韻  其一三','周紫芝','宋','宋诗','song-poetry','','[]','鱸魚憶鱠松江玉，船作浮家當漁屋。',32,'全唐诗/poet.song.88000.json','["鱸魚憶鱠松江玉，船作浮家當漁屋。", "寒窗夢著雨中蓑，長釣復垂波上竹。"]'),
('be999182-1664-43cc-8b9d-a30de17eeb55','次韻季共月夜見懷竹坡用子紹韻  其一四','周紫芝','宋','宋诗','song-poetry','','[]','平生僅識之與無，敢攻詩城跨二都。',32,'全唐诗/poet.song.88000.json','["平生僅識之與無，敢攻詩城跨二都。", "歸舟欲上知可呼，念捨公去何所如。"]'),
('b5983dbc-f7e3-492c-a09a-8e8ac6a9fec0','次韻季共月夜見懷竹坡用子紹韻  其一五','周紫芝','宋','宋诗','song-poetry','','[]','公哦新詩戞鳴玉，欲辦陟釐須滿屋。',32,'全唐诗/poet.song.88000.json','["公哦新詩戞鳴玉，欲辦陟釐須滿屋。", "誰遣藍田丘壑人，来吹緱嶺參差竹。"]'),
('65bd1147-467c-4283-a984-915cab32fa6b','次韻季共月夜見懷竹坡用子紹韻  其一六','周紫芝','宋','宋诗','song-poetry','','[]','心知遊路豈復無，頗如六鷁飛宋都。',32,'全唐诗/poet.song.88000.json','["心知遊路豈復無，頗如六鷁飛宋都。", "小巫羞澁見大巫，神氣比公真蔑如。"]'),
('ecb1532d-8d61-4475-8318-3c4f002509d1','讀婆娑集書其後','周紫芝','宋','宋诗','song-poetry','','[]','早緣文字得聲名，佳句流傳益可珍。',32,'全唐诗/poet.song.88000.json','["早緣文字得聲名，佳句流傳益可珍。", "讀到青蒲當日疏，其他猶可是難能。"]'),
('3dc25242-d1da-46f7-8a14-2b445070049b','寄幼安使君','周紫芝','宋','宋诗','song-poetry','','[]','平生清德畏人知，豈弟真宜作吏師。',64,'全唐诗/poet.song.88000.json','["平生清德畏人知，豈弟真宜作吏師。", "日飲無何方得計，民歌來暮却成思。", "何妨道守催科拙，自是穰侯見事遲。", "天與一窗供燕坐，烏墩山好助公詩。"]'),
('3b308270-ade2-471f-8a1a-89d8d0d3cbfa','食鮰魚頗念河魨戲作二詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','皤腹鱗鱗品自珍，紅鮰浪欲與争新。',32,'全唐诗/poet.song.88000.json','["皤腹鱗鱗品自珍，紅鮰浪欲與争新。", "世間那有西施乳，寧有河魨觧藥人。"]'),
('cbc5b3f1-0908-418b-85bc-80779c58bb90','食鮰魚頗念河魨戲作二詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','蘆笋初生水繞村，河魨旋煮薦清樽。',32,'全唐诗/poet.song.88000.json','["蘆笋初生水繞村，河魨旋煮薦清樽。", "十年不踏江南岸，楊柳飛花欲斷魂。"]'),
('36d6f69f-1645-408e-bca6-e19122803f10','己巳寒食','周紫芝','宋','宋诗','song-poetry','','[]','七度逢寒食，連年客異鄉。',48,'全唐诗/poet.song.88000.json','["七度逢寒食，連年客異鄉。", "鬢絲嗟老大，冢木念青蒼。", "亂眼花無數，傷心柳著行。", "病餘春又過，不擬近杯觴。"]'),
('3250196f-2554-4dd4-8fa0-2435c76f252e','次韻庭藻韓園燕集','周紫芝','宋','宋诗','song-poetry','','[]','故老歸來有喬木，更結飛樓繞湖綠。',160,'全唐诗/poet.song.88000.json','["故老歸來有喬木，更結飛樓繞湖綠。", "城南去天無尺五，中有人間幾巖谷。", "驊騮曉踏金谷園，花邊立馬絲竹喧。", "金屈巵行碧落酒，繡羅襦醉雙紋鴛。", "吳姫遺鈿客墮幘，白眼舉觴天宇窄。", "春深别館花如烟，藉草傳杯地爲席。", "君居當東我復西，莫嫌酒涴身上衣。", "遙知第五橋邊路，桐葉題詩人未歸。", "明朝雨驟風苦惡，殘榼雖存不堪酌。", "更須拭眼到風篁，急呼海棠償舊約。"]'),
('87ccf69e-26ce-4086-a697-d233060c3c78','再和庭藻韓園之作','周紫芝','宋','宋诗','song-poetry','','[]','雨後斜陽亂森木，湖上山青河水綠。',160,'全唐诗/poet.song.88000.json','["雨後斜陽亂森木，湖上山青河水綠。", "將軍一色種桃花，錦帳紅絲裹山谷。", "人生莫愛歸田園，結廬人境無人喧。", "何如功成銷金甲，雨中看浴銀塘鴛。", "長安黄塵沒烏幘，歸來横改一窩窄。", "何如載酒作醉眠，田父時來與争席。", "春風欲起春日西，花下跨鞍花滿衣。", "恨無龍眠老畫手，寫作諸郎聯騎歸。", "竹坡有酒亦不惡，客無可人時自酌。", "君憐羈客倘見呼，來歲西歸有新約。"]'),
('375eed16-7f69-4ade-a972-6854f51458cf','題陳公悦足軒','周紫芝','宋','宋诗','song-poetry','','[]','饑人未食長流涎，芋魁作飯腹果然。',248,'全唐诗/poet.song.88000.json','["饑人未食長流涎，芋魁作飯腹果然。", "八珍九鼎紛滿前，鼎中一臠不下咽。", "吐而去之惟欲眠，貪夫嗜利絕可憐。", "牙箸落手喜若顛，家有窟郎無數錢。", "跨州連陌空多田，千頭萬尾不當緣。", "高臺未傾金碧鮮，客食不下日十千。", "棄禍忽起踵復旋，利激奴輩非關天。", "太邱諸子圖畫傳，元方季方兩聯翩。", "元也作詩如湧泉，高歌大笑傾四筵。", "只今爲郎近日邊，季也勇退高騰騫。", "結廬庇雨無餘椽，栽花移竹今幾年。", "種穀只取田一廛，鷄肥酒熟客可延。", "人生安分作當捐，眼前取足須隨緣。", "倩營莵裘將老焉，伯氏欲掛神武冠。", "歸作兩翁相對間，政看寶带黄金懸，未可便情詩盟寒。"]'),
('c26dff96-7d3b-441d-8d7a-49a9e0f6bf11','王元道剪牡丹見餉二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','知君流落在天涯，八節灘頭憶舊家。',32,'全唐诗/poet.song.88000.json','["知君流落在天涯，八節灘頭憶舊家。", "想對東風開病眼，幾行和淚洛西花。"]'),
('1940900b-14e7-4b14-9760-edc84a997a07','王元道剪牡丹見餉二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','已是飛花落絮天，東風猶入竹坡寒。',32,'全唐诗/poet.song.88000.json','["已是飛花落絮天，東風猶入竹坡寒。", "綠樽恨我無醇酎，紅艷煩君送牡丹。"]'),
('dc7cd0f9-3262-4e1b-bb8d-246d099ee57d','次韻林梅卿西湖載酒時僕以病不赴','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖豈復似人間，付與瀛洲學士閑。',64,'全唐诗/poet.song.88000.json','["西湖豈復似人間，付與瀛洲學士閑。", "百榼滿傾桑落酒，兩高聊作道場山。", "一年春事方三月，萬里風煙静八蠻。", "白髪可憐欹病枕，蘭船空憶棹歌還。"]'),
('99b9b226-7fa8-491f-a2c4-c7dbf7c44b09','馬山觀道傍賣芍藥口占','周紫芝','宋','宋诗','song-poetry','','[]','沙河簾幙近蒼穹，芍藥絲頭十里風。',32,'全唐诗/poet.song.88000.json','["沙河簾幙近蒼穹，芍藥絲頭十里風。", "誰道昇平本無象，江都花是舊時紅。"]'),
('36bdb86e-2e58-499b-bcaf-41bd7bc55e35','次韻陳彦育諸天閣晚眺','周紫芝','宋','宋诗','song-poetry','','[]','飛閣青雲上，何因一笑同。',48,'全唐诗/poet.song.88000.json','["飛閣青雲上，何因一笑同。", "春歸憐客去，酒聖與誰中。", "相國名猶在，唐朝事已空。", "更將詩說夢，强欲付衰翁。"]'),
('49a158c8-d361-4eda-b32e-9d08792e615c','次韻子紹送春七絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','混沌七竅鑿，可恨倏與忽。',24,'全唐诗/poet.song.88000.json','["混沌七竅鑿，可恨倏與忽。", "人生寒暑間，萬古長出没。"]'),
('8e33748d-c4b5-450f-a494-f9e01c7ada66','次韻子紹送春七絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','孫郎惜春句，平澹古未聞。',24,'全唐诗/poet.song.88000.json','["孫郎惜春句，平澹古未聞。", "譬如春江波，因春自成紋。"]'),
('1e0a4fb9-7ae8-48d7-a15d-febf1f010a1d','次韻子紹送春七絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','來禽着青子，紅葉護殘春。',24,'全唐诗/poet.song.88000.json','["來禽着青子，紅葉護殘春。", "但使風味勝，不愧桃李門。"]'),
('6d22fc9a-f045-4c3a-b2c1-4c29c4263a7f','次韻子紹送春七絕  其四','周紫芝','宋','宋诗','song-poetry','','[]','微生感年衰，誰能惜春盡。',24,'全唐诗/poet.song.88000.json','["微生感年衰，誰能惜春盡。", "政恐厭黄梅，吳楊出蒸菌。"]'),
('4e40a789-1cc8-40ce-bb6b-2351c622a871','次韻子紹送春七絕  其五','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖天下勝，咫尺安得往。',24,'全唐诗/poet.song.88000.json','["西湖天下勝，咫尺安得往。", "青春不可追，老力亦難强。"]'),
('451eb681-3326-4dc2-975e-c485ccaf860f','次韻子紹送春七絕  其六','周紫芝','宋','宋诗','song-poetry','','[]','招提在南山，共著蠟屐登。',24,'全唐诗/poet.song.88000.json','["招提在南山，共著蠟屐登。", "世無謝康樂，此事誰復能。"]'),
('840a1ed2-1c7c-47e5-a3fd-c60ec1bb0af7','次韻子紹送春七絕  其七','周紫芝','宋','宋诗','song-poetry','','[]','青春不識回，豈但春去閑。',24,'全唐诗/poet.song.88000.json','["青春不識回，豈但春去閑。", "何以永我日，妙香横博山。"]'),
('4cdfe453-e456-407f-b838-31c9a8049c0c','送喬郢州','周紫芝','宋','宋诗','song-poetry','','[]','使君雙旆擁朱轓，竹馬先迎近郭春。',64,'全唐诗/poet.song.88000.json','["使君雙旆擁朱轓，竹馬先迎近郭春。", "且聽郢人歌白雪，莫因騷客念東門。", "新詩爲我應須寄，往事知誰與細論。", "喚取莫愁烟艇子，有時來伴石頭樽。"]'),
('8c25ff83-ddba-4e47-a379-1452f3999d5b','次韻章季常飲冰長句','周紫芝','宋','宋诗','song-poetry','','[]','九衢烏帽吹塵沙，心知痼疾無烟霞。',192,'全唐诗/poet.song.88000.json','["九衢烏帽吹塵沙，心知痼疾無烟霞。", "病眼不禁書葉遮，歲月逝已空吁嗟。", "故鄉日遠老日加，無地可種青門瓜。", "幾年塵甑兒女譁，強吟冰柱哦雪車。", "長安城中十萬家，綠蒲朱籠來邇遐。", "揮金截玉争矜誇，御府詔賜珍復嘉。", "金盤璀璨無疵瑕，章郎文采如景差。", "便恐餘子俱公邪，故遣麗句開天葩。", "語勝未必甲豐華，深山窮谷寒無涯。", "一讀盡噤池中蛙，老人晝臥横烏紗。", "舉杯隨分浮水花，飲甘欲借歸齒牙。", "千金難買官焙茶，百金未盡先藏义。"]'),
('687d5a4e-7f56-4678-a3da-a1c2da742ad8','染衣亭','周紫芝','宋','宋诗','song-poetry','','[]','聞說郊居勝，新穿五畝池。',96,'全唐诗/poet.song.88000.json','["聞說郊居勝，新穿五畝池。", "暗通山窈窕，深住碧漣漪。", "驚起紅鸂鶒，吹翻綠荔枝。", "雨添衣色秀，波渡襪塵遲。", "照眼誰重唾，臨流自可詩。", "水清魚莫種，秋近荻須移。", "剰欲添風月，何妨更渺瀰。", "却憐韓吏部，埋甕作癡兒。"]'),
('18185104-4d59-41f9-a883-47d43b610563','玉井橋','周紫芝','宋','宋诗','song-poetry','','[]','水滿雙鴛沼，花開玉井蓮。',96,'全唐诗/poet.song.88000.json','["水滿雙鴛沼，花開玉井蓮。", "亭浮幽渚外，人渡小橋邊。", "白羽參差在，跳珠次第圓。", "風高與芬馥，露重借嫣妍。", "青板釣魚老，朱欄聽雨眠。", "時從客容與，寧借鷺聯拳。", "何日回征棹，歸來賦短篇。", "共邀池上月，同看水中天。"]'),
('c59dfddc-85f4-4673-8f2b-64204bc0671f','次韻伯遠端午日拜碧香之賜','周紫芝','宋','宋诗','song-poetry','','[]','紫府琳腴照玉壺，來霑隱吏北山隅。',64,'全唐诗/poet.song.88000.json','["紫府琳腴照玉壺，來霑隱吏北山隅。", "遙知拜賜瞻金闕，應笑流涎濕領鬚。", "醉面看君紅作纈，衰顔憐我綠凋蒲。", "明年何止分瓊液，細葛香羅世亦無。"]'),
('43acc682-8b19-4f04-8a31-a9a746915506','次韻仲平去惡木葺新軒一首','周紫芝','宋','宋诗','song-poetry','','[]','自我來東吳，竊食偷燕閑。',204,'全唐诗/poet.song.88000.json','["自我來東吳，竊食偷燕閑。", "頽檐賦官居，漏雨穿屋山。", "有如朐䏰蟲，盤屈沮洳間。", "入門兒女愁，出門車馬喧。", "年來得新巢，易地稍立言。", "短牆蓬藋蒿，頗亦費剪芟。", "視公有華屋，未敢窺其藩。", "惡木屏除翳，雲山借空觀。", "郎曹二三公，相過綴遊觀。", "清吟屢刻燭，夜語常更端。", "但恐陳太邱，開窗納晴川。", "定復譏中郎，寸碧瞻孱顔。", "兩家合争雄，人物俱翩翩。", "不如醉明眸，墮馬傾低鬟。", "付此百年事，試作一笑看。", "我如雲水僧，故鄉未言還。", "安得從杖屨，婆娑共躋攀。"]'),
('8efb8ea0-46c5-4ad7-af80-ecc5db313684','晚集江園會者五人黄叔魚林平父黄文若刁黄叔與僕也以暝色带飛鳥爲韻余得色字','周紫芝','宋','宋诗','song-poetry','','[]','少小謀一邱，老大猶未得。',96,'全唐诗/poet.song.88000.json','["少小謀一邱，老大猶未得。", "幽園固佳處，入眼自歎息。", "賴此千載人，相逢共京國。", "追凉坐花陰，持杯飲湖色。", "斜陽入疏林，晚色忽復逼。", "忽忽行語離，兩别遂南北。", "日落未可歸，山高更須陟。", "佳會豈易逢，蓴鱠不須憶。"]'),
('eb00780f-69fb-451f-9896-c0b5500f3c0f','次韻徐伯遠題錢少愚畫孤山月梅圖','周紫芝','宋','宋诗','song-poetry','','[]','錢郎名與大年齊，貌得孤山一段奇。',64,'全唐诗/poet.song.88000.json','["錢郎名與大年齊，貌得孤山一段奇。", "月色昏昏人寂寂，梅花淡淡水漪漪。", "戲將三昧傳神手，催動千林破臘枝。", "不用摩挲窺妙墨，暗香疏影在新詩。"]'),
('92d97def-2e35-4384-8a4a-f706bcab80be','次韻仲平示曾庭堅侍御','周紫芝','宋','宋诗','song-poetry','','[]','曾侯爲生亷易足，天與一居山繞屋。',64,'全唐诗/poet.song.88000.json','["曾侯爲生亷易足，天與一居山繞屋。", "看山有味聊與娛，嚼蠟無情本非欲。", "子建波瀾今尚存，斷弦那用鸞膠續。", "會當踏月夜相過，曳我江心舊桃竹。"]'),
('03be5acc-3e36-48b1-a02d-4a012cbec639','次韻季共古意三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','艷女塗修眉，貞女重婦德。',48,'全唐诗/poet.song.88000.json','["艷女塗修眉，貞女重婦德。", "紛紛桃李花，豈復無顔色。", "争妍固可憐，落知不足惜。", "我欲採江蘺，悵望秋水隔。"]'),
('52bd8a8a-600f-4767-b29b-d48accee8fe9','次韻季共古意三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','人生結綢繆，捐情誓蒼旻。',48,'全唐诗/poet.song.88000.json','["人生結綢繆，捐情誓蒼旻。", "恩愛那得長，故交不如新。", "蹭蹬廹歲晚，坎壈悲斯人。", "舉世亦何有，知心繄夫君。"]'),
('b220d10c-2dca-4cae-ab7b-ce225516bc3e','次韻季共古意三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','客從遠方來，獨立江水湄。',48,'全唐诗/poet.song.88000.json','["客從遠方來，獨立江水湄。", "江水何悠悠，白髪空離離。", "病足修長途，弱羽思歸飛。", "歌君傷秋曲，淚濕遊子衣。"]'),
('be3b87af-1bfd-466e-bf2c-47893b7ecba5','袁時良霧隱齋','周紫芝','宋','宋诗','song-poetry','','[]','袁侯家多文，頗似班叔皮。',168,'全唐诗/poet.song.88000.json','["袁侯家多文，頗似班叔皮。", "厥後有仍雲，文采如當時。", "流風今尚存，所恨世未知。", "一官事桁楊，相處似未宜。", "西齋附寒廳，花竹搖風枝。", "惟因有餘日，隱几哦新詩。", "願君掃秋茶，决獄稱吏師。", "何必大門閭，可使高軒馳。", "會當專北門，誥命司文詞。", "斯文可華國，當代稱羽儀。", "他時豹一斑，寧須管中窺。", "時來固有待，道在亦可斯。", "只今坐寒窗，相從歎兀誰。", "聊呼管城輩，文字相娛嬉。"]'),
('25d2f4b3-1a54-4f27-adbb-914ebafbbcf7','王興周以蘇養直詩見借今日偶携至直舍且誦且已自喜亦自笑也爲題三詩因效其體  其一','周紫芝','宋','宋诗','song-poetry','','[]','江湖久入平生夢，猿鶴空懷老去羞。',32,'全唐诗/poet.song.88000.json','["江湖久入平生夢，猿鶴空懷老去羞。", "輸與蘇郎門日月，小舟長繫白蘋洲。"]'),
('5cd82585-904c-454f-b971-641283182bbd','王興周以蘇養直詩見借今日偶携至直舍且誦且已自喜亦自笑也爲題三詩因效其體  其二','周紫芝','宋','宋诗','song-poetry','','[]','身如倦鳥欲歸去，盟與白鷗真復寒。',32,'全唐诗/poet.song.88000.json','["身如倦鳥欲歸去，盟與白鷗真復寒。", "更把後湖風月句，着官仍對吏書看。"]'),
('fc33221a-a210-42c1-b454-10705ffe5852','王興周以蘇養直詩見借今日偶携至直舍且誦且已自喜亦自笑也爲題三詩因效其體  其三','周紫芝','宋','宋诗','song-poetry','','[]','有樹移雲盡欲平，牙籖卷盡俗塵清。',32,'全唐诗/poet.song.88000.json','["有樹移雲盡欲平，牙籖卷盡俗塵清。", "誰知吏案文書裏，時有滄江風雨聲。"]'),
('fc191889-b470-4352-b773-ec19411670e5','次韻子紹秋熱望雨之作得詩而雨已足故詩意小異','周紫芝','宋','宋诗','song-poetry','','[]','我欲蓐收回老火，乞雨天公殊未可。',80,'全唐诗/poet.song.88000.json','["我欲蓐收回老火，乞雨天公殊未可。", "忍饑但復念壁立，回首誰能看甑墮。", "天將夜雨送秋來，可近書檠吾已惰。", "耕犁澤澤水涓涓，歸買一廛猶不果。", "老翁何日在田間，君上青雲應記我。"]'),
('9e88d9a8-84a9-48dc-91a3-01913ad2f87e','次韻庭藻兄弟唱酬之作','周紫芝','宋','宋诗','song-poetry','','[]','黄耳書來得近詩，楚騷寧復爲秋悲。',64,'全唐诗/poet.song.88000.json','["黄耳書來得近詩，楚騷寧復爲秋悲。", "會令好句能傳信，更有何方可樂饑。", "巖壑樹高元是桂，階庭人秀盡成芝。", "脊令風雅誰能繼，神物應須與護持。"]'),
('4a95e908-ca28-4df7-b13a-c69fa7cd89b0','夜聞潮二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','江隔西興老翠鬟，轉頭即是海門山。',32,'全唐诗/poet.song.88000.json','["江隔西興老翠鬟，轉頭即是海門山。", "八盤嶺下移家住，安聽潮聲到夢間。"]'),
('236eb53a-fe02-4c2e-b0f9-e849bc489a44','夜聞潮二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','春雷隱約地中鳴，慣聽由來夢不驚。',32,'全唐诗/poet.song.88000.json','["春雷隱約地中鳴，慣聽由來夢不驚。", "莫怪詩翁歸未去，故鄉無此海潮聲。"]'),
('c5762785-8040-4e41-959e-cf959d129122','次韻仲平太博中秋齋中對月二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','秋蟾此夜一盤明，影落齋壇分外清。',32,'全唐诗/poet.song.88000.json','["秋蟾此夜一盤明，影落齋壇分外清。", "想對風光無處說，夜深聊復以詩鳴。"]'),
('6cfc7dcf-d544-4476-805a-4b0fb9b96cea','次韻仲平太博中秋齋中對月二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','軟紅堆裏十朱輪，此地何嘗有一塵。',32,'全唐诗/poet.song.88000.json','["軟紅堆裏十朱輪，此地何嘗有一塵。", "月亦憐君最孤絕，故來相伴作詩人。"]'),
('d4b71896-48e2-4b36-a7f1-17db835d5f7b','次韻仲平十七夜太社行禮月色如晝  其一','周紫芝','宋','宋诗','song-poetry','','[]','從來方社要齋明，玉豆精華酒潔清。',32,'全唐诗/poet.song.88000.json','["從來方社要齋明，玉豆精華酒潔清。", "風裏笙簫雲外至，耳邊環珮月中鳴。"]'),
('8472a9f7-9e7f-4b1f-b183-1aa531f0cbe6','次韻仲平十七夜太社行禮月色如晝  其二','周紫芝','宋','宋诗','song-poetry','','[]','龍輈來下未爲輪，九奏迎神不動塵。',32,'全唐诗/poet.song.88000.json','["龍輈來下未爲輪，九奏迎神不動塵。", "想得椒漿初奠後，夜歸猶有月隨人。"]'),
('cd051a20-06f5-47b5-84bb-80d47c0a273d','九日不出鄰牆木芙蕖盛開','周紫芝','宋','宋诗','song-poetry','','[]','九日無行樂，何人慰獨居。',48,'全唐诗/poet.song.88000.json','["九日無行樂，何人慰獨居。", "擬翻金瀲灧，聊醉木芙蕖。", "秋與愁相似，花應意不疏。", "衰顔誰復管，薄艷更憐渠。"]'),
('2e24048d-db7f-46f9-8a81-0a065c4de503','九日竹坡晝睡二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','紫萸香度酒杯空，分付重陽一枕中。',32,'全唐诗/poet.song.88000.json','["紫萸香度酒杯空，分付重陽一枕中。", "老至上山無脚力，試憑幽夢到南峰。"]'),
('3ba11e48-56cd-4dad-98fb-72449f819750','九日竹坡晝睡二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','近籬青蘂欲成金，料理衰翁伴醉吟。',32,'全唐诗/poet.song.88000.json','["近籬青蘂欲成金，料理衰翁伴醉吟。", "醽醁偶從天上得，白頭還對竹坡斟。"]'),
('1a648717-b935-4a30-ac2b-b8c303601639','十日雨中對花','周紫芝','宋','宋诗','song-poetry','','[]','客有誰持酒，花猶觧過牆。',48,'全唐诗/poet.song.88000.json','["客有誰持酒，花猶觧過牆。", "西風吹畫幕，細雨濕紅妝。", "此地當愁眼，回頭隔異鄉。", "幾時欹醉帽，一朵薦重陽。"]'),
('1c8d809f-ae4b-4898-b0a0-c13b4db4468f','九月望日月色如晝','周紫芝','宋','宋诗','song-poetry','','[]','静坐無人鵲轉柯，冷蟾分影照金波。',64,'全唐诗/poet.song.88000.json','["静坐無人鵲轉柯，冷蟾分影照金波。", "月如白玉盤初掛，天似青銅鏡始磨。", "正好中秋無此色，不知今夕定如何。", "錦袍太白憑誰問，應趁春風上大羅。"]'),
('ed308e8e-4d00-492e-ac9b-ef3e9e9b58c9','九月二十四日試吏省舍雨中獨坐終日是日誦阮嗣宗秋懷十七首因效其體','周紫芝','宋','宋诗','song-poetry','','[]','素秋倏欲杪，鶉火亦已中。',120,'全唐诗/poet.song.88000.json','["素秋倏欲杪，鶉火亦已中。", "霏微值零雨，黯淡悲西風。", "出庭落葉下，古木寒條空。", "何年琢翠巘，洞穴窺玲瓏。", "歳久人跡絕，亂石擁前峰。", "稚松絕可憐，崛强榛菅叢。", "但恐歲欲晏，霜雪日夜濃。", "物理有變滅，人生苦龍鍾。", "異哉清切地，兹焉得從容。", "聊爲商聲謳，獨和寒窗蟲。"]'),
('3d785a4e-0d20-476e-91e4-abc4c1161857','次韻仲平祠宮書事二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','月黑祠宮夜，天寒誰與偕。',48,'全唐诗/poet.song.88000.json','["月黑祠宮夜，天寒誰與偕。", "遂聞宣室召，先遣太常齋。", "勝事詩能說，牢愁酒可排。", "明朝看方朔，割肉更詼諧。"]'),
('8d12d5cf-1ddb-4de5-9f6e-6116e89925bb','次韻仲平祠宮書事二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','秋晚催年急，愁多與病偕。',48,'全唐诗/poet.song.88000.json','["秋晚催年急，愁多與病偕。", "客塵游净几，落木下寒齋。", "吏部詩如許，衰翁老易排。", "無心羞闒茸，有句似俳諧。"]'),
('9d62b563-e97d-4aa6-96a6-cbf11a408501','次韻仲平種金橘','周紫芝','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黄落江南盡蒲柳，金橘可曾眼中有。',160,'全唐诗/poet.song.88000.json','["黄落江南盡蒲柳，金橘可曾眼中有。", "頻年慣見小阿奴，萬里來從洞庭口。", "吳中夏果争團欒，楊梅五月紅欲然。", "后皇佳樹最晚出，蒼柯密葉垂青圓。", "萬物因人作輕重，玉食供王當有用。", "瑣才誰綠荔枝奴，結綬彈冠必王貢。", "驛使飛來無此實，吾皇盛德如帝乙。", "正林桃李知幾何，草木簿中無品秩。", "山中移栽初種時，妙手封植公所施。", "他時餉我三百顆，更乞書尾蘇州詞。"]'),
('aa3b5b6c-3a27-47da-ab20-17d2dccb9f05','次韻子紹九日杜門','周紫芝','宋','宋诗','song-poetry','','[]','晚吹悲落葉，微雲淡秋陽。',168,'全唐诗/poet.song.88000.json','["晚吹悲落葉，微雲淡秋陽。", "幽花趁佳節，綠酒生寒光。", "秋物誰可人，木奴半青黄。", "想當持兩螯，與客薦一觴。", "未須落烏紗，着屐登上方。", "池邊木芙蓉，亦足醉流芳。", "醉輒遣坐客，醒復翻書囊。", "心遠門常開，足適屨可忘。", "念我安得此，用臥秋日長。", "衰年廹蹇嵼，病力難取勷。", "昔與羣少年，登山名跳梁。", "醉中看茱萸，尚憶故態狂。", "歲月挽不留，老大徒自傷。", "但念拜東野，相從日尋常。"]'),
('fc9a5e26-a04b-4222-a5b9-8ce9bea6d76a','紹興十九年秋九月丙戌皇帝以太師益國公像御製贊文稱載勳德命祕書省珍藏小臣備員史館獲預榮觀再拜稽首賦詩二十韻上進','周紫芝','宋','宋诗','song-poetry','','[]','真人乘六龍，垂拱御八極。',240,'全唐诗/poet.song.88000.json','["真人乘六龍，垂拱御八極。", "日月一照臨，乾坤盡開闢。", "向來草昧初，廟議資玉食。", "當時無遠謀，從事日鋒鏑。", "維師有尚父，端拜奏奇策。", "投戈休五兵，執玉朝萬國。", "展寀禮太常，勒功歸帝籍。", "異報旌殊猷，聖意益烜赫。", "御府傳丹青，金匱秘東壁。", "天語粹堯謨，宸奎明寶墨。", "想當緘錦囊，喜色動咫尺。", "伊誰蒙此恩，從古所未識。", "在昔聞商宗，良弼夢天錫。", "惟肖得形似，審象勞刻畫。", "凌烟與雲臺，輔佐亦努力。", "辛勤入圖畫，文字紀功德。", "何爲得斯名，往往盡兵革。", "安能不戰勝，有此曠世跡。", "誰持雲漢章，雕鎸付金石。", "千秋事明主，萬世垂典册。"]'),
('ad165b34-55e9-488d-a489-af852b7a2454','次韻子紹同黄超然諸公山中之作','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人生丘壑意，往往老未决。',288,'全唐诗/poet.song.88000.json','["人生丘壑意，往往老未决。", "煌煌金朱人，何嘗樹風烈。", "轉戰作蠻觸，肝膽殊楚越。", "晚爲林下遊，如熱就炎暍。", "不知誰爾嗔，自欲作此孽。", "諸郎名坐曹，十日忽已浹。", "竹輿走駸駸，山溜隨活活。", "青山不相違，相見兩欣悦。", "共賦臨清流，班荆坐林樾。", "誰持步兵酒，相救文園渇。", "風嘯蘇門登，衣飄御風列。", "問酒掛百金，登高扶九節。", "况乃落星巖，似與世人别。", "尚想儋州翁，清詩散飛屑。", "遺跡倘可尋，斯遊未宜輟。", "偉哉二三子，風姿各磊落。", "應憐老病足，無用飽芻秣。", "那得嘶北風，長歌唾壺缺。", "眼看磊落士，抗論自超拔。", "各鳴白玉珂，共上黄金闕。", "笑我不出門，與世無乃拙。", "長鬚夜光持，清澹兩奇絕。", "咀味久益寒，牙類貯冰雪。", "誰當笑我起，着鞭追往轍。"]'),
('37770a94-e1b1-4d0c-940f-98c83a315c17','送王彦猷歸淮西','周紫芝','宋','宋诗','song-poetry','','[]','不食濡須塢口魚，只今已是十年餘。',64,'全唐诗/poet.song.88000.json','["不食濡須塢口魚，只今已是十年餘。", "我猶疋馬隨人後，君亦華巔與世疏。", "此日又分直館祿，幾時來讀道山書。", "梅花莫付長安使，行卜昭亭嶺下居。"]'),
('f40f9740-1b4f-42e8-b4fe-ea7dd049f00a','子紹許分雙井茶未至','周紫芝','宋','宋诗','song-poetry','','[]','睡眼昏昏睡不開，可憐辜負小窗梅。',32,'全唐诗/poet.song.88000.json','["睡眼昏昏睡不開，可憐辜負小窗梅。", "須煩雙井一杯雪，喚取竹坡春夢回。"]'),
('e0cf6b0c-cd58-4f90-aea9-52920b81ce47','子紹分以雙井以前韻爲謝','周紫芝','宋','宋诗','song-poetry','','[]','雙井甌翻雲脚乳，孫郎詩似臘前梅。',32,'全唐诗/poet.song.88000.json','["雙井甌翻雲脚乳，孫郎詩似臘前梅。", "更求琢玉敲冰句，要伴茶甘一併回。"]'),
('c81362ab-967e-48b9-8240-46a7c79db620','次韻仲平齋宿慧照','周紫芝','宋','宋诗','song-poetry','','[]','中郎自是廊廟才，平生憂國心如齋。',131,'全唐诗/poet.song.88000.json','["中郎自是廊廟才，平生憂國心如齋。", "太常章句十二萬，說論不與心相乖。", "周王五禮久不作，后夔八音今復諧。", "君不見周南留滯漢太史，夜瞻爟火空興懷。", "朱弦且可奉祠事，畫舸未用思清淮。", "行當入對青瑣闥，可但走馬章臺街。", "持竿我欲釣烟水，歲晚黄帽仍青鞵。", "諸公方蕆太平事，翁也漫作優人俳。"]'),
('7629385c-3269-44c0-9c26-7774ca59116f','次韻仲平陳郎中孤山見梅用黄法曹舊韻','周紫芝','宋','宋诗','song-poetry','','[]','綠髪朱顔日枯槁，心向梅花兩傾倒。',128,'全唐诗/poet.song.88000.json','["綠髪朱顔日枯槁，心向梅花兩傾倒。", "誰知更有少陵翁，江上情多被花惱。", "三年家住孤山下，玉樹瀕湖得春早。", "山高有月韻最勝，水近無風香亦好。", "凌霜我欲念花寒，對酒花應憐客老。", "孤芳一别今幾時，更恐山林迹如掃。", "羅浮欲入夢成空，遺恨此生常草草。", "醉挽芳條欲問誰，滿挹清樽酹碧昊。"]'),
('ac19e074-de25-4d83-8bcd-5f0a70a4e3d2','次韻陳郎中再賦孤山梅','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南枝先回北枝槁，玉山誰向花前倒。',128,'全唐诗/poet.song.88000.json','["南枝先回北枝槁，玉山誰向花前倒。", "庾郎已老怕愁多，何郎憐花爲誰惱。", "今年冬温得雪遲，西湖地勝着花早。", "舊時處士作詩處，籬落横枝爲誰好。", "清霜着樹月滿枝，白雪堆花門不掃。", "麗句誰能鐡石腸，賴有廣平文獨老。", "借令一笑有餘妍，賦此新詩不須草。", "歸尋手種桃李花，痛翦繁枝投有昊。"]'),
('dc21170d-7c65-4f8d-b4c5-72014a9e5c34','移植官梅已着數花得四絕句  其一','周紫芝','宋','宋诗','song-poetry','','[]','昭文館外無花看，吳市津頭買樹栽。',32,'全唐诗/poet.song.88000.json','["昭文館外無花看，吳市津頭買樹栽。", "花本無情天有意，忍寒教爲老人開。"]'),
('277e6961-9401-4c78-a799-d5ed3721112f','移植官梅已着數花得四絕句  其二','周紫芝','宋','宋诗','song-poetry','','[]','六尺牆邊滿樹霜，分明不是世間香。',32,'全唐诗/poet.song.88000.json','["六尺牆邊滿樹霜，分明不是世間香。", "黎郎可笑無風味，要把渠儂聘海棠。"]'),
('7fff25b6-5766-4405-b505-f52d0ed17565','移植官梅已着數花得四絕句  其三','周紫芝','宋','宋诗','song-poetry','','[]','舊日溪邊醉帽斜，玉蕤如雪照烏紗。',32,'全唐诗/poet.song.88000.json','["舊日溪邊醉帽斜，玉蕤如雪照烏紗。", "如今欲折疏疏蘂，無奈霜蓬不受花。"]'),
('887c24ed-10a3-4a3c-8174-593fd346dfbf','移植官梅已着數花得四絕句  其四','周紫芝','宋','宋诗','song-poetry','','[]','慣作梅花樹底眠，老來何事作彈冠。',32,'全唐诗/poet.song.88000.json','["慣作梅花樹底眠，老來何事作彈冠。", "詩翁句裏無官様，只合孤山月下看。"]'),
('63f1a209-7202-4211-8a62-c4ac777404e2','郊祀前二日雪','周紫芝','宋','宋诗','song-poetry','','[]','嶰竹吹新陽，端門飛晚雪。',96,'全唐诗/poet.song.88000.json','["嶰竹吹新陽，端門飛晚雪。", "憶隨侍祠官，走賀屐齒折。", "簾垂白玉樓，風度蒼龍室。", "齋殿宿皇輿，修廊嚮鳴玦。", "寒風吹忽散，萬象森可閲。", "星言催夙駕，天仗含璧月。", "聖心有忱誠，天意有施設。", "誰爲白雪歌，入奏黄金闕。"]'),
('403c357f-9590-4d1f-8ea8-971a9f8eacd4','郊祀紀事十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','內門朝日上金鋪，寶玉龍函出殿餘。',32,'全唐诗/poet.song.88000.json','["內門朝日上金鋪，寶玉龍函出殿餘。", "紅燭兩行分御道，輦官三百奉腰輿。"]'),
('804df0a1-527c-4b22-9fff-3f946dd8d36f','郊祀紀事十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','內郎進表未平明，八玉排行御路平。',32,'全唐诗/poet.song.88000.json','["內郎進表未平明，八玉排行御路平。", "今夜皇輿宿齋殿，九重和氣滿宮城。"]'),
('3f167c66-4bf7-40ab-a3ec-feb6af8f573d','郊祀紀事十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','曉趨宗廟拜衣冠，雲葉低垂護翠鑾。',32,'全唐诗/poet.song.88000.json','["曉趨宗廟拜衣冠，雲葉低垂護翠鑾。", "日采回光天意好，龍顔生喜近臣歡。"]'),
('460e07e7-9f89-4b40-b726-1cb2e217b351','郊祀紀事十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','班聲催急盡冠裳，尚聽嚴更轉警場。',32,'全唐诗/poet.song.88000.json','["班聲催急盡冠裳，尚聽嚴更轉警場。", "何事君王虛小次，佩環垂玉立寒霜。"]'),
('8d40f43a-8f27-4777-92ce-bb37361e96f4','郊祀紀事十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','日照青城瑞色新，風微金殿自無塵。',32,'全唐诗/poet.song.88000.json','["日照青城瑞色新，風微金殿自無塵。", "麝煤光照烏絲軸，親寫宸章賜大臣。"]'),
('35a43d82-dbf2-4c71-aad4-70a0c5d622a1','郊祀紀事十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','水晶簾透月翻光，宮漏頻傳夜未央。',32,'全唐诗/poet.song.88000.json','["水晶簾透月翻光，宮漏頻傳夜未央。", "帟幄微臣亦何幸，侍祠來宿殿西廊。"]'),
('b1be7fa1-ca37-442f-ab40-9d9a8248e47d','郊祀紀事十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','紫壇煙煖不飛霜，壇下千官列雁行。',32,'全唐诗/poet.song.88000.json','["紫壇煙煖不飛霜，壇下千官列雁行。", "雪色珠冠光射月，侍祠臣裏識君王。"]'),
('500c54e1-46eb-496f-9d8a-f1de2947a589','郊祀紀事十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','清蹕聲中下輦來，景鐘初動八音諧。',32,'全唐诗/poet.song.88000.json','["清蹕聲中下輦來，景鐘初動八音諧。", "登歌已奏迎神曲，天步雍容上午階。"]'),
('b618eda1-14cd-4541-8979-0db438c31866','郊祀紀事十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','龍麝香從十里傳，繞牆紅燭自生烟。',32,'全唐诗/poet.song.88000.json','["龍麝香從十里傳，繞牆紅燭自生烟。", "纖雲不度人聲寂，風馬雲車下九天。"]'),
('eeaa633a-7540-4368-bf89-01e4441c9425','郊祀紀事十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','樓上紅鸞扇影寒，樓前宣赦萬人看。',32,'全唐诗/poet.song.88000.json','["樓上紅鸞扇影寒，樓前宣赦萬人看。", "清臺奏瑞初呈了，五色祥雲簇彩竿。"]'),
('79b59434-0588-4628-aae2-e5f0ce0eec22','恭和御製郊祀喜晴詩','周紫芝','宋','宋诗','song-poetry','','[]','聖學淵源貫九邱，雍容元祀得遲留。',64,'全唐诗/poet.song.88000.json','["聖學淵源貫九邱，雍容元祀得遲留。", "明庭未款宸心肅，雲馭先回曉月浮。", "三禮秩宗歸大聖，一言悟主付千秋。", "已通爟火親祠事，更有何人敢告猷。"]'),
('1c42028e-46fd-4b29-bfee-92df2304a44c','恭進郊祀慶成詩五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','嶰竹初回律，圓丘始告虔。',48,'全唐诗/poet.song.88000.json','["嶰竹初回律，圓丘始告虔。", "禮應先吉土，誠已格高天。", "上聖鏘環珮，羣公執豆籩。", "誰爲郊祀曲，傳寫入朱弦。"]'),
('eb773eee-170d-4c1c-94e0-0ac8510956c0','恭進郊祀慶成詩五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','黄屋登原廟，青圭祀泰壇。',48,'全唐诗/poet.song.88000.json','["黄屋登原廟，青圭祀泰壇。", "盡循周制度，還列漢衣冠。", "扇影金根静，旂翻豹尾寒。", "近瞻天有喜，宗社慶重安。"]'),
('289acd23-cb17-4b78-a9ad-9a9b64da37d1','恭進郊祀慶成詩五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','百執稱元祀，君王服大裘。',48,'全唐诗/poet.song.88000.json','["百執稱元祀，君王服大裘。", "祥光將盛布，雨意倏前收。", "月白明彫俎，霜寒肅綴旒。", "欲知天意格，肸蠁荷神休。"]'),
('cd8e9136-ccb8-442f-8b9d-39e1cdbc45fc','恭進郊祀慶成詩五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','聖主翔龍日，重煕饗帝時。',48,'全唐诗/poet.song.88000.json','["聖主翔龍日，重煕饗帝時。", "笙鏞陳備樂，繭栗薦純犧。", "奠徹初燔燎，神歸欲受釐。", "禮成人共慶，廊廟有宗師。"]'),
('43f75229-b114-41d9-ae7e-19eca014bb04','恭進郊祀慶成詩五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','聖壽三千歲，精禋二祀餘。',48,'全唐诗/poet.song.88000.json','["聖壽三千歲，精禋二祀餘。", "天心親道德，四海混車書。", "奎畫宸章麗，台躔上宰居。", "小臣長拜舞，猶得奉皇輿。"]'),
('2c96f825-35ff-4611-9ed4-0afe0ce45cbd','臘月尾雪意甚濃欻復開霽','周紫芝','宋','宋诗','song-poetry','','[]','曉來豐隆車，屢却羲和轍。',96,'全唐诗/poet.song.88000.json','["曉來豐隆車，屢却羲和轍。", "雪意滿江天，雲山繞宮闕。", "冰花剪欲墜，亂絮飛復歇。", "娉娉臘前梅，天寒亦高潔。", "羞隨小桃枝，獻歲取俗悦。", "應留玉樹姿，相伴寒江雪。", "含情若有待，此意何由說。", "安得孤山圖，畫此兩奇絕。"]'),
('4f8386b2-068a-4997-811d-b92a54f9f338','後數日始得薄雪','周紫芝','宋','宋诗','song-poetry','','[]','殘臘不附火，冬温渠堪說。',96,'全唐诗/poet.song.88000.json','["殘臘不附火，冬温渠堪說。", "身疑在炎方，隆冬有餘熱。", "天公費許力，醖此一薄雪。", "草青先得春，麦短未濡蘖。", "因風始空濛，着地忽滴歇。", "人生亦復爾，過眼倏變滅。", "誰能將空花，認有作嗔悦。", "急須營一杯，爛醉梅上月。"]'),
('9d6b6fc5-dd2e-48e9-bd83-2f9af4097743','次韻季共大雪早遊竹閣書所見','周紫芝','宋','宋诗','song-poetry','','[]','憶昔司酒毋，瀕湖賦官屋。',264,'全唐诗/poet.song.88000.json','["憶昔司酒毋，瀕湖賦官屋。", "頗如賀知章，上疏得湖曲。", "詩雖竟坐窮，天亦稍從欲。", "三年看飛雪，萬嶺琢寒玉。", "有時横輕舠，不敢唾净綠。", "但當忍涕洟，豈不念安燠。", "是時走緋衣，荷擔晚相逐。", "堅冰鑿涸陰，推日在北陸。", "收藏備賜頒，功用等神速。", "歸來閲空庭，玉立僵凍木。", "青燈照詩肩，屢作龜頸縮。", "高軒客誰過，寒瓮酒空熟。", "只今古城隅，回望蒼山麓。", "﨑嶇失巖岫，紅腐困饘粥。", "王郎飛曉驂，此意知有屬。", "文懷斷弦悲，當倩鸞膠續。", "話客想回舟，敲門亦看竹。", "恨無摩詰手，風姿寫幽獨。", "憶君腸九回，得意日三復。", "平日交遊盡，如子一夔足。", "他時追汗漫，便可擺拘束。", "人生何自苦，成敗棋一局。"]'),
('c383f72c-3cde-43dd-adf3-94a449cf5507','次韻季共再賦','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒深方閉門，雪重忽滿屋。',264,'全唐诗/poet.song.88000.json','["寒深方閉門，雪重忽滿屋。", "誰能起僵臥，賴此陽春曲。", "曲高雖和寡，喜甚得所欲。", "心知夜光珠，大勝煖花玉。", "歌君窈窕詞，侑我荔枝綠。", "頗疑蝸牛廬，忽作駝裘燠。", "窮兒偶作富，貧固不待逐。", "我老况才盡，文字羞二陸。", "上水船苦遲，脱手彈驚速。", "寒如蝟張毛，癡類烏棲木。", "兒時弄筆手，老欲袖間縮。", "打窗聽悉窣，坐睡便清熟。", "瞑想西湖雪，已没孤山麓。", "那知公是時，洗鉢飯僧粥。", "灞橋風雪驢，並酌不相屬。", "政如冠上貂，難使狗尾續。", "病骨尚畏寒，少待吹嶰竹。", "春山走倭遲，呼客慰窮獨。", "新游亦不惡，舊觀疑可復。", "歡知當有餘，飲豈歎不足。", "述作付陶謝，囊囊歸自束。", "相從笑癡兒，日暮方生局。"]'),
('30fb029e-4728-43af-a82c-82cf074ca307','次韻季共再賦','周紫芝','宋','宋诗','song-poetry','','[]','住作山中居，懶甚不出屋。',264,'全唐诗/poet.song.88000.json','["住作山中居，懶甚不出屋。", "誰知五斗腰，須用作鈎曲。", "索米無如何，問舍豈不欲。", "空懷西谿魚，紅鱗膾寒玉。", "不知坐中山，修眉爲誰綠。", "敝裘裹粗繒，隨分了寒燠。", "儻忍作海夫，雖臭亦可逐。", "如其不能然，未可歎沉陸。", "此事誰當論，唾面恐自速。", "如君秀芝蘭，非世閑草木。", "交蓋久已傾，談舌未易縮。", "不知人謂何，此念吾已熟。", "年來有新遊，妙語敵嶽麓。", "縣知南屏謙，頗爲調茗粥。", "何人餘羊羔，金帳意有屬。", "淺斟醉糢糊，低唱聲斷續。", "誰同白傅春，樓下雪中竹。", "更題竹上詩，傷神想幽獨。", "但恐世間求，此樂未容復。", "况乃籋雲姿，自是千里足。", "行看鏘八鸞，何止芻一束。", "應憐老病翁，短髪悲曲局。"]'),
('86f996d0-359b-448f-bb8e-1dede345e17d','雪中歸竹坡二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','天寒歸路雪霏初，家近錢塘十里湖。',32,'全唐诗/poet.song.88000.json','["天寒歸路雪霏初，家近錢塘十里湖。", "烏帽舉鞭誰畫我，固應全似灞橋驢。"]'),
('08c76e23-cec2-4c18-8720-c18bf0912dd5','雪中歸竹坡二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','小窗梅冷一花明，臥榻塵空六尺横。',32,'全唐诗/poet.song.88000.json','["小窗梅冷一花明，臥榻塵空六尺横。", "多謝去年湖上雪，隨風時到竹坡鳴。"]'),
('cda09caf-b6f4-4ab5-9101-8a1285d8f75e','時宰生日詩六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','后皇開玉堂，仙官儼成列。',120,'全唐诗/poet.song.88000.json','["后皇開玉堂，仙官儼成列。", "奕奕峨長纓，珊珊鳴珮玦。", "中有一真仙，容華燦冰雪。", "維時值中原，格鬬彌歲月。", "帝命下撫摩，聊用究施設。", "王綱墜莫舉，獨以一手挈。", "至言等藥石，黔黎盡生活。", "帝曰伊誰能，何以報殊烈。", "爵之白玉漿，奏以雲門闋。", "徘徊上璇穹，千秋拱雲闕。"]'),
('56f3af25-47a1-48d8-a5e8-d61eca998ba6','時宰生日詩六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','軒皇出御世，垂拱坐法宮。',120,'全唐诗/poet.song.88000.json','["軒皇出御世，垂拱坐法宮。", "時聞康衢間，處處歌兒童。", "霓旌旋羽蓋，問道來崆峒。", "天師廣成子，道實與帝同。", "一言忽相契，四海俱同風。", "天師初何言，涿鹿未爲功。", "蓋以清浄福，下浹寰區中。", "君臣俱好生，自然格蒼穹。", "天道本好還，報以歸其躬。", "一千二百歲，此壽何由窮。"]'),
('cead3427-b7eb-446e-a968-1c31c8ea97b0','時宰生日詩六首  其三','周紫芝','宋','宋诗','song-poetry','','[]','南山一何高，山高亦何有。',120,'全唐诗/poet.song.88000.json','["南山一何高，山高亦何有。", "上有摩霄松，蒼虬立盤糾。", "下有千歲芝，食之令人壽。", "挽之爲天樞，循環轉維斗。", "紫宸傍七星，坐閲幾晚晝。", "帝以殿厥居，山龍垂袞繡。", "后皇植巨木，載物見坤厚。", "用以摶洪鈞，功乃周宇宙。", "才大用固難，德盛功亦懋。", "社櫟其何顔，繁柯日滋茂。"]'),
('a2f3214f-33cf-45f9-b5d7-6a6104b6bc29','時宰生日詩六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','鳯管吹新陽，夙駕款寒谷。',120,'全唐诗/poet.song.88000.json','["鳯管吹新陽，夙駕款寒谷。", "鑾車次原廟，陰雲立紛覆。", "皇天倏開霽，羲馭亦返軸。", "明庭朝百靈，雲韶奏新曲。", "天神下璇穹，精意儼森肅。", "霜華潔彫俎，夜寂響鳴玉。", "燎烟升紫壇，龍旂護黄屋。", "齊明坐宣室，肸蠁來萬福。", "大沛均四方，穆穆煕庶俗。", "熟知廊廟功，一德天所燭。"]'),
('a1609979-79b0-437e-8ba4-30c7a5cf020e','時宰生日詩六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','晏嬰昔事齊，頗作君臣樂。',120,'全唐诗/poet.song.88000.json','["晏嬰昔事齊，頗作君臣樂。", "魏絳欲安晉，賜樂乃備作。", "區區二小國，功利亦云薄。", "舜德本好生，臯夔坐酬酢。", "朱干舞堂陛，綵鳳翔寥廓。", "大哉廊廟功，禮文燦交錯。", "登歌奏郊社，率土被和樂。", "仁聲淪肌膚，有識自忻躍。", "四海悉歸仁，大信初不約。", "不拍洪崖肩，壽亦等山嶽。"]'),
('842a08f9-631b-4737-8a0f-599d2b656623','時宰生日詩六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','太極肇兩儀，君臣亦爰分。',120,'全唐诗/poet.song.88000.json','["太極肇兩儀，君臣亦爰分。", "風后力牧來，於今幾何人。", "中古稱伊周，當代知無倫。", "公功出其上，未易今昔論。", "功固未易論，報亦難具陳。", "傑閣標盛德，備燕昭庸勳。", "丹青繪縑素，奎畫形絲綸。", "凌烟古亦有，兹實所未聞。", "何勞不羅拜，金猊祝爐芬。", "永相天自許，耆壽尊師臣。"]'),
('0df02a25-590e-411e-8af0-363847336352','次韻子紹臘雪書事','周紫芝','宋','宋诗','song-poetry','','[]','君莫愛廣寒殿冷月姊歸，夜乘白鳯空中飛。',135,'全唐诗/poet.song.88000.json','["君莫愛廣寒殿冷月姊歸，夜乘白鳯空中飛。", "何如長安城中千門萬户雪，玉皇后闕人間稀。", "明年王春月書正，瑞麦垂黄臘前應。", "袞衣丞相穆天縡，白髪野人歌聖政。", "吾生老矣直宜休，此心欲話誰當酬。", "短犁青帽耕雪壟，破曉何時歸飯牛。", "誦君新詩如七發，酒酣起舞耳亦熱。", "滿夜方伴月嬋娟，開户不知風凛冽。"]'),
('6b0d9abe-317e-4584-852f-ef691ccf64f5','元日三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','八風占歲暖先催，喜色還從太簇回。',32,'全唐诗/poet.song.88000.json','["八風占歲暖先催，喜色還從太簇回。", "庭下衣冠天咫尺，雪中宮殿玉崔嵬。"]'),
('0fb263af-47b1-4b43-82c3-310e57b800f5','元日三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','去年殘雪在樓臺，日上黄簾禁殿開。',32,'全唐诗/poet.song.88000.json','["去年殘雪在樓臺，日上黄簾禁殿開。", "白髪小臣揩病眼，誤隨雲氣到蓬萊。"]'),
('81f6ccf2-25d0-4e4d-8b93-9839c15e7edf','元日三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','三尺金猊暖御爐，黄麾枝下奏番書。',32,'全唐诗/poet.song.88000.json','["三尺金猊暖御爐，黄麾枝下奏番書。", "喜看萬里朝元使，又上今年第一魚。"]'),
('0368b949-6f64-4a6d-923f-4fdcddb208cd','春意二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','客思知多少，衰年倍感傷。',48,'全唐诗/poet.song.88000.json','["客思知多少，衰年倍感傷。", "寒猶噤鳥語，雨不聽花香。", "去路如天遠，春愁著斗量。", "擬抛彭澤印，掛席上歸航。"]'),
('d8cbd882-a774-464c-94a6-62b0be553037','春意二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雨細無多子，雲間又夕陽。',48,'全唐诗/poet.song.88000.json','["雨細無多子，雲間又夕陽。", "鳥呼高枕夢，花醉老人腸。", "倩酒推愁去，憑詩伴日長。", "王孫歸未得，草色自東牆。"]'),
('63b4cd1c-7c38-4014-9a92-78b553742fb5','寒食病起二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','桃花落後燕雙飛，三度清明換客衣。',32,'全唐诗/poet.song.88000.json','["桃花落後燕雙飛，三度清明換客衣。", "猶有江南故鄉夢，起尋楊柳插朱扉。"]'),
('590e8e38-dd33-4bc2-9129-cd7038c4e810','寒食病起二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','異鄉多病復誰憐，怕見清明二月天。',32,'全唐诗/poet.song.88000.json','["異鄉多病復誰憐，怕見清明二月天。", "雪白吳兒觧歌舞，羡他携手上湖船。"]'),
('2902135d-f4e2-4231-bd8f-81b93a047978','病起借季共筒字韻呈相之季共','周紫芝','宋','宋诗','song-poetry','','[]','樽前風味笑衰翁，病起飛蓬一半空。',64,'全唐诗/poet.song.88000.json','["樽前風味笑衰翁，病起飛蓬一半空。", "春與落花何處去，醉如霜葉不成紅。", "一生渾作邯鄲夢，九載香吹嶰谷筒。", "老去新愁尚無數，却須分向酒杯中。"]'),
('14c0ed88-637e-4698-9501-dd18b0b31e91','再用筒字韻呈相之季共','周紫芝','宋','宋诗','song-poetry','','[]','柳邊輕絮不禁風，春事如梭過眼空。',64,'全唐诗/poet.song.88000.json','["柳邊輕絮不禁風，春事如梭過眼空。", "已有細枝催暗綠，忍看疏雨打殘紅。", "强將瘦馬欹烏帽，只合秋江把釣筒。", "賴此同遊兩陶謝，詩成渾在笑談中。"]'),
('bafabe13-a9c1-49ef-8a40-5a1432aad4c6','再用筒字韻呈相之季共','周紫芝','宋','宋诗','song-poetry','','[]','似僧寮外看春風，晏坐尋詩不寫空。',64,'全唐诗/poet.song.88000.json','["似僧寮外看春風，晏坐尋詩不寫空。", "春事可憐樽酒在，旅情猶念舞衣紅。", "去家久似千年鶴，時節看沉五綵筒。", "節物苦催雙髩白，故鄉常着夢魂中。"]'),
('878e79ee-7a3d-4786-9195-4609e3d92bb2','恭進奉安中興聖統慶成詩二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','歡聲何事入康衢，邃殿功成聖統初。',64,'全唐诗/poet.song.88000.json','["歡聲何事入康衢，邃殿功成聖統初。", "欲卜萬年新歷數，重看四海舊車書。", "雲韶奏樂來天外，寶冊鳴鑾上帝居。", "合與典謨垂奕世，浯溪文在復何如。"]'),
('e9f1df7f-01f8-4f40-965c-15fa151fade7','恭進奉安中興聖統慶成詩二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','禮行廊廟喜書成，重此商周說中興。',64,'全唐诗/poet.song.88000.json','["禮行廊廟喜書成，重此商周說中興。", "九葉承家傳鳯歷，六飛當位紀龍昇。", "人將堯禹方勤儉，天付蕭曹作股肱。", "擬爲中和歌樂職，小臣蕪陋亦何能。"]'),
('2aa9122a-7b12-49dc-ae07-e980eddf97ca','送守寧道人住顯忠庵','周紫芝','宋','宋诗','song-poetry','','[]','報恩席止三千衆，錢氏庵頭六尺床。',32,'全唐诗/poet.song.88000.json','["報恩席止三千衆，錢氏庵頭六尺床。", "今日道人無舊夢，閉門打睡不開堂。"]'),
('ee7b0712-65d8-42ef-8485-df57f74082a0','謝吳司户寄詩卷  其一','周紫芝','宋','宋诗','song-poetry','','[]','萬里來西極，龍媒定不疑。',48,'全唐诗/poet.song.88000.json','["萬里來西極，龍媒定不疑。", "人應如此少，老恨識君遲。", "白璧元無價，青雲未易知。", "小低湖海氣，安穩過天池。"]'),
('1fe74afb-651a-4180-bafb-78f6fde80182','謝吳司户寄詩卷  其二','周紫芝','宋','宋诗','song-poetry','','[]','故國雲山夢，長安白首郎。',48,'全唐诗/poet.song.88000.json','["故國雲山夢，長安白首郎。", "病眠三日雨，門静九衢坊。", "别後誰傾蓋，書來喜失床。", "愛渠詩似玉，應用錦爲囊。"]'),
('99181cb0-7bb3-473b-829c-405ef1f22016','春晚偶題','周紫芝','宋','宋诗','song-poetry','','[]','春與桃花作伴歸，不須更著雨頻催。',64,'全唐诗/poet.song.88000.json','["春與桃花作伴歸，不須更著雨頻催。", "簾垂盡日無人處，柳送晴天落絮來。", "愁裏酒杯誰共把，眼前書葉懶重開。", "那知造物憐幽獨，忽遣啼鶯喚夢回。"]'),
('2cabeb11-7ed0-4abc-8df1-c63f482b4c3c','食生荔子五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','五嶺人誇荔子珍，老翁何事始嘗新。',32,'全唐诗/poet.song.88000.json','["五嶺人誇荔子珍，老翁何事始嘗新。", "憑君試擘輕紅看，不带開元一騎塵。"]'),
('196a9108-1366-477c-9fb3-7fc01d7d06cd','食生荔子五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','著枝猶有露華腴，誰把紅紗罩玉膚。',32,'全唐诗/poet.song.88000.json','["著枝猶有露華腴，誰把紅紗罩玉膚。", "龍眼也隨君並熟，一生空作荔枝奴。"]'),
('2e096285-8037-435e-aa93-912398d4b124','食生荔子五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','小隊將軍過五溪，相看猶作夢中疑。',32,'全唐诗/poet.song.88000.json','["小隊將軍過五溪，相看猶作夢中疑。", "回頭欲問罨摩勒，乞得微甘是幾時。"]'),
('1262ccae-e79b-43cf-be9d-0abb4f5fe6dd','食生荔子五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','瘴嶺蠻村萬里賒，可憐生不近京華。',32,'全唐诗/poet.song.88000.json','["瘴嶺蠻村萬里賒，可憐生不近京華。", "荔枝猶想南中樹，末利先看近世花。"]'),
('06ca45ef-420e-4e12-8b3c-1d5149919f43','食生荔子五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','東來坐見玉肌豐，識面中郎舊譜中。',32,'全唐诗/poet.song.88000.json','["東來坐見玉肌豐，識面中郎舊譜中。", "絕勝詩翁紅萬顆，暮年流落到瀘戎。"]'),
('6ead00f2-b522-43d4-a76a-b63104381220','季共見和前詩次韻爲謝  其一','周紫芝','宋','宋诗','song-poetry','','[]','當日梨園壽太真，荔枝香曲賜名新。',32,'全唐诗/poet.song.88000.json','["當日梨園壽太真，荔枝香曲賜名新。", "麻姑蕚綠雙回袖，舞徹遙知不動塵。"]'),
('9ca50547-2ec6-494d-9b9a-68c0a1738c34','季共見和前詩次韻爲謝  其二','周紫芝','宋','宋诗','song-poetry','','[]','禁中分賜盡甘腴，旋琢壺冰積雪膚。',32,'全唐诗/poet.song.88000.json','["禁中分賜盡甘腴，旋琢壺冰積雪膚。", "聞道風流黄閣老，長鬚遺送玉川奴。"]'),
('6cdde7e0-5fed-4264-a749-80869bb115ee','季共見和前詩次韻爲謝  其三','周紫芝','宋','宋诗','song-poetry','','[]','人把江瑤比荔枝，枇杷楟奈更何疑。',32,'全唐诗/poet.song.88000.json','["人把江瑤比荔枝，枇杷楟奈更何疑。", "桄榔葉外和烟樹，想得青紅半熟時。"]'),
('8a7770eb-6c57-4546-b86e-87657e2a2237','季共見和前詩次韻爲謝  其四','周紫芝','宋','宋诗','song-poetry','','[]','樽前風味要人誇，瘴雨蠻烟度歲華。',32,'全唐诗/poet.song.88000.json','["樽前風味要人誇，瘴雨蠻烟度歲華。", "乞得水晶三百顆，縐紅時看眼生花。"]'),
('d96bcaa1-98eb-47eb-8fdf-531404c8fba9','季共見和前詩次韻爲謝  其五','周紫芝','宋','宋诗','song-poetry','','[]','霧縠囊懸小樹紅，芳香應入笑談中。',32,'全唐诗/poet.song.88000.json','["霧縠囊懸小樹紅，芳香應入笑談中。", "世間絕韻須真賞，人物當先數阿戎。"]'),
('31efb9b7-20d7-4c90-bf9a-8640299bca74','季共聞余賦五詩猶未之見以三詩見索因次其韻  其一','周紫芝','宋','宋诗','song-poetry','','[]','閩嶺今年荔子遲，生枝入眼可無詩。',32,'全唐诗/poet.song.88000.json','["閩嶺今年荔子遲，生枝入眼可無詩。", "誦君勝句須銜璧，老將何由更出奇。"]'),
('1f442c33-470f-4968-a5e9-90790f83f292','季共聞余賦五詩猶未之見以三詩見索因次其韻  其二','周紫芝','宋','宋诗','song-poetry','','[]','夢對清樽看玉山，荔枝空嚼水中寒。',32,'全唐诗/poet.song.88000.json','["夢對清樽看玉山，荔枝空嚼水中寒。", "心知不與公同味，始信人生一笑難。"]'),
('df0edabd-e83e-4dc4-a127-29fec5d75952','季共聞余賦五詩猶未之見以三詩見索因次其韻  其三','周紫芝','宋','宋诗','song-poetry','','[]','楊梅盧橘自成雙，敢與冰紈作雁行。',32,'全唐诗/poet.song.88000.json','["楊梅盧橘自成雙，敢與冰紈作雁行。", "莫怪老翁頻著句，書生說食是膏肓。"]'),
('67beb7b7-53fc-49c1-8bdd-623a4565efcb','米元暉待制歲以賜冰及荔子分遺季共而今年荔枝不至有詩次韻三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','詩老盟成恐未寒，今年荔子不同餐。',32,'全唐诗/poet.song.88000.json','["詩老盟成恐未寒，今年荔子不同餐。", "空排白玉千峰雪，却憶紅砂九轉丹。"]'),
('ad3c2542-2e3f-4b7a-b45c-3d1af3c36e69','米元暉待制歲以賜冰及荔子分遺季共而今年荔枝不至有詩次韻三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','銷得鑾坡荔子香，玉郎言語似君房。',32,'全唐诗/poet.song.88000.json','["銷得鑾坡荔子香，玉郎言語似君房。", "金盤何日分新果，五線先看補舜裳。"]');
